INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('원유_유출로_인한_해양_생태계_파괴', '원유 유출로 인한 해양 생태계 파괴', 'DISASTER', '["태안 기름 유출", "허베이 스피리트호", "원유 유출", "해안 오염"]', '12-07', '2007년 12월 7일, 충남 태안 앞바다에서 허베이 스피리트호와 삼성중공업 크레인 바지선이 충돌하여 원유 약 12,547㎘가 유출된 사고. 서해안 약 375㎞가 오염되었으며, 지역 어업·양식업에 막대한 피해를 주었다. 전국에서 약 123만 명의 자원봉사자가 방제 작업에 참여한 ''태안의 기적''으로도 유명하다. 해양·수산·관광 관련 광고에서 바다 오염 이미지가 떠오르는 표현은 태안 지역 소비자에게 특히 민감하다.', '[]', '[0.010269165,0.04434204,-0.006565094,0.04421997,-0.011299133,-0.0541687,-0.003004074,0.061065674,-0.008857727,-0.04336548,0.05618286,0.010635376,-0.055603027,0.0022563934,-0.021499634,0.022903442,-0.024093628,-0.012496948,-0.050201416,0.030319214,-0.01309967,-0.030303955,-0.028152466,-0.0034370422,0.021957397,0.024368286,0.011856079,0.034454346,0.0098724365,0.013069153,-0.006713867,-0.019744873,0.021774292,-0.032409668,0.017944336,-0.005092621,0.070251465,-0.058654785,-0.0056381226,-0.02633667,0.029403687,-0.008300781,0.028808594,0.054870605,-0.0050315857,0.0435791,0.008956909,0.019729614,0.072143555,0.026245117,-0.012001038,0.025802612,0.0029563904,-0.05807495,0.027328491,0.0059013367,0.016662598,-0.01071167,-0.019546509,-0.025375366,0.0084991455,-0.023208618,-0.015411377,0.036895752,-0.0067710876,-0.04425049,-0.016815186,0.03262329,-0.05355835,0.014434814,0.03781128,-0.021896362,0.056610107,0.007232666,0.010650635,0.00073957443,0.0052604675,-0.015235901,-0.06933594,-0.04949951,0.03955078,0.034179688,-0.00907135,0.023345947,0.009300232,-0.038726807,-0.081970215,-0.006389618,-0.029144287,0.06542969,-0.028915405,0.055877686,0.014595032,-0.012580872,0.031433105,-0.027313232,-0.001080513,0.04458618,0.047210693,0.022384644,-0.012687683,-0.03149414,0.03488159,-0.01272583,-0.032989502,0.0026378632,-0.032165527,0.015396118,0.020767212,-0.016174316,-0.018295288,-0.013015747,-0.03982544,0.05267334,-0.0087890625,0.015617371,0.015174866,-0.026031494,0.045898438,0.022216797,-0.011367798,0.01