INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('유흥업소_성범죄_및_경찰_유착_의혹', '유흥업소 성범죄 및 경찰 유착 의혹', 'GENDER', '["버닝썬 게이트", "클럽 성범죄", "경찰 유착", "약물 성폭행"]', NULL, '2019년 초 폭로된 서울 강남 클럽 ''버닝썬''을 둘러싼 성범죄·마약·경찰 유착 의혹 사건. 폭행 피해 신고자가 오히려 경찰에게 연행된 것을 계기로 클럽 내 불법 촬영, 마약 유통, 강간 조력 등의 의혹이 연달아 폭로되었으며, 유명 연예인들이 연루되어 사회적 파장이 컸다. 이후 가수 정준영의 단체 채팅방 내 불법 촬영물 유포 사건도 연달아 터졌다.', '[]', '[-0.0055503845,0.038238525,0.012748718,0.016143799,-0.022064209,-0.0077438354,-0.02279663,0.0076560974,0.029174805,-0.054229736,0.035217285,-0.013160706,-0.025482178,0.011207581,-0.0020580292,-0.015487671,-0.008964539,0.0025138855,-0.030883789,0.0053482056,0.009857178,0.0077438354,-0.0158844,-0.0035419464,-0.031433105,0.036132812,-0.032318115,0.011703491,0.009376526,0.035858154,-0.0036067963,-0.019760132,0.038848877,-0.06677246,-0.0036697388,-0.019760132,0.02998352,-0.029541016,0.05130005,-0.026229858,0.030303955,-0.04257202,-0.016616821,-0.01940918,-0.034576416,0.038635254,-7.015467e-05,0.017822266,0.025100708,0.04751587,0.029815674,0.031463623,-0.008361816,0.038208008,-0.009643555,0.017333984,-0.030456543,-0.027038574,0.013160706,-0.003982544,0.02331543,-0.012817383,-0.023544312,0.0010156631,-0.027435303,-0.05529785,-0.0017194748,-0.0022678375,-0.00077056885,0.025054932,0.08001709,-0.04034424,0.040222168,0.042907715,0.015060425,0.026000977,-0.017745972,0.013328552,-0.029785156,-0.024169922,0.054138184,0.009338379,0.01727295,0.07659912,-0.0079193115,-0.02670288,-0.1538086,-0.015541077,0.018539429,0.009246826,-0.07122803,0.04812622,0.027038574,0.027328491,0.048187256,-0.02494812,-0.0020275116,-0.04385376,0.05834961,0.035064697,-0.025863647,0.019119263,0.041503906,-0.0009813309,0.048828125,-0.030395508,-0.0020599365,0.0021018982,0.0013771057,-0.034118652,0.044067383,0.028182983,-0.052246094,0.0473938,0.01600647,0.0052871704,0.064575195,-0.020507812,-0.018035889,0.017837524,-0.030410767,0.0129776,0.0138549805,-0.05581665,-0.