INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('독립운동_역사_상업화', '독립운동 역사 상업화', 'HISTORY', '["만세", "항일", "독립운동 희화화", "일제", "식민"]', '03-01', '1919년 3월 1일, 일제강점기 조선 민중이 일본의 식민 지배에 맞서 전국적으로 독립을 외친 비폭력 항일운동. 유관순 열사를 비롯한 수많은 시민·학생이 ''대한독립만세''를 외치며 거리로 나섰고, 일본 헌병과 군대에 의해 수천 명이 학살되고 수만 명이 투옥되었다. 이후 임시정부 수립의 계기가 된 민족 최대의 독립운동으로, 매년 3월 1일은 공휴일로 지정되어 기념된다.', '[]', '[-0.016693115,0.0036735535,0.017959595,0.028549194,0.052093506,-0.022506714,-0.020935059,0.057861328,-0.006790161,-0.039215088,0.06341553,0.029876709,0.008964539,-0.03555298,0.020095825,0.0047836304,-0.026550293,0.0154418945,-0.011604309,0.017944336,0.037628174,0.015625,-0.020248413,0.060577393,-0.009384155,0.030639648,-0.0066223145,0.011001587,-0.008621216,-0.030410767,-0.009849548,0.0079574585,-0.02104187,-0.033294678,0.040649414,-0.017440796,0.015434265,-0.0112838745,-0.029403687,-0.03253174,0.016159058,-0.091796875,0.01600647,0.00932312,-0.041229248,-0.009178162,0.016723633,0.044647217,0.052520752,0.053100586,0.008987427,-0.019546509,0.016906738,-0.03955078,-0.024246216,-0.0013723373,-0.020629883,-0.01259613,-0.0050621033,-0.015365601,0.016815186,-0.016296387,-0.036254883,0.013000488,0.0362854,-0.0016870499,0.039367676,0.01322937,0.007904053,-0.0017738342,0.014549255,-0.024642944,0.030395508,-0.008323669,0.0022506714,0.0037212372,-0.026809692,0.02218628,-0.07080078,0.07501221,-0.0028133392,-0.013832092,-0.0546875,0.028625488,0.023834229,-0.026412964,-0.059448242,0.009140015,-0.027709961,0.019180298,-0.016693115,-0.020706177,-0.013877869,0.02998352,0.04937744,0.019241333,0.0003707409,0.019989014,0.018035889,0.02279663,-0.037628174,-0.06021118,0.008346558,0.03366089,-0.054595947,-0.013458252,0.010429382,-0.027816772,0.002986908,-0.005092621,0.011634827,0.04067993,-0.020828247,0.025177002,0.027313232,0.0041656494,0.034179688,-0.020690918,-0.0079422,-0.0135650635,-0.04058838,-0.025817871,0.01159668,0.026031494,-0.046966553,-0.02