INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('민간인_집단_학살', '민간인 집단 학살', 'HISTORY', '["제주 4.3", "초토화 작전", "민간인 학살", "봉기 진압"]', '04-03', '1948년 4월 3일부터 1954년까지 제주도에서 발생한 대규모 민간인 학살 사건. 미군정 시기 남로당 제주도당의 무장봉기가 도화선이 되었으나, 이후 이승만 정부의 초토화 작전으로 인해 제주 전체 인구의 10분의 1에 달하는 약 25,000~30,000명이 학살되거나 행방불명되었다. 수십 년간 금기시되다가 2003년 노무현 대통령이 공식 사과했으며, 2014년 국가 기념일로 지정되었다.', '[]', '[-0.023208618,0.039154053,0.017608643,0.038604736,0.027496338,-0.04345703,0.017791748,0.026885986,-0.02659607,-0.023986816,0.052093506,0.013015747,-0.039855957,0.06402588,0.030151367,-0.06677246,-0.010673523,-0.013748169,-0.010528564,0.041259766,0.027496338,-0.038757324,0.019119263,0.023666382,0.05606079,-0.015007019,0.0093307495,-0.033813477,-0.02029419,0.02381897,0.034698486,-0.0140686035,-0.029510498,-0.056396484,0.03466797,-0.0051879883,0.011764526,-0.0040779114,0.013946533,-0.01689148,-0.0070114136,-0.04345703,-0.016952515,-0.028564453,-0.0013818741,0.0048217773,0.021835327,0.051757812,0.058807373,0.0791626,0.012435913,0.00806427,0.039611816,-0.016662598,-0.019805908,0.015426636,0.03515625,-0.0259552,0.009757996,-0.04827881,0.07659912,-0.014945984,-0.004047394,0.02015686,0.031799316,-0.0024528503,0.027618408,0.012794495,-0.0029792786,-0.008575439,0.028549194,-0.015487671,0.03366089,-0.009796143,-0.035003662,0.05886841,-0.0038108826,0.0020198822,-0.07019043,0.050689697,0.015106201,0.043182373,0.018615723,0.036224365,-0.0038280487,0.01109314,-0.04006958,0.006767273,0.03591919,0.004135132,-0.021209717,0.0052337646,-0.004650116,0.012435913,0.029647827,-0.08074951,0.015327454,-0.017974854,0.042999268,0.0029945374,-0.07080078,-0.026748657,-0.00036239624,-0.029708862,-0.023406982,-0.001537323,-0.017471313,-0.0146484375,-0.052612305,-0.026412964,-0.004386902,0.038879395,-0.028671265,0.04547119,-0.023239136,0.0050582886,0.021057129,-0.029663086,0.0012655258,-0.015457153,-0.005657196,-0.014884949,0.0052948,-0.05026245,-0.016