INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('독재_정권_폭력_진압', '독재 정권 폭력 진압', 'HISTORY', '["경찰 발포", "독재 타도", "부정선거", "시위 진압"]', '04-19', '1960년 4월 19일, 이승만 자유당 정권의 3·15 부정선거에 분노한 학생과 시민들이 전국적으로 봉기한 민주주의 혁명. 경찰의 발포로 186명이 사망하고 6,000여 명이 부상당했으나 결국 이승만 대통령이 하야하면서 독재 정권이 붕괴되었다. 대한민국 민주주의 역사의 출발점으로 평가받으며, 매년 4월 19일은 국가 기념일이다. ''혁명적 할인'', ''독재자 가격 타도'' 등 혁명·타도의 언어를 광고에 가볍게 활용하면 역사 왜곡 및 희생자 모욕으로 비칠 수 있다.', '[]', '[0.010726929,0.020950317,0.023757935,0.025146484,0.03778076,-0.0038452148,-0.04736328,0.040740967,-0.012001038,-0.0473938,0.059143066,0.03677368,-0.017852783,0.004016876,0.06756592,-0.023620605,-0.0033893585,0.02835083,-0.015129089,0.045928955,-0.02494812,-0.012580872,0.052001953,0.04309082,0.024276733,0.033447266,0.013366699,-0.029144287,0.009597778,-0.020751953,0.006664276,0.0030765533,-0.03717041,-0.07269287,0.010009766,0.005405426,0.049713135,4.8577785e-05,-0.038330078,-0.02861023,0.002784729,-0.08178711,-0.008811951,0.026260376,-0.021499634,-0.031402588,0.029708862,0.043548584,0.01852417,0.038635254,0.003894806,0.011833191,0.02015686,0.041381836,0.00053596497,-0.005908966,-0.0075912476,-0.017333984,0.023544312,-0.049468994,0.017837524,-0.014884949,-0.08972168,-0.0056266785,-0.014923096,-0.025604248,0.028579712,0.01525116,0.031677246,0.041900635,0.029586792,-0.016296387,0.064941406,0.007484436,0.020187378,0.04257202,-0.008224487,0.05203247,-0.06945801,0.07531738,0.03717041,0.00021362305,-0.044769287,0.031555176,-0.029510498,-0.01878357,-0.103149414,-0.031280518,0.043701172,0.0043907166,-0.031234741,0.014564514,0.013534546,0.026885986,0.019485474,-0.045410156,0.019241333,-0.009254456,0.013160706,0.018081665,-0.018295288,0.01322937,0.028274536,-0.0020256042,-0.03805542,0.01399231,0.020141602,-0.004802704,-0.0015621185,0.030334473,0.026748657,0.022140503,-0.06573486,0.041229248,0.019088745,-0.008583069,0.0047912598,-0.007858276,0.019317627,0.0008993149,-0.064086914,-0.041503