INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('군사_쿠데타', '군사 쿠데타', 'HISTORY', '["쿠데타", "군사정변", "헌정 중단", "군부 독재"]', '05-16', '1961년 5월 16일 새벽, 박정희 소장을 비롯한 군부 세력이 민주당 장면 정부를 무력으로 전복한 쿠데타. 이 사건으로 민주주의 헌정 질서가 중단되고 군사혁명위원회가 권력을 장악했으며, 이후 박정희는 18년간 권력을 유지했다. 경제 개발의 성과를 내세우는 지지층과 독재·인권 탄압을 비판하는 측이 극명하게 나뉘어 현재까지도 정치적으로 가장 민감한 역사적 평가가 엇갈리는 사건 중 하나다. 군사·지도력·혁명 등의 마케팅 언어가 이 날짜와 결합될 경우 정치적 편향 논란을 초래할 수 있다.', '[]', '[-0.017623901,-0.013252258,0.00920105,-0.0046157837,0.04425049,0.023513794,-0.01171875,0.04864502,0.009017944,-0.06866455,0.037963867,0.010887146,-0.021881104,-0.012527466,-0.008323669,0.009963989,-0.03353882,0.0053367615,0.036621094,0.035461426,-0.035125732,-0.0211792,0.040924072,0.056396484,0.040008545,0.02760315,-0.05090332,-0.043121338,0.008232117,-0.064819336,0.029556274,-0.01953125,0.005645752,-0.054260254,-0.0019445419,0.023635864,0.021224976,0.00080633163,-0.018585205,-0.02784729,0.004184723,-0.011054993,-0.034729004,0.011878967,0.01398468,-0.08013916,0.008392334,0.04916382,0.02078247,0.021774292,0.02406311,0.040985107,-0.0064582825,0.020401001,-0.008811951,0.027908325,0.025604248,-0.023284912,0.03656006,-0.034423828,0.0027656555,0.0259552,-0.05609131,0.00819397,-0.016082764,-0.032073975,0.036010742,0.025802612,0.003004074,0.014816284,0.01953125,0.033111572,0.02079773,-0.021713257,-0.012710571,-0.0006070137,0.004524231,0.02104187,-0.03768921,0.052612305,0.0049552917,0.009025574,-0.059570312,0.02142334,-0.01966858,-0.01776123,-0.06567383,-0.0069770813,0.011474609,0.0496521,0.0019483566,0.054107666,0.01977539,-0.004550934,0.016494751,-0.005683899,-0.0017976761,-0.011871338,-0.018936157,-0.03475952,-0.018218994,0.00756073,-0.026412964,0.02255249,-0.010665894,0.026901245,-0.018341064,-0.01071167,-0.03616333,0.023330688,-0.004787445,0.021652222,-0.0619812,0.038238525,-0.02607727,0.0061683655,0.061828613,0.0070533752,-0.03515625,0.007019043,0.0030708313,-0.0070724487,0.022735