INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('민족_전쟁_및_대량_학살', '민족 전쟁 및 대량 학살', 'HISTORY', '["6.25", "한국전쟁", "남침", "이산가족", "전쟁 피해"]', '06-25', '1950년 6월 25일 새벽 북한군의 기습 남침으로 발발한 한국전쟁. 3년 1개월간 지속된 이 전쟁으로 군인·민간인을 합쳐 남북한 합계 300만 명 이상이 사망하고, 수백만 명의 피란민과 이산가족이 발생했다. 1953년 7월 휴전협정이 체결되었으나 현재까지 공식 종전이 되지 않아 분단이 지속되고 있다. ''총공세 세일'', ''전면전 특가'', ''침공 가격'' 등 전쟁 용어를 광고 카피에 활용하는 행위는 전쟁 피해자와 유가족에게 극도로 불쾌감을 줄 수 있으며, 매년 6월 25일 전후로 특히 민감도가 높아진다.', '[]', '[-0.010437012,0.035888672,-0.00566864,0.0017633438,0.00035429,-0.031311035,0.0059165955,0.050445557,-0.042114258,0.0034732819,0.057128906,0.034057617,-0.03829956,0.014892578,0.033172607,-0.016525269,-0.027420044,0.014694214,-0.020309448,0.013168335,0.060699463,0.0021133423,-0.011451721,0.020843506,0.014251709,0.03164673,-0.006702423,0.013679504,-0.005050659,-0.030532837,-0.00019466877,-0.005054474,-0.06555176,-0.052001953,0.019897461,-0.020126343,0.03842163,0.01058197,-0.022460938,-0.02558899,0.02748108,-0.06072998,-0.03201294,0.012870789,-0.015670776,-0.029006958,-0.024734497,0.041381836,0.030273438,0.014450073,-0.028656006,0.0040779114,0.00019609928,-0.021377563,-0.0134887695,0.027252197,-0.01184082,-0.031921387,-0.011238098,-0.042816162,0.050201416,-0.009284973,-0.06774902,0.01449585,0.008918762,-0.053619385,0.024093628,-0.0519104,-0.029708862,0.033935547,0.013542175,-0.025024414,0.0059394836,-0.0030059814,-0.036621094,0.02734375,-0.034210205,0.015991211,-0.03488159,-0.0002925396,0.021591187,0.04852295,-0.021606445,0.010482788,0.007209778,-0.017868042,-0.08013916,-0.007843018,0.02255249,0.015777588,-0.062194824,0.014442444,0.0005836487,0.021911621,0.008903503,-0.068237305,-0.0054397583,-0.0041542053,0.017105103,0.052947998,-0.037078857,0.023925781,0.04486084,0.015281677,-0.0098724365,-0.03010559,0.0058517456,0.013809204,-0.051116943,0.025054932,-0.0056762695,0.05722046,-0.009117126,0.06329346,0.018478394,0.005355835,0.0020484924,-0.0304718