INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('유가족_사별_슬픔_상업적_소비', '유가족·사별·슬픔의 상업적 소비', 'ETC', '["사별", "유가족 감정", "슬픔 이용", "죽음 마케팅", "그리프"]', NULL, '가족의 죽음이나 사별로 인한 슬픔, 유가족의 감정을 상업적 목적으로 활용하는 행위는 보편적으로 비윤리적으로 받아들여진다. 특히 제품과의 연결이 억지스럽거나 진정성이 없어 보일 때, 죽음과 슬픔을 소비하는 행위에 대한 반발이 강하게 나타난다.', '["INTL-014"]', '[0.030136108,0.06121826,-0.033691406,0.073791504,-0.037994385,0.0005168915,-0.014083862,0.009399414,0.039489746,-0.037353516,0.062683105,-0.05142212,-0.008201599,-0.02381897,0.021881104,0.018325806,-0.0072135925,-0.004348755,-0.023635864,-0.01802063,0.023986816,-0.030380249,0.0021209717,0.017349243,-0.014434814,0.033569336,0.028244019,0.0071640015,-0.035491943,-0.02128601,0.005344391,-0.038360596,0.02128601,-0.025054932,0.01675415,-0.0053520203,0.020950317,-0.013366699,0.04736328,0.0013389587,0.009605408,-0.03781128,-0.003194809,-0.0003130436,-0.03579712,0.064331055,0.0211792,0.00995636,0.063964844,-0.028808594,0.032348633,0.016220093,0.030410767,0.020599365,-0.021224976,0.0015001297,-0.040740967,-0.013366699,0.02217102,-0.02029419,0.0023651123,-0.07720947,-0.00011765957,-0.010398865,-0.0039787292,-0.024353027,-0.019378662,0.028213501,-0.07098389,0.0075149536,0.039001465,-0.049865723,0.01751709,0.042633057,0.027038574,-0.029266357,0.05831909,0.010879517,0.014038086,-0.04525757,0.014984131,0.031311035,-0.0068626404,0.083984375,-0.006072998,-0.010467529,-0.054626465,-0.030471802,-0.048706055,0.048675537,-0.07684326,0.020950317,-0.0035896301,-0.016403198,0.052642822,0.0067634583,0.020965576,-0.006099701,0.014930725,0.018508911,-0.028259277,0.032196045,0.022109985,0.021759033,0.020767212,-0.060302734,0.004760742,-0.04888916,-0.043548584,-0.03265381,-0.04421997,0.023773193,-0.027755737,0.079833984,0.023803711,-0.008201599,-0.013900757,0.018814087,0.03665161,-0.02468872,-0.021316528,0.0020523071,0.010818481,-0.058746338,-0.040802002,0.050476074,-0.0064964294,0.015571594,-0.045684814,-0.