INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('일제_식민_지배_역사_상업화', '일제 식민 지배 역사 상업화', 'HISTORY', '["광복", "해방", "일본 불매", "친일", "강제징용"]', '08-15', '1945년 8월 15일, 35년간의 일제강점으로부터 해방된 날로, 대한민국의 국경일이자 공휴일이다. 일본이 연합국에 항복하면서 조선이 해방되었으며, 이후 1948년 대한민국 정부가 공식 수립되었다. 매년 광복절 전후로 한일 관계 이슈, 일본 불매운동, 강제징용·위안부 배상 문제 등 역사 갈등이 재점화되는 경우가 많다.', '["KR-021"]', '[-0.062469482,0.013305664,0.02029419,0.036834717,0.0099487305,-0.01637268,-0.001627922,0.05657959,-0.0008625984,0.016021729,0.095703125,-0.0065612793,0.030899048,-0.0045928955,0.028930664,-0.0020771027,-0.034240723,0.041412354,-0.05105591,0.011405945,0.04208374,0.03363037,-0.041503906,0.055908203,0.006591797,0.020385742,-0.026306152,-0.008552551,0.0074157715,-0.038024902,0.009437561,-0.008140564,-0.001791954,-0.03466797,0.07220459,0.0048599243,0.07421875,0.0019006729,0.015258789,-0.010612488,0.015716553,-0.04550171,0.013511658,0.0062828064,-0.05633545,-0.009422302,-0.0075149536,0.0592041,0.038482666,0.012130737,-0.028015137,0.023086548,-0.025726318,-0.019622803,0.035003662,0.0010204315,-0.019058228,0.028671265,-0.014968872,-0.025009155,0.054504395,0.0039520264,-0.074401855,0.0008420944,0.021118164,-0.027557373,0.00793457,0.028823853,-0.023086548,-0.015068054,0.014175415,-0.03427124,-0.0067710876,-0.03503418,-0.008216858,0.024917603,0.000831604,0.016204834,-0.021148682,0.0025043488,0.015220642,0.01586914,-0.02545166,0.040222168,0.05682373,-0.041107178,-0.101989746,0.030303955,-0.014533997,0.04446411,-0.028808594,0.040374756,-0.029006958,0.013954163,0.041015625,-0.008728027,-0.005592346,0.027938843,-0.012161255,0.015586853,-0.014976501,-0.0015287399,-0.011047363,0.012588501,0.028793335,0.022872925,-0.0026683807,0.011497498,-0.023880005,0.0021858215,0.026611328,0.0071868896,-0.06982422,0.022201538,0.030273438,0.03955078,0.004600525,-0.015914917,0.013725281,-0.024414062,-0.042938232,0.0003643036,0.03781128,-0.053253174,-0.026519775,0.004753113,-0