INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('2차_핵폭탄_민간인_피해', '2차 핵폭탄 민간인 피해', 'HISTORY', '["원폭", "나가사키", "핵", "방사능", "2차 폭격"]', '08-09', '1945년 8월 9일, 미국이 일본 나가사키에 두 번째 핵폭탄을 투하한 날. 약 4만 명이 즉사하고 최종적으로 7만~8만 명이 사망했다. 히로시마 투하 3일 만에 벌어진 이 사건은 일본의 항복을 이끌어냈지만, 민간인 대량 학살이라는 윤리적 논쟁은 지금도 계속되고 있다.', '[]', '[-0.03173828,0.01638794,0.03414917,0.02696228,0.016540527,-0.036743164,-0.042755127,0.020217896,0.0048675537,-0.046569824,0.015640259,0.04434204,-0.026550293,-0.0048828125,-0.000831604,-0.025222778,-0.020431519,-0.010253906,0.007095337,0.0027923584,0.0034866333,0.010971069,0.013534546,0.02166748,0.054901123,0.018081665,-0.0026416779,-0.008758545,-0.03302002,-0.03479004,0.026519775,-0.013648987,-0.019195557,0.006313324,-0.017868042,-0.033355713,0.06561279,0.018493652,-0.02229309,-0.016540527,0.022232056,-0.03225708,-0.0026302338,0.051513672,0.0009775162,-0.018218994,0.005706787,0.04333496,0.04473877,0.052642822,-0.015823364,0.020553589,-0.008926392,-0.0023651123,0.012886047,0.07598877,-0.011566162,0.0019950867,0.037109375,-0.059631348,0.034851074,-0.0418396,-0.01852417,-0.02609253,0.006378174,-0.013252258,0.016952515,0.024368286,-0.05859375,0.06518555,0.003282547,-0.013572693,-0.0001540184,-0.030349731,-0.0135650635,0.0013809204,-0.040405273,-0.032958984,-0.03390503,0.025756836,0.038726807,0.016571045,-0.03765869,0.010032654,0.01398468,0.01737976,-0.029464722,0.019989014,-0.020339966,0.00032258034,-0.06921387,0.009605408,0.012145996,0.014038086,-0.019317627,-0.050598145,0.024353027,0.03829956,0.018920898,0.010665894,-0.002735138,0.014419556,0.025405884,-0.017303467,0.0090789795,-0.0042152405,0.019607544,0.008544922,-0.042816162,-0.022247314,0.014961243,0.03427124,-0.0011100769,0.05114746,-0.021408081,0.054595947,0.011947632,0.019638062,0.021331787,-0.01763916,-0.050933838,-0.003332138,0.03353882,-0.01361084,-0.0017404556,0.0014848709,0.039794922,-0.0033798218,0.007671356,-0.02095031