INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('군사_반란_및_권력_찬탈', '군사 반란 및 권력 찬탈', 'HISTORY', '["12.12", "하나회", "군사반란", "정승화 체포", "신군부"]', '12-12', '1979년 12월 12일, 박정희 대통령 암살(10.26 사건) 이후 국정 혼란을 틈타 전두환·노태우를 중심으로 한 ''하나회'' 군부 세력이 계엄사령관 정승화를 불법 체포하고 군권을 장악한 군사반란. 이 사건은 이후 5.18 광주민주화운동의 군사 진압으로 이어졌으며, 전두환 정권 7년의 시작점이 되었다. 1995년 관련자들이 내란죄로 기소·처벌되었고, 2024년 영화 ''서울의 봄''이 천만 관객을 동원하며 사건이 재조명되었다.', '[]', '[0.01586914,0.030029297,0.016647339,0.02178955,-0.0025482178,-0.017318726,-0.058135986,0.010620117,0.00013196468,-0.08093262,0.04660034,-0.027801514,-0.021759033,0.008201599,0.035247803,-0.016998291,-0.012046814,0.03125,0.014602661,-0.024017334,-0.016723633,0.005458832,0.003419876,0.07525635,-0.05368042,0.044189453,-0.014045715,0.018875122,-0.016479492,-0.0040130615,0.0357666,0.008895874,-0.02432251,-0.040252686,0.0076789856,0.0032176971,0.008155823,-0.02015686,-0.0079193115,-0.015991211,0.025299072,-0.09039307,-0.013839722,0.062347412,0.012268066,-0.032104492,-0.048797607,0.037231445,0.022201538,0.032806396,0.016281128,0.04083252,0.02268982,0.024841309,-0.025421143,0.028045654,-0.025436401,-0.02960205,-0.010528564,-0.007801056,0.032562256,0.004508972,-0.042175293,0.0234375,-0.020309448,-0.07879639,-0.010719299,0.0041618347,0.004261017,0.032806396,0.01424408,0.029052734,0.0574646,-0.006504059,-0.005027771,0.035583496,-0.015602112,0.046875,-0.066833496,0.051971436,0.018585205,0.0061531067,-0.005760193,0.006290436,0.0055503845,-0.025665283,-0.07897949,0.0016679764,0.02947998,0.015235901,-0.015701294,0.06335449,0.023498535,0.013763428,0.057617188,-0.032440186,-0.009170532,0.012931824,0.029724121,0.039611816,-0.011756897,-0.009796143,0.024520874,0.024520874,0.012557983,-0.010734558,0.017822266,0.0021152496,-0.010124207,-0.041412354,0.06451416,0.032989502,-0.08477783,0.02508545,-0.01626587,0.026657104,0.029785156,-0.034332275,0.0034008026,0.027145386,-0.013313293,-0.017333984,0.00579834,-0.