INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('대규모_테러_공격', '대규모 테러 공격', 'HISTORY', '["9.11", "테러", "항공기 납치", "건물 붕괴", "테러리즘"]', '09-11', '2001년 9월 11일, 알카에다 테러리스트들이 민항기 4대를 납치해 뉴욕 세계무역센터 쌍둥이 빌딩, 워싱턴 국방부 청사(펜타곤)를 공격한 사상 최대의 테러 사건. 2,977명이 사망하고 6,000명 이상이 부상당했으며, 이후 미국의 아프가니스탄·이라크 침공으로 이어져 전 세계의 지정학적 판도를 바꿨다. 매년 9월 11일 전후로 미국 및 서방권에서 추모 분위기가 조성된다.', '["INTL-022"]', '[-0.035461426,0.02204895,0.05279541,0.01020813,-0.0146865845,-0.029647827,-0.023269653,0.033996582,-0.024215698,-0.011405945,0.0054740906,0.009262085,-0.026168823,-0.010307312,-0.030685425,-0.0029640198,-0.017913818,0.028839111,0.0062942505,-0.036499023,-0.019195557,-0.004611969,-0.03591919,-0.021697998,0.021438599,0.03479004,-0.018569946,0.0063552856,0.02822876,0.021316528,0.048187256,-0.008682251,0.0022239685,0.010795593,0.013442993,-0.023071289,0.013450623,-0.029708862,0.018478394,0.013824463,0.027145386,-0.022232056,-0.012939453,0.037078857,-0.00015592575,-0.024276733,-0.027542114,0.016052246,0.0362854,0.03668213,0.0021362305,0.034362793,-0.025360107,0.007911682,0.0413208,0.058532715,-0.012542725,0.010765076,0.04159546,-0.0015525818,0.004283905,-0.027282715,-0.030792236,0.031143188,0.015792847,-0.08123779,0.0048103333,0.019088745,-0.061431885,0.02645874,-0.020339966,0.025604248,-0.004119873,-0.02557373,0.068847656,0.021850586,-0.053710938,-0.044799805,-0.027450562,-0.057891846,0.015945435,0.0045204163,-0.028503418,-0.008735657,-0.007472992,-0.03543091,-0.09460449,-0.01133728,-0.010795593,0.025054932,-0.06488037,0.055358887,0.03277588,0.02418518,-0.022354126,-0.034698486,0.011154175,0.03564453,-0.026428223,0.036132812,-0.030731201,-0.006290436,0.007686615,-0.014831543,-0.007095337,-0.068847656,0.00083589554,0.017654419,0.006752014,0.012702942,-0.00095653534,0.0037593842,-0.06945801,0.04458618,-0.0027942657,0.0035362244,0.017318726,-0.021881104,-0.020690918,0.013999939,-0.05630493,-0.02709961,0.047790527,-0.040588