INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('원전_폭발_및_방사능_오염', '원전 폭발 및 방사능 오염', 'DISASTER', '["체르노빌", "원전 폭발", "방사능 유출", "핵 사고"]', '04-26', '1986년 4월 26일 새벽, 소련(현 우크라이나) 체르노빌 원자력 발전소 4호기에서 발생한 폭발 사고. 역사상 최악의 원자력 사고로, 직접 사망자 외에 방사능 피폭으로 인한 장기 사망자가 수만~수십만 명에 달하는 것으로 추산된다. 폭발로 방출된 방사성 물질은 유럽 전역에 퍼졌으며, 반경 30km 내 지역은 현재도 거주 불가능한 출입 금지 구역으로 남아 있다.', '[]', '[-0.0026226044,0.12023926,0.048706055,0.027557373,-0.0501709,-0.03161621,-0.009628296,-0.020401001,0.0054092407,-0.013801575,0.03793335,-0.008300781,-0.024841309,-0.025421143,0.021728516,0.046539307,-0.030807495,0.014663696,-0.024414062,-0.060333252,-0.043884277,-0.021896362,-0.021224976,0.019348145,0.0047416687,0.015670776,0.014976501,0.02935791,-0.09613037,0.012924194,0.045318604,-0.016082764,-0.02180481,0.0070266724,0.044128418,-0.008995056,0.07281494,-0.0118637085,0.0011367798,-0.0072250366,-0.021591187,-0.06616211,-0.032073975,0.044799805,-0.041931152,-0.021606445,-0.03036499,0.0124053955,0.049621582,0.003824234,-0.004875183,0.058654785,-0.006755829,0.00630188,0.028427124,0.020889282,-0.02406311,0.0135269165,-0.0035133362,-0.042663574,0.022369385,-0.02456665,-0.020492554,0.017440796,-0.011688232,-0.056884766,0.05126953,-0.0012950897,-0.014930725,0.037353516,0.06036377,0.018707275,0.01927185,0.021057129,0.011955261,0.023849487,-0.046661377,-0.024795532,-0.066589355,-0.00045204163,0.027893066,-0.0002117157,-0.02923584,-0.0003733635,-0.016815186,-0.006465912,-0.02961731,-0.02835083,6.252527e-05,0.05722046,-0.081970215,0.022277832,0.038726807,-0.012069702,0.01550293,-0.013267517,0.01852417,0.011131287,0.050811768,0.050628662,-0.006755829,-0.057006836,0.06036377,0.033996582,0.027557373,-0.048217773,-0.024139404,0.003293991,-0.028823853,-0.022705078,0.0025844574,0.017532349,-0.07928467,0.057891846,0.00818634,0.02468872,0.039489746,-0.024276733,0.030639648,0.04486084,-0.0072784424,-0.0014543533,-0.0065612793,-0.008491516,-0.04660