INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('재일_조선인_집단_학살', '재일 조선인 집단 학살', 'HISTORY', '["관동대학살", "조선인 학살", "유언비어", "자경단 학살"]', '09-01', '1923년 9월 1일 일본 도쿄·요코하마 일대를 강타한 관동대지진 직후, ''조선인이 우물에 독을 탔다'', ''방화한다''는 등의 유언비어가 퍼지면서 일본 자경단과 군경이 재일 조선인 6,000여 명(추정)을 집단 학살한 사건. 중국인·사회주의자 등도 희생되었다. 일본 정부는 아직까지 공식적으로 사과하지 않고 있으며, 학살 규모를 축소하려는 역사 수정주의와의 논쟁이 현재까지 이어지고 있다.', '[]', '[-0.021697998,0.03439331,0.05618286,0.02104187,0.015541077,-0.023849487,-0.023406982,0.033325195,-0.032226562,-0.044281006,0.0362854,-0.0016870499,0.026229858,0.014572144,0.036743164,-0.02607727,0.006385803,0.03265381,-0.00094747543,0.041229248,0.019699097,-0.052978516,0.024261475,0.040008545,0.011192322,-0.0021076202,0.033843994,-0.0079422,-0.04586792,0.005897522,0.048217773,-0.009231567,-0.021438599,-0.022613525,0.0065345764,-0.031036377,0.025131226,-0.005050659,-0.068115234,-0.015304565,-0.022415161,-0.054534912,0.017242432,0.014038086,-0.051361084,0.03024292,0.02999878,0.016540527,0.03668213,0.04650879,-0.028839111,0.070251465,0.041992188,-0.04800415,-0.030090332,0.020584106,-0.017333984,-0.03378296,-0.006088257,-0.008979797,0.052978516,-0.044128418,-0.039398193,0.04147339,-0.034332275,-0.05130005,0.025177002,0.041931152,-0.034820557,0.0178833,0.03692627,0.03552246,0.031082153,0.007610321,-0.03616333,0.0073432922,-0.011680603,-0.0038280487,-0.06677246,0.024597168,0.012336731,0.040985107,-0.024291992,-0.009536743,0.017700195,-0.0024318695,-0.012428284,-0.049346924,0.014389038,-0.02017212,-0.019760132,0.038879395,-0.031555176,0.005050659,0.036712646,-0.01889038,0.012275696,0.0076942444,0.019073486,-0.012779236,-0.024612427,-0.03250122,-0.008171082,0.0042381287,-0.00027656555,-0.016418457,-0.013206482,0.007411957,-0.06518555,-0.009796143,-0.00982666,0.0053253174,-0.016708374,0.010406494,-0.011245728,0.0012836456,0.034118652,-0.058380127,-0.033203125,0.0017108917,0.015296936,0.037994385,-0.006313324,0.0027980804,