INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('식민지_강점_및_국권_피탈', '식민지 강점 및 국권 피탈', 'HISTORY', '["경술국치", "한일병합", "국권 상실", "매국", "식민 지배 시작"]', '08-29', '1910년 8월 29일, 대한제국이 일본 제국에 강제 합병되어 국권을 완전히 상실한 날. 친일 내각의 이완용과 일본 통감 데라우치 마사타케가 체결한 한일병합조약으로 조선은 공식적으로 일본의 식민지가 되었다. 이 날은 ''나라를 잃은 치욕''이라는 뜻의 ''경술국치(庚戌國恥)''로 불리며, 독립운동가들과 민중의 통분과 저항의 기원이 된 날이다. 조약 체결 당일 매국에 항의하여 자결한 관료와 지식인도 있었다. 광복절(8월 15일)과 약 2주 시차를 두고 위치하며, 이 시기는 일제강점기와 독립운동 역사가 집중 재조명되는 기간이다. 일본 기업·브랜드 관련 광고나 일본과의 역사적 관계를 소재로 한 마케팅은 이 시기에 특히 강한 반감을 유발할 수 있다.', '[]', '[-0.04260254,0.072143555,-0.007160187,0.01965332,0.045166016,-0.010925293,-0.029129028,0.022781372,-0.0073165894,-0.038024902,0.08178711,0.0141067505,-0.02708435,0.01979065,0.050628662,-0.020111084,-0.030944824,0.0440979,-0.008903503,0.025009155,0.047668457,0.0077667236,-0.045776367,0.043792725,-0.0357666,0.007045746,-0.025680542,0.014709473,-0.027908325,-0.032165527,-0.013641357,-0.008293152,0.0029182434,-0.033111572,0.018463135,-0.008964539,0.036712646,-0.0055503845,-0.02720642,-0.0045280457,-0.026000977,-0.0496521,0.006855011,0.03125,-0.0231781,-0.04623413,0.014709473,0.029815674,0.03366089,0.020050049,-0.0039634705,0.004890442,-0.02961731,-0.041259766,-0.00831604,0.02267456,-0.022140503,0.007904053,0.01737976,-0.025268555,0.015533447,-0.026687622,-0.023635864,-0.030914307,-0.0044784546,-0.027786255,0.026824951,-0.0051841736,0.015975952,0.010253906,0.007801056,-0.021362305,0.013755798,-0.03265381,-0.034851074,0.025726318,-0.025939941,0.051940918,-0.020645142,0.002445221,0.016220093,0.011207581,-0.038970947,0.040374756,0.022888184,-0.02029419,-0.10699463,0.013748169,0.00945282,0.035888672,-0.02835083,0.061798096,-0.005393982,0.0635376,0.052459717,-0.0050468445,-0.023513794,0.038269043,-0.007133484,0.046539307,-0.03265381,-0.008110046,0.022155762,0.022979736,0.043640137,0.00026750565,-0.0034656525,-0.006839752,-0.034423828,-0.0044555664,0.034118652,0.0015630722,