INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('항일_의거_및_독립_투쟁', '항일 의거 및 독립 투쟁', 'HISTORY', '["안중근", "이토 히로부미 저격", "하얼빈 의거", "순국"]', '10-26', '1909년 10월 26일, 독립운동가 안중근 의사가 중국 하얼빈 역에서 조선 침략의 원흉으로 지목한 일본 초대 통감 이토 히로부미를 권총으로 저격·사살한 날. 안중근 의사는 현장에서 체포된 후 뤼순 감옥에서 이듬해 3월 26일 순국했다. 그는 사형 직전까지 『동양평화론』을 집필하며 동아시아 평화 공존의 비전을 제시한 사상가이기도 하다. 한국에서 가장 존경받는 독립운동가 중 한 명으로, 그의 이름·이미지·손도장(단지동맹 상징)은 강한 민족주의적 감수성과 결부되어 있다. 상업적 맥락에서 안중근 의사의 이미지나 어록을 무분별하게 차용하는 것은 역사 인식 부재로 비판받을 수 있으며, 10월 26일은 박정희 대통령 시해일(1979)과 날짜가 겹쳐 정치적 감수성이 이중으로 높은 날이기도 하다.', '[]', '[-0.04638672,-0.008529663,1.2218952e-05,0.02293396,0.012054443,-0.013580322,-0.0012569427,0.06225586,-0.038513184,-0.032714844,0.0099105835,0.041107178,-0.028823853,0.00019645691,1.7881393e-05,-0.013458252,-0.040039062,0.062316895,-0.0052757263,0.042877197,0.0007548332,-4.696846e-05,-0.03302002,0.07733154,0.00031352043,0.009468079,0.02998352,0.009857178,0.00033330917,-0.05859375,-0.021911621,0.002790451,-0.005897522,-0.03326416,0.022888184,-0.01902771,-0.012496948,-0.026412964,-0.0124053955,-0.032928467,-0.00053977966,-0.031921387,0.024856567,0.07019043,-0.018951416,-0.076538086,0.022766113,0.013046265,0.027862549,-0.00010770559,-0.0032901764,0.013175964,0.010276794,-0.05404663,-0.03475952,0.0005955696,-0.025360107,-0.02293396,0.031173706,-0.0066223145,-0.01007843,-0.06994629,-0.08459473,0.026016235,-0.0054969788,0.0055732727,0.011253357,-0.0152282715,-0.0178833,0.0021781921,0.028625488,-0.011428833,0.0013856888,-0.014091492,-0.0006146431,0.004688263,-0.010871887,0.041534424,-0.06402588,0.02229309,0.005344391,0.020355225,-0.021148682,0.01285553,0.025512695,0.021774292,-0.07446289,-0.015151978,0.028320312,-0.010879517,-0.05935669,0.005138397,0.012008667,0.012062073,0.0004930496,-0.0050354004,0.0032539368,0.037231445,-0.014732361,0.033172607,-0.01348114,0.0015649796,-0.0011587143,0.020858765,-0.046905518,0.022583008,0.020492554,0.0070495605,-0.000298