INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('독재_탄압_및_시민_저항', '독재 탄압 및 시민 저항', 'POLITICS', '["최루탄", "호헌 철폐", "이한열", "박종철 고문 사망"]', '06-10', '1987년 6월 10일을 전후해 벌어진 전국적인 민주화 운동. 박종철 고문 사망 사건 은폐 의혹과 전두환 정권의 4.13 호헌 조치에 분노한 시민·학생 수십만 명이 거리로 나섰으며, 최루탄을 맞은 이한열 열사의 죽음이 항쟁을 더욱 격화시켰다. 결국 노태우 민주정의당 대표가 ''6.29 민주화 선언''을 발표하며 대통령 직선제 개헌을 약속했고, 이는 1987년 헌법 체제의 출발점이 되었다.', '[]', '[-0.0020389557,0.0034122467,-0.0077552795,0.018707275,9.6678734e-05,-0.0138168335,-0.02519226,0.04663086,0.023498535,-0.064331055,0.051696777,0.036499023,-0.047058105,-0.0064811707,0.013465881,-0.03591919,-0.013458252,-0.0034637451,-0.0041275024,0.05038452,0.02734375,-0.048858643,0.026779175,0.02859497,0.02279663,0.056671143,0.0079193115,0.014381409,-0.008865356,-0.02015686,0.0046920776,-0.00504303,0.005214691,-0.05267334,-0.012161255,-0.027038574,0.013847351,-0.016418457,0.021697998,-0.008911133,0.04663086,-0.034179688,-0.010772705,0.033111572,0.024246216,-0.005203247,-0.012992859,0.06591797,0.07849121,0.047332764,0.057739258,0.009300232,0.01838684,-0.012031555,-0.027069092,0.02532959,-0.027618408,-0.018295288,0.01259613,-0.0138168335,0.035064697,-0.016952515,-0.053985596,-0.017913818,0.0040397644,-0.03604126,0.027786255,-0.025100708,0.0067825317,0.03665161,0.023422241,-0.003364563,0.012290955,-0.0151901245,0.022216797,-0.007221222,-0.050933838,0.049438477,-0.04675293,0.041259766,0.0067596436,0.03677368,-8.21352e-05,0.023483276,-0.0075798035,-0.055023193,-0.0690918,-0.032470703,0.023712158,0.008361816,-0.053771973,0.032073975,0.029968262,0.021728516,0.040985107,-0.080200195,0.008384705,0.022445679,0.02835083,0.016845703,-0.061798096,-0.012527466,0.008079529,-0.010681152,-0.011039734,0.036987305,-0.012268066,-0.04220581,-0.06463623,0.0069618225,0.008232117,0.0032577515,-0.09075928,0.013702393,-0.02859497,0.01889038,0.0012178421,-0.02331543,-0.013282776,0.012084961,0.022216797,-0.056732178,0.002363205,0.009246826,