INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('민중_봉기_무력_학살', '민중 봉기 무력 학살', 'HISTORY', '["동학", "농민 학살", "갑오", "전봉준", "관군 진압"]', NULL, '1894년(갑오년) 전라도 고부에서 시작되어 전국으로 번진 대규모 농민 봉기. 전봉준 장군을 지도자로 한 동학 농민군은 탐관오리 척결, 신분 차별 철폐, 외세 배격을 기치로 내걸고 봉기했으며, 전주성을 점령하는 등 한때 전라도 전역을 장악했다. 조선 정부가 진압을 위해 청나라 군대를 요청하면서 청일전쟁의 빌미가 되었고, 일본군과 관군의 합동 진압으로 수만 명의 농민이 학살되며 운동은 막을 내렸다. 이 운동은 이후 3.1 독립운동, 4.19 혁명, 5.18 광주민주화운동으로 이어지는 한국 민중 저항 역사의 원류로 평가받는다.', '[]', '[-0.023712158,0.057128906,0.014328003,0.02079773,0.04248047,-0.02104187,-0.008987427,0.008117676,-0.033966064,-0.01878357,-0.0024585724,0.038757324,-0.06384277,0.041015625,0.08972168,-0.023880005,0.008361816,0.026031494,-0.03265381,0.023834229,6.4492226e-05,-0.00071811676,0.009216309,0.0034179688,-0.0051574707,-0.013618469,-0.002614975,-0.029449463,0.0050849915,-0.044189453,0.010368347,-0.0048675537,-0.04498291,-0.032165527,0.0017538071,-0.04232788,0.05407715,0.026351929,0.001335144,0.0146102905,-0.0054779053,-0.09588623,0.019805908,0.018310547,-0.001291275,-0.018432617,0.009483337,0.044128418,0.053985596,0.026275635,-0.0048179626,0.010307312,0.033325195,-0.030029297,-0.024841309,0.017425537,-0.019180298,-0.034729004,-0.0234375,-0.039367676,0.06274414,-0.032196045,-0.015205383,0.04776001,0.06317139,-0.03024292,0.022537231,-0.0046463013,0.016281128,0.006542206,0.020858765,-0.040496826,0.01864624,-0.013877869,-0.04736328,0.051452637,-0.025558472,-0.017471313,-0.09094238,0.05731201,0.006778717,0.05783081,0.0030269623,0.003545761,0.044769287,-0.008987427,-0.049560547,0.020401001,0.023452759,0.008071899,-0.0070495605,0.000344038,-0.015411377,0.06726074,0.061431885,0.0026397705,0.011543274,0.015670776,0.07922363,0.044952393,-0.05987549,-0.001581192,0.046081543,0.014480591,0.019958496,-0.01524353,-0.026626587,-0.03326416,-0.06665039,0.0007648468,0.013053894,0.045806885,-0.007472992,-0.0042648315,0.021133423,0.026626587,0.033203125,-0.05517578,-0.04364