INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('선박_침몰_및_구조_실패', '선박 침몰 및 구조 실패', 'DISASTER', '["세월호", "침몰", "구조 방기", "수학여행 참사", "304명"]', '04-16', '2014년 4월 16일, 전라남도 진도군 인근 해상에서 인천발 제주행 여객선 세월호가 침몰하면서 탑승자 304명이 사망·실종된 대형 참사. 희생자의 절반 이상이 수학여행을 떠나던 안산 단원고등학교 학생들이었다. ''가만히 있으라''는 방송 속 배 안에서 대기하다 희생된 아이들의 이야기, 정부의 늑장 대응과 해경 철수 등은 사회 전체에 깊은 트라우마를 남겼다. 4월 16일 전후는 온라인 전체가 추모 분위기이며, 바다·배·구조·탈출 등의 단어를 마케팅 캠페인에 경솔하게 활용하면 극도의 비난을 받는다. 노란 리본 이미지 또한 세월호 추모 상징으로 상업적 사용이 부적절하다.', '["KR-003", "KR-029"]', '[0.007434845,0.039855957,0.003982544,-0.008369446,-0.015113831,0.017913818,-0.025863647,0.016860962,0.026138306,-0.020248413,0.0067329407,-0.029052734,-0.060699463,0.0058288574,0.00025558472,-0.0051116943,-0.048828125,-0.0035076141,-0.019317627,0.024490356,-0.014854431,-0.038970947,-0.015464783,0.009269714,0.03616333,-0.03604126,0.015411377,0.050842285,0.030441284,0.017822266,0.037231445,-0.010131836,-0.0049705505,-0.008377075,-0.026382446,0.036254883,0.010734558,-0.025909424,0.004032135,-0.0010271072,0.02394104,-0.050933838,-0.015731812,0.02168274,-0.001616478,0.05407715,-0.03616333,-0.008880615,0.077941895,0.035980225,0.010826111,0.042938232,0.00472641,0.04232788,-6.7949295e-06,-0.016204834,-0.016281128,-0.004840851,-0.011352539,-0.03933716,0.064697266,-0.044952393,-0.027313232,0.020401001,-0.027389526,-0.05810547,-0.013214111,-0.007820129,-0.04260254,0.048919678,0.024398804,0.011657715,0.040008545,-0.010643005,-0.011100769,0.023849487,-0.012878418,-0.027740479,-0.06518555,-0.004005432,0.059753418,-0.00166893,0.018554688,0.016693115,0.008926392,-0.005004883,-0.06921387,-0.00049877167,0.01121521,0.009025574,-0.061920166,0.045074463,0.05770874,-0.0062675476,0.013000488,-0.09295654,0.0032482147,0.0524292,0.0039901733,0.022277832,-0.008071899,-0.040039062,0.034851074,-0.030960083,0.034179688,-0.020385742,-0.026367188,-0.019042969,-0.02368164,0.01751709,-0.042785645,0.0034446716,-0.14416504,0.