INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('지하철_방화_및_대규모_사상', '지하철 방화 및 대규모 사상', 'DISASTER', '["대구 지하철 화재", "방화", "질식사", "대중교통 참사"]', '02-18', '2003년 2월 18일, 대구 도시철도 1호선 중앙로역에서 방화범의 방화로 발생한 화재로 지하철 두 편성이 전소되며 192명이 사망하고 148명이 부상당한 대형 참사. 사망자 대부분이 정전으로 어둠 속에서 탈출하지 못하고 질식사했으며, 이후 지하철 안전 기준 강화의 계기가 되었다. 방화범은 정신질환자로 알려져 정신질환에 대한 사회적 논쟁도 불러일으켰다.', '[]', '[0.029281616,-0.009239197,0.010009766,0.018218994,-0.026519775,-0.03817749,-0.026351929,0.01247406,0.0019264221,-0.011260986,-0.009017944,-0.0036621094,-0.025909424,0.03540039,-0.0069847107,-0.03491211,0.014701843,-0.0028419495,0.04534912,0.0030765533,-0.040405273,-0.05758667,0.0029697418,-0.02420044,0.0029411316,-0.014694214,0.01940918,0.022613525,-0.010292053,-0.020004272,-0.0026950836,-0.0047073364,-0.004348755,-0.025726318,-0.006198883,0.00021243095,-0.053894043,0.028182983,0.031433105,-0.0036811829,0.0079422,0.0019798279,-0.019577026,0.07043457,-0.0058937073,-0.0049858093,-0.0035305023,0.025894165,0.059631348,0.01890564,0.04498291,0.05810547,0.0026626587,0.001964569,0.006214142,0.0357666,0.012763977,-0.0013771057,0.024246216,-0.067871094,0.0423584,-0.06896973,-0.038238525,0.026016235,-0.010322571,-0.047851562,0.012649536,-0.039031982,-0.017318726,0.0011177063,0.02494812,0.0028686523,0.038269043,-0.0057907104,0.038116455,-0.016616821,-0.020492554,-0.05117798,-0.037994385,0.045440674,0.046936035,0.005680084,-0.05038452,0.02720642,-0.0006155968,-0.03387451,-0.061279297,-0.009674072,-0.00074386597,0.021102905,0.0006175041,0.041534424,-0.019546509,0.027069092,0.006011963,-0.040863037,0.045928955,8.7320805e-05,-0.0023326874,0.009262085,-0.0006775856,0.020263672,0.022583008,0.0016469955,0.0073165894,-0.027175903,-0.025115967,-0.002922058,-0.02746582,-0.011512756,0.014030457,0.03692627,-0.045654297,0.025985718,0.005569458,0.03286743,0.051940918,-0.06222534,-0.03225708,0.024383545,-0.08001709,0.007423401,-0.0024662018,-0.014526367,