INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('부실_시공_건물_붕괴', '부실 시공 건물 붕괴', 'DISASTER', '["삼풍 붕괴", "부실 시공", "건물 붕괴", "안전 불감증"]', '06-29', '1995년 6월 29일 오후 5시 52분, 서울 서초구 삼풍백화점이 부실 시공과 안전 무시로 인해 20초 만에 완전 붕괴된 사고. 영업 중 무너진 건물로 502명이 사망하고 937명이 부상당했으며, 구조 작업 17일 만에 생존자가 발견되는 등 한국 역사상 최악의 건물 붕괴 사고로 기록되어 있다. 사고 원인은 건물주의 무단 구조 변경과 당국의 부실 관리·감독이었으며, 이는 한국 사회의 ''빨리빨리'' 문화와 안전 불감증에 대한 사회적 반성을 촉구했다.', '[]', '[0.009773254,0.079956055,-0.006134033,0.024841309,-0.010437012,-0.008338928,-0.028640747,0.00522995,0.014076233,-0.031677246,0.03161621,-0.011070251,-0.0073776245,-0.04244995,0.01058197,0.007160187,0.0013513565,-0.011749268,-0.0009841919,-0.068481445,-0.018234253,-0.043060303,-0.07434082,0.007007599,-0.016448975,-0.016983032,0.017593384,0.05621338,0.01927185,-0.004386902,0.007587433,-0.0098724365,0.013000488,-0.03111267,0.0236969,-0.00031971931,-0.016647339,0.008110046,0.0088272095,-0.0131073,0.015670776,-0.05029297,-0.027496338,0.01259613,-0.017150879,0.01979065,-0.020401001,0.04837036,0.03942871,0.041931152,-0.008033752,0.020248413,-0.02861023,-0.02809143,-0.005680084,-0.0035629272,-0.029449463,-0.00011098385,-0.013290405,0.019073486,0.0413208,-0.0088272095,-0.0073242188,0.014549255,0.01828003,-0.06915283,0.012519836,0.045806885,-0.04232788,0.042388916,-0.0027866364,-0.0032138824,0.018508911,-0.00881958,0.004497528,-0.022537231,-0.015151978,0.0005221367,-0.040100098,-0.029083252,0.0317688,0.021820068,-0.045135498,0.051818848,-0.0048561096,-0.045898438,-0.078063965,0.015075684,-0.004425049,0.044708252,-0.05014038,0.036071777,0.04458618,-0.002494812,0.005466461,-0.038726807,0.030761719,0.0066452026,0.0146102905,0.028137207,-0.009407043,-0.009475708,0.029083252,-0.029296875,-0.008659363,0.007007599,-0.026245117,-0.018432617,-0.026397705,-0.03112793,-0.00422287,0.0043907166,-0.07293701,0.088134766,0.017623901,0.012420654,0.017807007,-0.008934021,0.023956299,0.023864746,-0.012496948,0