INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('군중_밀집_압사_사고', '군중 밀집 압사 사고', 'DISASTER', '["이태원 압사", "군중 압사", "핼러윈 참사", "밀집 사고"]', '10-29', '2022년 10월 29일 밤, 서울 용산구 이태원 해밀턴 호텔 인근 골목에서 핼러윈 행사 인파가 밀집하여 159명이 압사 사망하고 197명이 부상당한 참사. 희생자 평균 연령이 20대로, 대다수가 젊은 청년들이었다. 사전 안전 대책 부재와 경찰·소방·지자체의 대응 실패가 도마에 올랐으며, 이후 정부의 책임 회피와 유가족 지원 미비로 장기간 사회적 갈등이 이어졌다. 10월 말 핼러윈 시즌 마케팅, 축제·파티·군중 관련 이벤트 광고는 2022년 이후 매년 이 시기에 극도로 민감한 여론에 직면한다.', '["KR-017"]', '[-0.04168701,0.031158447,0.004547119,-0.012619019,-0.0030021667,-0.03463745,-0.03869629,0.051086426,-0.018630981,-0.04510498,0.008964539,-0.04876709,-0.036895752,0.0124053955,0.011634827,0.013092041,-0.031829834,-0.024505615,-0.040008545,-0.012634277,-0.012710571,-0.024810791,-0.014755249,-0.026321411,0.0011482239,0.016159058,0.049072266,-0.010108948,-0.003982544,0.030395508,0.025344849,-0.009513855,-0.011993408,-0.0045280457,-0.0137786865,0.027679443,0.060699463,0.009567261,-0.0057678223,-0.044708252,0.02458191,-0.022659302,-0.049560547,-0.009941101,0.035217285,0.011009216,0.010055542,0.02645874,0.030929565,0.026611328,0.04510498,0.04244995,-0.042175293,0.033050537,0.038238525,0.0034427643,0.0070991516,-0.029403687,0.044555664,-0.0073127747,0.052368164,-0.013160706,-0.020874023,0.0116119385,0.022277832,-0.03451538,0.028396606,0.05050659,-0.018066406,0.043670654,0.00091934204,-0.0068130493,0.02470398,-0.02432251,0.014633179,0.020187378,-0.024810791,-0.030044556,-0.040222168,-0.00050115585,0.047180176,-0.014221191,-0.012199402,0.009407043,-0.0072364807,-0.004623413,-0.0904541,0.0065078735,-0.011817932,0.012046814,-0.029678345,0.060546875,0.024337769,0.035186768,0.0052986145,-0.07373047,0.04159546,0.023086548,-0.0032405853,0.010047913,-0.00566864,-0.01109314,0.07733154,-0.060272217,0.02607727,-0.052337646,-0.03137207,-0.029281616,0.0118637085,0.007724762,0.04156494,-0.001619339,-0.07763672,0.056518555,-0.016830444,0.028762817,0.035888672,0.01763916,0