INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('교량_붕괴_및_인명_피해', '교량 붕괴 및 인명 피해', 'DISASTER', '["성수대교 붕괴", "다리 붕괴", "출근길 참사", "한강 추락"]', '10-21', '1994년 10월 21일 아침 출근 시간, 서울 성동구와 강남구를 잇는 성수대교의 상판 일부(48m 구간)가 갑자기 붕괴되어 승용차·버스 등이 한강으로 추락하며 32명이 사망하고 17명이 부상당한 사고. 사고 원인은 부실 시공과 부적절한 유지보수로 밝혀졌으며, 1995년 삼풍백화점 붕괴와 함께 1990년대 한국의 ''총체적 안전 불감증''을 상징하는 사건으로 기록되어 있다.', '[]', '[-0.041229248,0.071899414,0.014549255,0.017654419,-0.014289856,-0.020309448,-0.048706055,0.049591064,-0.011886597,-0.045196533,0.048950195,-0.019119263,-0.010673523,0.02897644,-0.004714966,-0.021728516,0.0012493134,-0.009750366,-0.023544312,0.005405426,0.0027656555,-0.0075950623,-0.034118652,0.02204895,-0.012367249,-0.0058517456,0.060760498,0.06756592,0.01876831,-0.03186035,-0.0069847107,0.0011529922,-6.5267086e-05,-0.037017822,0.018859863,0.014053345,-0.027862549,0.01953125,-0.039245605,-0.05731201,0.026901245,-0.048583984,-0.027313232,0.01626587,-0.009109497,0.022964478,0.0066108704,0.027282715,0.01953125,0.036254883,0.02406311,0.030227661,-0.033477783,0.049835205,0.042938232,0.0048103333,-0.0340271,-0.007068634,0.009941101,-0.037078857,0.023223877,-0.032196045,-0.01914978,0.00045871735,0.006137848,-0.088012695,0.0068244934,-0.011383057,-0.05908203,0.0446167,-0.0014677048,-0.013908386,0.050354004,-0.011489868,0.047607422,-0.0075912476,-0.008872986,-0.018356323,-0.029571533,-0.0057258606,0.04977417,1.5437603e-05,-0.023101807,0.02218628,-0.034210205,-0.05065918,-0.070617676,0.040649414,-0.015167236,0.051635742,-0.05001831,0.038757324,0.02986145,-0.010894775,0.0077056885,-0.053466797,0.0087509155,0.007610321,0.035339355,0.010437012,-0.037597656,-0.019973755,0.07336426,-0.018478394,0.0062789917,-0.009132385,0.006690979,-0.016693115,0.0005927086,-0.008255005,0.031341553,-0.008903503,-0.058685303,0.08050537,0.05718994,0.018508911,0.040527344,-0.008842468,0.009635925,0.05154419,-0.017303467,-0.009719849,0.018066406,-0.0094