INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('지진_쓰나미_원전_복합_재난', '지진·쓰나미·원전 복합 재난', 'DISASTER', '["후쿠시마", "방사능 오염", "쓰나미 피해", "원전 멜트다운"]', '03-11', '2011년 3월 11일, 일본 미야기현 인근 해저에서 규모 9.0의 초강력 지진이 발생하고 이어진 쓰나미로 인해 약 22,000명이 사망·실종된 재난. 지진과 쓰나미는 후쿠시마 제1원자력발전소에도 심각한 손상을 입혀 역사상 두 번째로 심각한 원전 사고(INES 7등급)로 이어졌으며, 방사성 물질이 대기와 해양으로 방출되었다. 한국에서는 이후 일본산 수산물 방사능 오염 논란이 수년간 이어졌다. 일본 관련 식품·관광·수산물 광고에서 이 사건의 민감도는 현재까지도 지속되고 있다.', '[]', '[0.00036144257,0.030532837,0.014297485,0.03302002,-0.015777588,-0.020828247,-0.0090789795,0.03225708,0.00894165,-0.045684814,-0.008132935,-0.012496948,-0.056762695,0.00919342,-0.035064697,0.0138549805,-0.040527344,-0.013046265,-0.0007276535,0.00011050701,-0.041107178,-0.029403687,-0.011672974,-0.01713562,0.035186768,0.01146698,0.02746582,0.048858643,-0.0060043335,-0.007160187,0.017654419,-0.018432617,-0.015533447,0.02015686,-0.019882202,-0.022369385,0.019577026,-0.013824463,-0.046447754,0.006614685,-0.007499695,-0.017700195,0.0004582405,0.041015625,-0.034362793,-0.025543213,0.0042266846,0.012870789,0.0524292,0.010955811,0.009567261,0.011871338,0.007659912,-0.0043907166,0.0035324097,0.0033931732,0.03466797,0.050994873,0.011154175,-0.03540039,0.022079468,-0.05895996,-0.054504395,0.01852417,-0.017166138,-0.05630493,0.047729492,-0.010055542,-0.02911377,0.051971436,-0.013412476,-0.036010742,0.004070282,-0.0033931732,-0.016098022,0.0026893616,-0.050323486,-0.028137207,-0.06378174,0.02861023,0.06311035,0.015068054,-0.030212402,-0.0035057068,-0.0058555603,0.02519226,-0.056121826,-0.015945435,-0.027999878,0.06185913,-0.10241699,0.022979736,0.010719299,0.05621338,-0.013092041,-0.05215454,0.013015747,0.0075263977,0.039978027,0.04348755,0.01373291,0.01737976,0.0037498474,0.019973755,0.022338867,-0.041259766,-0.021911621,0.015975952,0.0015001297,-0.05239868,0.090148926,-0.005584717,-0.07196045,0.0026626587,-0.038146973,0.011268616,0.0035820007,-0.0070648193,0.0068626404,