INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('계엄군_민간인_학살', '계엄군 민간인 학살', 'POLITICS', '["5.18", "공수부대 진압", "계엄 학살", "광주 민주화", "신군부"]', '05-18', '1980년 5월 18일부터 27일까지 광주·전남 지역 시민들이 신군부의 비상계엄 확대와 민주주의 탄압에 맞서 봉기한 민주화 운동. 전두환을 중심으로 한 신군부는 공수부대를 투입해 시민군을 무력으로 진압했으며, 공식 사망자는 166명이지만 실제 희생자는 수백 명이 넘는 것으로 추정된다. 유네스코 세계기록유산에 등재된 기록물을 보유하고 있으며, 매년 5월 18일에 기념식이 열린다.', '["KR-001", "KR-011", "KR-022"]', '[0.008331299,0.07928467,-0.017303467,0.05493164,0.0037059784,-0.008407593,-0.013954163,0.00055646896,0.011413574,-0.060058594,0.026687622,-0.018356323,-0.02520752,0.06866455,0.06222534,-0.035186768,-0.02784729,0.01625061,-0.03543091,0.009681702,0.020843506,-0.00026750565,0.007736206,0.04159546,0.026184082,-0.030395508,0.033691406,0.020355225,-0.007095337,-0.022781372,0.042297363,-0.00932312,0.0011062622,-0.06604004,-0.0043296814,-0.03326416,0.03604126,-0.012718201,0.024795532,-0.03463745,0.0040893555,-0.040985107,-0.068359375,0.018295288,0.010025024,0.0033473969,-0.026748657,0.04989624,0.051605225,0.052612305,0.004940033,0.0021514893,0.048980713,-0.017745972,-0.035827637,0.023635864,0.0069122314,-0.010032654,-0.01727295,-0.039276123,0.016281128,-0.02456665,-0.020309448,0.04397583,0.034240723,-0.033966064,0.045684814,-0.010986328,-0.0038661957,0.0132369995,0.011268616,0.00031495094,0.058044434,-0.03652954,-0.009529114,0.04901123,0.039276123,0.004005432,-0.107177734,0.022415161,0.03463745,0.024993896,0.020004272,0.007484436,-0.0055885315,-0.0031776428,-0.055847168,0.007972717,0.053466797,0.04043579,-0.01638794,0.006500244,-0.012435913,0.030517578,0.034698486,-0.06304932,0.03616333,-0.017364502,0.062347412,0.06088257,-0.0181427,-0.009674072,0.018753052,-0.014015198,-0.0013742447,-0.034118652,-0.011520386,-0.011405945,-0.0074768066,-0.024795532,-0.011016846,0.04434204,-0.0368042,0.040771484,-0.0053367615,0.029953003,0.012138367,-0.0055999756,-0.030395508,0.0021686554,0.02178955,0.0057373047,0