INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('국정농단_및_대통령_파면', '국정농단 및 대통령 파면', 'POLITICS', '["국정농단", "최순실", "탄핵 인용", "촛불집회", "파면"]', '03-10', '2017년 3월 10일, 헌법재판소가 박근혜 대통령에 대한 탄핵 소추안을 재판관 8인 전원 일치로 인용하며 파면을 선고한 날. 최순실 국정농단 사건으로 촉발된 ''촛불집회''와 이후 ''태극기집회''의 충돌로 국론이 극도로 분열되었으며, 선고 직후 탄핵 반대 집회에서 사망자가 발생했다. 이 사건은 현재까지도 지지·반대 진영 간 정치적 갈등의 핵심 분기점으로 작용한다.', '[]', '[-0.0035266876,0.009346008,0.03692627,0.03149414,0.022613525,-0.0023384094,0.0046806335,0.005332947,-0.0014152527,-0.039764404,0.03225708,-0.035858154,-0.027694702,0.0107421875,-0.013648987,-0.035736084,-0.011116028,-0.013290405,-0.004348755,0.04034424,0.0008468628,-0.02494812,0.025436401,0.04348755,0.033416748,-0.01727295,-0.013496399,-0.0009889603,0.0017318726,-0.00415802,0.034088135,0.0022563934,0.018432617,-0.09503174,-0.035308838,0.023742676,-0.014915466,0.005420685,-0.013015747,0.0062065125,-0.0019702911,0.0043640137,-0.029190063,0.0154800415,0.029663086,0.021713257,-0.023101807,0.068603516,0.028030396,0.0030784607,0.019439697,0.060668945,0.015670776,0.017608643,0.016464233,0.02923584,-0.008476257,-0.0062217712,0.016433716,-0.028259277,0.015213013,-0.045135498,-0.018310547,0.04916382,-0.041137695,-0.08477783,-0.0317688,0.0592041,0.02293396,0.033843994,0.029006958,-0.0016975403,-0.009468079,-0.04058838,0.0038433075,0.004169464,0.047302246,0.019226074,-0.05831909,-0.034088135,0.004020691,0.019897461,-0.011528015,0.014572144,0.027755737,-0.013931274,-0.070617676,0.01878357,0.026779175,0.0003039837,-0.082458496,0.06707764,0.0066490173,0.027008057,0.022064209,-0.023849487,-0.02633667,0.0151901245,0.004901886,0.032958984,-0.036865234,0.005378723,-0.00945282,0.0060768127,0.026062012,-0.009506226,-0.027618408,-0.009963989,-0.035461426,-0.028701782,0.036254883,-0.031234741,-0.03366089,0.006454468,0.027435303,-0.03753662,0.009819031,0.023391724,-0.021362305,-0.022949219,-0.015930176,0.021697998,-0.02178955,-0.050994873,-0.0373