INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('비상계엄_선포_및_헌정_위기', '비상계엄 선포 및 헌정 위기', 'POLITICS', '["비상계엄", "계엄군 국회 진입", "탄핵 정국", "헌정 중단"]', '12-03', '2024년 12월 3일 밤, 윤석열 대통령이 야당의 예산안 처리를 ''내란 행위''로 규정하며 긴급 비상계엄을 선포한 사건. 계엄군이 국회에 진입을 시도했으나 국회의원들이 계엄 해제 결의안을 가결하면서 6시간 만에 계엄이 해제되었다. 이후 국회는 윤석열 대통령에 대한 탄핵 소추안을 가결했으며 헌법재판소의 심판이 진행되었다.', '[]', '[0.018798828,0.025970459,0.018173218,0.051757812,0.008125305,0.02696228,0.008224487,0.006942749,-0.014350891,-0.007911682,0.051483154,-0.028045654,-0.02079773,0.042938232,0.043151855,-0.014877319,-0.0022087097,0.009689331,-0.014518738,0.035736084,-0.025817871,-0.042114258,0.011909485,0.024047852,-0.0034713745,-0.006832123,0.0024089813,0.0056762695,-0.015151978,-0.01184082,0.034454346,-0.012573242,0.027572632,-0.105529785,-0.023590088,0.0047569275,0.0029907227,0.03463745,-0.026809692,-0.027938843,-0.014732361,0.014480591,-0.032684326,0.016662598,0.051361084,0.02368164,0.0014257431,-0.018539429,0.011520386,0.043395996,0.015129089,0.06213379,0.020614624,0.07110596,-0.014816284,0.02470398,0.0019283295,-0.07501221,-0.008171082,-0.0151901245,0.008720398,-0.02960205,0.0011940002,0.046936035,0.010345459,-0.029525757,-0.014564514,0.051605225,0.02659607,0.0022945404,-0.019012451,-0.026519775,0.04650879,-0.042388916,-0.007965088,-0.007621765,0.01953125,-0.018356323,-0.020584106,0.00047683716,-0.015403748,0.0033454895,-0.010772705,0.02331543,0.006832123,-0.033447266,-0.035949707,0.010383606,0.029327393,-0.008514404,-0.06237793,0.015563965,-0.03744507,0.022033691,0.017440796,0.016281128,0.023605347,-0.013824463,0.03375244,0.03164673,-0.034942627,0.010940552,0.052703857,0.0014019012,0.04421997,0.018875122,-0.04559326,0.0023326874,-0.0017824173,-0.008872986,0.020446777,0.024795532,-0.0068588257,0.03463745,0.008270264,-0.035888672,0.0018663406,-0.0030956268,-0.017227173,0.0070381165,0.008117676,0.040039062,-0.003818512,-0.0569458,-0.06994629,0.021606445,-0.0