INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('세계_여성의_날_International_Women_s_Day', '세계 여성의 날 (International Women''s Day)', 'GENDER', '["핑크워싱", "여성 마케팅 역풍", "페미니즘 세탁", "진정성 없는 여성 광고"]', '03-08', '1975년 유엔이 공식 지정한 세계 여성의 날로, 여성의 정치·경제·사회적 권리를 기리는 날. 평소 젠더 차별적 광고나 성별 임금격차 문제를 외면하던 브랜드가 이날 하루만 여성 권리를 내세우는 행태는 소비자, 특히 여성 소비자의 강한 역반응을 불러온다. 진정성 있는 사회적 행동을 수반하지 않는 감성 마케팅은 오히려 브랜드 이미지를 해친다.', '["INTL-012", "INTL-028", "INTL-029"]', '[0.0289917,0.05014038,0.025253296,0.041290283,0.030883789,-0.041900635,0.023544312,-0.007774353,-0.020401001,-0.008018494,0.012954712,-0.0070533752,-0.054595947,-0.034210205,0.038146973,0.04815674,-0.07208252,-0.0055656433,-0.010437012,0.019058228,0.009925842,-0.0016870499,-0.025863647,0.06726074,-0.009315491,0.06286621,0.009597778,0.027648926,-0.020355225,0.03262329,0.033569336,-0.024032593,-0.018447876,-0.0748291,0.026031494,0.0070343018,-0.0056991577,0.010719299,0.030426025,0.0051078796,-0.01852417,-0.021621704,0.054779053,0.013008118,0.016738892,0.0340271,-0.02507019,0.010475159,0.05407715,0.030456543,-0.029907227,0.01828003,0.030670166,-0.0124435425,0.006504059,-0.022537231,-0.036987305,0.02458191,-0.00062799454,-0.0015516281,0.0063934326,-0.016586304,-0.033081055,-0.008834839,0.008125305,-0.0087509155,0.039093018,0.019821167,-0.003753662,0.052703857,0.058441162,-0.026397705,0.03744507,0.01965332,0.018112183,-0.0015535355,0.016906738,0.03479004,-0.0046691895,0.0029850006,-0.0234375,0.010620117,-0.059020996,0.07672119,-0.007045746,-0.023284912,-0.07745361,0.003955841,-0.010299683,0.047729492,-0.054992676,-0.0070152283,-0.013557434,0.0046920776,-0.019760132,-0.0047950745,-0.007621765,0.039520264,0.043060303,0.047180176,0.02078247,-0.029418945,0.004146576,0.016601562,-0.015113831,-0.021408081,0.030761719,0.0107040405,-0.009880066,-0.0368042,-0.027908325,0.015037537,-0.041748047,0.0418396,0.07849121,0.03753662,0.005470276,0.032989502,0.015106201,-0.004