INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('여성혐오_살인_범죄', '여성혐오 살인 범죄', 'GENDER', '["여성혐오 범죄", "묻지마 살인", "강남역 살인", "성별 표적 범죄"]', '05-17', '2016년 5월 17일, 서울 서초구 강남역 인근 공용 화장실에서 20대 여성이 면식 없는 남성에게 살해된 사건. 가해자는 ''여자들이 나를 무시해서'' 범행했다고 진술했으며, 사건은 한국 사회에서 ''여성혐오 범죄'' 논쟁의 도화선이 되었다. 피해 여성을 추모하는 포스트잇이 강남역 근처에 가득 붙으며 ''#나는_우연히_살아남았다'' 캠페인이 퍼졌고, 이는 한국 페미니즘 운동의 중요한 전환점이 되었다.', '["KR-036"]', '[0.026809692,0.05239868,0.03062439,0.051971436,0.002117157,-0.05670166,0.016799927,0.027313232,0.022003174,-0.05117798,0.028213501,0.054351807,-0.029434204,-0.0027751923,-0.002450943,-0.0023212433,0.0035152435,0.008155823,-0.059753418,-0.011749268,-0.038208008,-0.0055274963,-0.02720642,0.031585693,0.014709473,0.031921387,-0.02911377,-0.0027484894,-0.0018825531,-0.009963989,-0.0042877197,-0.0020427704,0.026931763,-0.062042236,0.02798462,-0.021392822,0.014984131,-0.01826477,0.04977417,-0.029174805,-0.013595581,-0.066833496,0.005706787,0.0051193237,0.01751709,0.040283203,-0.011383057,0.025375366,-0.021972656,0.027816772,0.01209259,-0.008361816,-0.025268555,-0.0025558472,-0.024536133,0.061584473,-0.013366699,0.023071289,-0.026870728,-0.020095825,0.055023193,0.0063934326,0.0030174255,-0.012763977,0.012130737,-0.019714355,-0.02835083,-0.007736206,-0.002407074,0.015792847,0.051818848,0.019256592,0.033355713,0.034118652,-0.027908325,0.026748657,-0.019943237,0.00756073,-0.048461914,-0.028213501,0.0026626587,0.0059051514,-0.023422241,0.042419434,0.008857727,-0.0006747246,-0.12817383,-0.021438599,0.0013742447,0.022201538,-0.060791016,0.042144775,0.008415222,-0.01386261,0.015350342,-0.072265625,0.017059326,-0.025878906,0.04473877,0.04901123,-0.0033302307,-0.025787354,0.06817627,-0.008605957,-0.010009766,-0.02671814,0.03704834,-0.017105103,-0.024612427,0.010520935,-0.015419006,-2.9802322e-07,-0.008636475,-0.002817154,0.036010742,-0.017547607,0.04437256,-0.027175903,0.020584106,0.008796692,0.010215759,-0.0038890