INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('디지털_성착취_및_불법_촬영물_유포', '디지털 성착취 및 불법 촬영물 유포', 'GENDER', '["n번방", "디지털 성범죄", "성착취물 유포", "텔레그램 성범죄"]', '03-16', '2020년 3월 16일 텔레그램 기반 성착취물 제작·유포 범죄인 ''n번방'' 주범 조주빈의 신상이 공개된 날. 박사방·n번방 등 텔레그램 대화방에서 수십 명의 여성·청소년을 협박하여 성착취물을 제작하고 수천 명의 유료 회원에게 유포한 디지털 성범죄로, 피해자 중 미성년자도 다수 포함되어 있었다. 사건 이후 ''디지털 성범죄 처벌 강화''를 요구하는 청와대 청원이 270만 명 이상의 동의를 받았다.', '["KR-041", "KR-042"]', '[0.054473877,0.029678345,-0.01612854,0.030883789,0.012969971,-0.023971558,0.0025577545,0.07208252,-0.01020813,-0.10217285,0.06488037,-0.01864624,-0.045440674,-0.011016846,-0.00806427,0.008056641,-0.0013132095,-0.044677734,-0.016586304,0.017288208,0.015838623,0.031402588,0.049743652,0.006790161,0.005718231,0.03186035,-0.019882202,-0.023483276,-0.030395508,-0.00019848347,-0.021728516,-0.019638062,-0.0035133362,-0.03967285,-0.031082153,-0.004825592,-0.012229919,-0.020751953,0.045776367,0.018859863,0.0033721924,-0.02859497,-0.015975952,0.018051147,9.1552734e-05,0.06311035,-0.01612854,-0.01210022,0.009918213,0.03768921,0.0029964447,0.051635742,0.0015773773,0.0037593842,-0.036987305,0.032714844,-0.034484863,0.010246277,-0.02468872,-0.028244019,0.05529785,-0.03817749,-0.008926392,0.028762817,-0.004005432,-0.072021484,-0.030563354,0.01626587,-0.005252838,0.0037155151,0.058258057,-0.0116119385,0.016952515,0.05368042,-0.0005273819,0.052703857,0.01828003,0.06329346,-0.019714355,-0.005832672,0.03970337,0.04916382,-0.042510986,0.053131104,-0.0066070557,-0.010025024,-0.08795166,-0.016052246,-0.044891357,0.020385742,-0.062408447,0.046569824,-0.0105896,0.00995636,0.05178833,0.016403198,-0.008705139,-0.009513855,0.059814453,0.055023193,-0.015304565,0.000992775,0.03756714,0.00048708916,0.004802704,-0.011978149,0.026306152,-0.0015707016,-0.010017395,0.026992798,0.016937256,0.03289795,-0.056854248,0.0031871796,0.02218628,-0.0056114197,0.04196167,0.0289917,-0.014274597,-0.01914978,-0.032165527,-