INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('이슬람_라마단_금식월', '이슬람 라마단 금식월', 'RELIGION', '["라마단", "이슬람 금식", "무슬림 금식월", "이프타르"]', NULL, '이슬람력 9번째 달로, 이슬람 신자들이 일출부터 일몰까지 음식·음료·흡연을 금하며 기도와 자선에 집중하는 신성한 금식월. 매년 날짜가 달라지며 약 30일간 지속된다. 전 세계 약 19억 명의 무슬림에게 가장 신성한 기간으로, 이 기간 중 음식·음료·파티·엔터테인먼트 광고를 무슬림 소비자에게 노출할 경우 종교적 감수성을 해치는 것으로 간주된다. 반대로 라마단 기간에 맞춘 진정성 있는 캠페인(이프타르 행사 후원, 자선 연계 마케팅 등)은 무슬림 소비자에게 긍정적으로 받아들여질 수 있다.', '["KR-019"]', '[-0.0072364807,0.05432129,0.002046585,-0.011154175,-0.008918762,0.0059165955,-0.03555298,0.014427185,0.025314331,-0.029037476,0.015670776,-0.03387451,-0.022262573,-0.013839722,0.0423584,0.033477783,-0.013160706,-0.01751709,-0.05355835,0.043060303,-0.0036697388,-0.03387451,-0.032287598,0.04425049,-0.03729248,0.034210205,-0.03164673,-0.010597229,0.014228821,0.017822266,0.028823853,-0.02822876,0.028213501,-0.035736084,-0.023849487,0.03060913,0.036224365,0.00919342,0.0067863464,-0.02381897,-0.01386261,0.0077438354,-0.005718231,-0.02859497,0.014381409,0.07110596,-0.004386902,-0.012359619,0.040130615,-0.012451172,-0.021499634,0.044158936,-0.009788513,-0.023910522,0.03805542,-0.0129776,0.0030555725,0.001042366,0.03945923,-0.027679443,0.005432129,-0.0057411194,-0.007980347,-0.07312012,-0.003774643,-0.06713867,-0.027770996,0.0513916,-0.012756348,0.023010254,0.0010976791,-0.0395813,0.05328369,0.01574707,0.020309448,0.034484863,0.05239868,0.005455017,0.0011844635,-0.021102905,0.011993408,-0.0011377335,-0.003129959,0.039001465,0.020889282,-0.016296387,-0.05517578,0.034942627,-0.03363037,0.091674805,-0.015327454,-0.023483276,-0.008666992,0.0050735474,0.051483154,-0.025375366,-0.008300781,0.041778564,0.0093688965,0.05819702,0.029373169,-0.05633545,0.053497314,-0.033172607,-0.033691406,0.009246826,0.03475952,-0.00466156,-0.0036029816,-0.048339844,-0.0046920776,0.012573242,-0.018554688,0.015487671,0.06488037,0.035339355,0.020599365,0.01600647,0.007045746,-0.027679443,0.00027