INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('기독교_성탄절_크리스마스', '기독교 성탄절 (크리스마스)', 'RELIGION', '["크리스마스 상업화", "성탄 신성 훼손", "종교 이미지 오용"]', '12-25', '예수 그리스도의 탄생을 기념하는 기독교의 최대 절기. 한국에서는 공휴일로 지정되어 있으며 비기독교인에게도 연말 문화 행사로 자리 잡았다. 그러나 예수 탄생의 종교적 의미를 왜곡하거나 과도하게 상업화하는 광고는 기독교 신자들의 반감을 유발한다. 반대로 ''크리스마스'' 표현을 배제하고 ''Happy Holidays''로만 대체하는 글로벌 기업에 대해 기독교 단체의 불매운동 사례도 있다. 신성한 종교 이미지(성경 구절, 아기 예수 등)를 상품 판매에 직접 활용하는 것은 특히 지양해야 한다.', '[]', '[0.022705078,0.032348633,-0.0052604675,0.02230835,-0.03111267,-0.015197754,-0.051818848,0.038391113,0.008796692,-0.051635742,0.026992798,-0.017196655,0.0037078857,-0.028686523,0.020996094,0.00920105,0.0014944077,-0.033691406,-0.03665161,0.009109497,-0.01663208,-0.041656494,-0.01878357,0.039489746,-0.03149414,0.055847168,0.035980225,0.046783447,0.049438477,0.0362854,0.039855957,-0.02482605,0.041290283,-0.04925537,0.022018433,0.039886475,-0.0178833,0.009162903,0.010185242,-0.0063972473,0.045013428,-0.0016460419,-0.027313232,0.038848877,0.0105896,0.07147217,-0.008399963,-0.0025539398,0.06732178,0.020248413,-0.012046814,0.040863037,-0.00029277802,0.017486572,-0.055480957,-0.035827637,-0.034332275,-0.017562866,-0.012825012,-0.0066604614,0.07183838,-0.056915283,0.017608643,-0.028839111,-0.0362854,0.023330688,0.0049057007,0.03878784,-0.10058594,0.057861328,0.041503906,0.014213562,-0.005104065,-0.0020599365,0.012367249,0.0046691895,0.0060768127,-0.016906738,0.03060913,0.010032654,0.0059509277,0.0017471313,0.0009713173,0.026901245,-0.027374268,-0.013046265,0.007194519,-0.00043272972,-0.0059165955,0.045776367,-0.012573242,0.0075263977,0.036743164,0.0054855347,0.027633667,-0.020523071,-0.0069999695,0.019622803,0.06945801,0.00554657,0.045562744,-0.014297485,0.027923584,-0.01008606,0.013114929,-0.025970459,-0.018173218,0.026992798,-0.0007815361,-0.016708374,-0.018600464,-0.0064430237,-0.01524353,0.02558899,0.018051147,-0.027145386,-0.0138168335,0.008651733,-0.0044784