INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('불교_석가탄신일_부처님_오신_날', '불교 석가탄신일 (부처님 오신 날)', 'RELIGION', '["불교 이미지 남용", "연등 상업화", "불상 장식 오용", "종교 소품화"]', NULL, '음력 4월 8일, 불교에서 석가모니 부처의 탄생을 기념하는 날로 대한민국 공휴일로 지정되어 있다. 서울 종로 일대에서 열리는 연등행렬은 유네스코 인류무형문화유산으로 등재된 문화 행사이기도 하다. 연꽃·연등·불상 등 불교적 상징물을 광고에서 단순한 장식 소품으로 활용하거나 제품 판매를 위한 배경으로 사용하는 것은 불교 신자에게 신성모독으로 받아들여질 수 있다. 특히 음식이나 유흥 관련 광고에서 불교 이미지를 혼용하는 것은 강한 반발을 초래한다.', '[]', '[0.03753662,0.042999268,-0.009559631,0.05078125,-0.0072135925,-0.013114929,-0.02267456,0.029693604,-0.016815186,-0.0158844,0.032196045,-0.010696411,-0.019729614,-0.021957397,0.05899048,0.002588272,0.0017900467,0.019989014,-0.04058838,0.040863037,0.014144897,-0.05682373,-0.050476074,0.07043457,-0.008705139,0.033935547,0.010856628,0.0073890686,0.039154053,-0.022094727,-0.000770092,-0.031341553,-0.003276825,-0.06738281,0.016616821,0.022537231,-0.0021953583,-0.0045776367,-0.0025157928,-0.018753052,-0.028167725,-0.042419434,0.016357422,0.009712219,-0.05319214,0.061645508,-0.032165527,0.008636475,0.03010559,-0.007881165,0.0051727295,0.009643555,0.013679504,-0.02508545,-0.0045204163,-0.00793457,-0.04385376,0.027877808,0.004032135,0.00440979,0.033813477,-0.018127441,-0.003271103,-0.054016113,-0.049346924,-0.008415222,0.02456665,0.018371582,-0.05532837,0.033691406,0.04498291,0.011528015,0.03652954,0.016189575,0.020050049,0.06201172,0.04650879,-0.0021438599,0.019119263,-0.03564453,0.030792236,-0.0047950745,-0.026473999,0.061462402,-0.025390625,0.007896423,-0.07940674,0.027252197,0.0015907288,0.06488037,-0.019119263,-0.006008148,0.010253906,0.011604309,0.024215698,-0.025299072,0.01940918,0.004070282,0.03564453,0.047698975,0.018234253,-0.024673462,0.013114929,-0.0124435425,0.017730713,-0.005859375,0.035064697,0.001294136,-0.006576538,0.008430481,-0.00730896,-0.008628845,-0.050872803,0.025146484,0.067993164,-0.0015392303,0.025024414,-0.01134491,0.048919678,-0.023803711,0.00709533