INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('유대교_욤_키푸르_속죄일', '유대교 욤 키푸르 (속죄일)', 'RELIGION', '["욤 키푸르", "유대교 금식일", "속죄일 광고 집행"]', NULL, '유대교에서 1년 중 가장 신성한 날로, ''속죄일''이라 불린다. 25시간 동안 음식·음료·목욕 등을 금하고 기도와 참회에 전념하며, 유대인 대부분이 이날 직장·학교를 쉬고 회당에서 예배를 드린다. 이스라엘에서는 이날 텔레비전과 라디오 방송, 공항, 대중교통이 완전히 중단된다. 유대인 커뮤니티나 이스라엘을 대상으로 한 광고·이벤트를 이날 집행하는 것은 심각한 무례로 간주되며, 글로벌 광고 캠페인 일정 수립 시 반드시 확인해야 할 종교 일정이다.', '[]', '[-0.04586792,0.0418396,-0.02999878,0.00806427,0.013069153,0.021759033,-0.021759033,0.049194336,-0.01586914,-0.019058228,-0.0034770966,-0.025436401,-0.04815674,-0.0029468536,0.08679199,0.022018433,-0.0034828186,0.013252258,-0.0541687,-0.0014820099,-0.039093018,-0.038970947,-0.026428223,0.0925293,-0.026184082,0.0031795502,0.030014038,0.026550293,0.013214111,-0.005443573,0.038482666,-0.022537231,0.06274414,-0.028182983,0.012931824,-0.0034427643,0.013298035,-0.0057754517,-0.011856079,-0.04058838,0.004940033,-0.018051147,-0.008224487,-0.041625977,0.009597778,0.028182983,-0.013061523,0.029907227,-0.006122589,0.012435913,-0.010650635,0.06439209,-0.035461426,0.02758789,-0.022201538,-0.017486572,-0.026611328,0.0075531006,0.027496338,-0.009277344,0.017044067,-0.041107178,0.029067993,-0.023895264,0.0014915466,-0.019836426,0.025238037,0.030014038,-0.026290894,0.0501709,-0.0019798279,-0.0014829636,0.045166016,-0.05517578,0.068115234,0.020706177,0.037506104,0.014022827,0.027999878,-0.0018091202,0.014923096,0.01108551,-0.045440674,0.057617188,-0.030883789,-0.047424316,-0.057250977,0.010314941,-0.0009646416,0.026123047,-0.05218506,0.019104004,0.02130127,-0.010955811,-0.031951904,0.01651001,0.021148682,0.011016846,0.053894043,0.04638672,0.03314209,-0.04345703,0.021331787,0.0121536255,-0.044281006,-0.012664795,0.011650085,-0.008468628,0.028625488,-0.017440796,0.002752304,0.0087890625,-0.060791016,0.034484863,0.05883789,-0.009086609,0.072753906,0.002368927,0.022735596,-0.040771484,-0.029251099,0.03092956