INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('신천지_코로나19_집단감염_사건', '신천지 코로나19 집단감염 사건', 'RELIGION', '["신천지 집단감염", "사이비 종교 방역", "이단 집회", "집단 감염"]', NULL, '2020년 2~3월, 국내 코로나19 초기 확산의 핵심 진원지가 신천지예수교회(신천지) 대구 집회였던 것으로 밝혀졌다. 당시 신천지 관련 확진자가 전체 국내 확진자의 약 60%를 차지했으며, 신천지의 신도 명단 미공개와 비협조적 태도가 방역 당국과의 심각한 갈등을 빚었다. 이 사건으로 신천지에 대한 사회적 비판이 폭발적으로 증가했으며, ''이단'', ''사이비 종교'', ''종교 집회'' 등의 키워드는 팬데믹 관련 트라우마와 결합되어 매우 민감한 표현이 되었다.', '[]', '[-0.008674622,0.0072135925,0.043121338,0.027557373,-0.022994995,0.0008234978,-0.047943115,0.014846802,-0.041015625,-0.007827759,-0.02330017,-0.02104187,-0.000746727,0.05227661,-0.0033607483,-0.033172607,0.0025024414,0.017807007,0.0042533875,0.032287598,0.035858154,-0.0013275146,-0.00011777878,-0.01586914,-0.003583908,-0.006099701,0.031188965,0.048828125,0.020446777,-0.0015192032,0.0025177002,-0.010848999,0.0055770874,-0.0385437,-0.02267456,0.051239014,0.007858276,-0.029144287,-0.014228821,0.0044517517,0.022918701,-0.028076172,-0.02909851,0.032806396,-0.00592041,0.038024902,-0.019195557,-0.0692749,0.051239014,-0.0067749023,-0.00053596497,0.011604309,0.010322571,0.040527344,-0.0054893494,-0.01499939,-0.021072388,0.035308838,-0.006385803,-0.015991211,0.09863281,-0.037719727,-0.008628845,0.008911133,0.015808105,-0.049713135,0.028503418,0.014595032,-0.012062073,0.04034424,0.011062622,0.024917603,0.014053345,0.025772095,0.011917114,0.05883789,-0.023803711,-0.021636963,-0.017822266,0.009254456,0.051361084,0.016403198,0.0030403137,0.022583008,0.0014400482,0.0064697266,-0.03515625,0.028442383,0.0055236816,0.024887085,-0.019195557,0.04852295,-0.0118637085,-5.2392483e-05,0.015701294,-0.05166626,0.044311523,-0.0053253174,-0.0074539185,0.048797607,0.03463745,-0.0362854,0.0015487671,-0.015777588,-0.0016269684,0.0008354187,-0.03527832,-0.0020256042,0.029144287,-0.04937744,0.05166626,0.016708374,-0.047607422,0.036224365,0.030471802,-0.0093307495,0.021072388,-0.045959473,-0.01