INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('인종차별_경찰_폭력_및_흑인_살해', '인종차별 경찰 폭력 및 흑인 살해', 'DISCRIMINATION', '["조지 플로이드 사망", "경찰 과잉진압", "흑인 살해", "BLM", "인종차별 폭력"]', '05-25', '2020년 5월 25일, 미국 미네소타주 미니애폴리스에서 흑인 남성 조지 플로이드가 백인 경찰관 데릭 쇼빈에게 8분 46초간 무릎으로 목이 눌려 사망한 사건. 현장 영상이 전 세계에 퍼지며 ''Black Lives Matter(BLM)'' 운동이 미국 전역과 전 세계로 확산되었고, 수십 개국에서 수백만 명이 인종차별 철폐 시위에 참여했다. 이 사건을 계기로 많은 글로벌 기업들이 BLM 지지 성명을 냈으나, 실질적 다양성 개선 없이 성명만 내는 기업에 대한 ''기업 인종차별 세탁(Woke-washing)'' 비판도 거세게 일었다. 5월 25일 전후 흑인 커뮤니티 관련 마케팅은 진정성과 실질적 기여가 반드시 수반되어야 한다.', '["INTL-001", "INTL-004", "INTL-017"]', '[0.042419434,0.050445557,-0.032714844,0.061431885,0.010375977,-0.030731201,0.032287598,0.035125732,0.022964478,-0.060516357,-0.008598328,0.023971558,-0.09246826,0.024505615,0.05215454,-0.011222839,0.0048332214,0.038146973,-0.037963867,0.007911682,0.012924194,-0.028427124,0.0061950684,0.06640625,-0.01499939,0.006439209,-0.027832031,-0.032287598,-0.03918457,-0.014457703,0.0418396,-0.004940033,-0.009597778,-0.05429077,0.02999878,-0.014778137,-0.014961243,-0.042114258,0.046936035,-0.016189575,0.018966675,-0.043395996,-0.027664185,0.020874023,-0.03668213,-0.008872986,-0.0042037964,0.043395996,0.035614014,0.054260254,-0.03112793,0.02798462,-0.029144287,0.0115737915,-0.0014543533,0.046295166,-0.0040130615,-0.041534424,0.0045394897,-0.004989624,0.035064697,-0.048706055,-0.033996582,-0.021591187,-0.012542725,-0.051513672,-0.018508911,0.03137207,0.0023498535,-0.01550293,-0.0011072159,0.026428223,0.02104187,0.06451416,-0.016143799,0.034118652,0.0025959015,0.01852417,-0.04348755,-0.008583069,0.039764404,0.01309967,-0.0011348724,0.018478394,0.00894165,0.014831543,-0.06359863,-0.06970215,0.023666382,0.0010719299,-0.048034668,0.0140686035,0.02848816,0.03250122,0.017974854,-0.05331421,-0.0005245209,0.0025234222,0.048339844,0.04525757,-0.0592041,0.008728027,0.015670776,0.022766113,0.022521973,-0.010093689,0.010101318,-0.005836487,0.00