INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('아시아인_혐오_범죄', '아시아인 혐오 범죄', 'DISCRIMINATION', '["아시아인 혐오", "반아시아 폭력", "코로나 인종차별", "혐오 범죄"]', NULL, '2020년 코로나19 팬데믹 초기, 바이러스의 중국 발원설이 퍼지면서 미국·유럽 등 서방 국가에서 아시아계 주민을 대상으로 한 혐오 범죄가 급증한 시기(2020년 1월~). 미국에서만 2020~2021년 아시아인 혐오 범죄가 150% 이상 증가한 것으로 집계되었다. 한국 내에서도 중국인·재중교포에 대한 혐오 표현이 확산되었으며, 반대로 해외에서 한국인을 포함한 동아시아계 인물을 향한 차별도 빈번했다.', '[]', '[-0.02444458,0.0054740906,0.03164673,0.09210205,0.027114868,-0.034576416,-0.029815674,0.05230713,-0.019882202,-0.04586792,0.0057029724,0.02406311,-0.03567505,0.03225708,0.010726929,-0.0181427,-0.041992188,-0.010223389,-0.03463745,0.0036716461,-0.02999878,-0.005596161,0.0073165894,0.062469482,0.00023937225,-0.027297974,0.0012483597,0.023269653,-0.00579834,-0.004184723,-0.005306244,-0.010429382,0.015304565,-0.0501709,-0.017150879,-0.0030555725,-0.040618896,-0.046691895,0.040496826,-0.016235352,0.0053253174,-0.0061454773,0.0073890686,0.03527832,-0.041534424,0.00031375885,0.0053596497,-0.039886475,0.02268982,0.03286743,-0.046844482,0.00283432,-0.011482239,-0.0024147034,0.0119018555,0.049713135,0.0060310364,0.04284668,-0.017730713,-0.050994873,0.05456543,-0.040130615,-0.014724731,0.029968262,-0.024215698,-0.03439331,-0.015975952,0.009063721,0.0105896,0.033691406,0.020401001,0.041503906,0.006187439,0.026519775,0.016418457,-0.0032863617,-0.074035645,0.017318726,0.012886047,-0.020690918,0.009437561,0.06774902,0.013557434,0.010612488,0.0055656433,-0.0129776,-0.04647827,-0.003824234,-0.0071907043,-0.012382507,-0.026062012,0.022109985,-0.00856781,-0.0690918,-0.011558533,-0.010650635,0.036743164,-0.004940033,0.043182373,0.029632568,-0.015991211,-0.03010559,0.011695862,0.03781128,0.0068244934,-0.004638672,-0.029403687,-0.009185791,-0.009773254,0.028335571,0.04559326,0.027923584,-0.08996582,-0.025405884,-0.046661377,-0.011199951,-0.007686615,-0.04525757,0.02041626,0.008239746,-0.01939392,-0.043670654,0.017456055,0.0