INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('아동_학대_및_방임', '아동 학대 및 방임', 'CHILD_PROTECTION', '["아동학대", "아동 방임", "학대 피해 아동", "아동 착취"]', '05-05', '1923년 방정환 선생이 제정한 어린이날로, 현재는 대한민국 공휴일이다. 어린이의 권리와 행복을 기념하는 날이지만, 동시에 국내 아동 학대 통계와 사건들이 재조명되는 시기이기도 하다. 미성년자를 성인처럼 묘사하거나 아동 관련 서비스에서 안전·보호보다 오락·소비를 우선시하는 광고는 아동 인권 단체의 항의와 불매운동을 유발할 수 있다.', '["INTL-005", "INTL-016", "INTL-021", "KR-034"]', '[0.022705078,0.015701294,-0.004432678,0.056243896,0.015838623,-0.01020813,-0.0008845329,0.035827637,-0.025726318,-0.03665161,0.03387451,-0.0022335052,0.009796143,0.05581665,0.03024292,-0.03552246,-0.0031757355,0.03289795,0.018478394,0.06530762,0.04058838,-0.032592773,0.021133423,0.045074463,-0.009712219,-0.019363403,0.042388916,-0.02545166,0.029159546,0.016906738,0.057678223,-0.0066184998,-0.011619568,-0.068237305,0.042541504,0.0026054382,-0.01574707,-0.010566711,-0.05142212,-0.0028743744,0.0042648315,-0.06854248,-0.0063705444,0.023101807,-0.07940674,0.02458191,-0.017028809,0.03488159,0.031555176,0.055419922,-0.00907135,0.0074882507,0.035736084,0.026428223,-0.015808105,0.047607422,-0.021469116,-0.026489258,-0.013412476,0.00063943863,0.029464722,0.014167786,-0.06149292,0.01675415,-0.03338623,-0.03945923,-0.03829956,0.031280518,-0.03567505,0.023040771,0.08538818,-0.010192871,0.06414795,-0.039642334,-0.03930664,0.04272461,0.0047416687,0.013282776,-0.04534912,0.022537231,0.0034370422,0.02243042,-0.014251709,0.050231934,-0.015548706,0.0031013489,-0.105163574,-0.024490356,0.020706177,-0.024749756,-0.016296387,0.00762558,-0.066711426,0.012580872,0.050354004,-0.0026607513,-0.0055885315,-0.0076522827,0.09820557,0.029876709,-0.011955261,-0.05392456,-0.002527237,-0.0005350113,-0.046905518,-0.04550171,0.009986877,-0.0003631115,-0.04345703,-0.028625488,-0.028671265,0.0050811768,-0.016326904,0.020858765,0.039245605,-0.015342712,0.011810303,-0.001909256,-0.0154800415,-0.011833191,-0.031402588,-0.0017499924,0.067