INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('입양아_아동학대_사망', '입양아 아동학대 사망', 'CHILD_PROTECTION', '["정인이 사망", "입양아 학대", "아동 살해", "양부모 학대"]', '01-02', '2020년 10월 13일 사망(언론 보도는 2021년 1월 2일 집중)한 입양아 정인이(당시 생후 16개월) 사건. 양부모의 지속적인 학대로 사망한 정인이 사건은 2021년 1월 SBS ''그것이 알고싶다'' 방영 이후 전국적으로 공분을 불러일으켰으며, ''#정인아 미안해'' 해시태그 운동이 폭발적으로 확산되었다. 이 사건은 아동 학대 신고·처벌 강화 입법 논의의 기폭제가 되었다.', '[]', '[0.039611816,0.027694702,-0.0075798035,0.04675293,0.025497437,-0.013793945,0.0027809143,0.011566162,-0.0049743652,-0.0073242188,0.039611816,-0.01537323,-0.022979736,0.052612305,0.016235352,0.0099487305,-0.011764526,0.01651001,-0.04296875,0.03491211,0.03765869,-0.05368042,0.02798462,0.017074585,0.034484863,-0.07867432,0.05404663,-0.014183044,0.038024902,0.004295349,0.074523926,-0.01576233,-0.014968872,-0.06561279,0.017822266,0.021560669,-0.027023315,-0.020980835,-0.019180298,-0.043182373,-0.0023002625,-0.03274536,-0.0129852295,0.022216797,-0.018081665,-0.002002716,0.038208008,0.043060303,0.05758667,0.022201538,0.0019340515,0.049468994,0.048217773,0.055114746,0.017288208,0.022827148,-0.004108429,0.0066223145,0.002588272,-0.0068511963,0.045318604,-0.017974854,-0.021560669,0.011459351,-0.014259338,-0.11462402,-0.035217285,0.029327393,-0.030090332,-0.02166748,0.062683105,0.012710571,-0.006706238,0.028686523,-0.033111572,0.033447266,-0.014816284,-0.0028362274,-0.066467285,-0.0027809143,0.029037476,0.058135986,-0.00041675568,0.038970947,-0.008407593,0.00084114075,-0.0826416,-0.024047852,0.022155762,0.006416321,-0.048339844,0.04159546,-0.029434204,0.0049552917,0.040039062,-0.04446411,0.016967773,0.021942139,0.013320923,0.021057129,-0.017745972,-0.028869629,0.033813477,0.011161804,-0.022155762,-0.036315918,-0.032958984,0.012435913,-0.030715942,-0.032104492,-0.012779236,-0.006034851,-0.053497314,0.019561768,-0.04095459,0.0011482239,-0.009475708,-0.041259766,-0.022888184,0.03274536,-0.0015707016,0.046905518,-0.0066947937