INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('세계_환경의_날_World_Environment_Day', '세계 환경의 날 (World Environment Day)', 'ENVIRONMENT', '["환경 파괴 기업", "플라스틱 오염", "탄소 배출 과장", "환경 허위 선언"]', '06-05', '1974년부터 매년 6월 5일, 유엔환경계획(UNEP)이 지정한 세계 환경의 날. 매년 특정 주제(해양 오염, 생태계 복원, 사막화 등)를 선정하여 전 세계적인 환경 인식 캠페인을 펼친다. 환경 파괴적 산업(석유·석탄·화학·패스트패션 등)에 종사하는 기업이 이날 환경 보호를 내세우는 광고를 집행할 경우 ''그린워싱''으로 분류되어 기업 이미지에 심각한 타격을 줄 수 있다. 특히 플라스틱 과다 사용 기업이나 탄소 배출 상위 기업의 친환경 선언은 언론과 환경 단체의 즉각적인 팩트체크 대상이 된다.', '["KR-031"]', '[0.009552002,0.025054932,0.03942871,0.057861328,0.054504395,-0.00762558,-0.005302429,0.012374878,-0.016494751,-0.0055732727,0.022705078,-0.014122009,-0.03704834,-0.045318604,0.023971558,0.057861328,-0.045928955,0.011383057,-0.02961731,-0.012420654,-0.019210815,-0.0178833,-0.02784729,0.07116699,-0.011169434,0.028442383,0.01512146,0.074523926,0.04916382,-0.0029067993,0.02696228,-0.022644043,0.009773254,0.006046295,0.051849365,-0.02961731,-0.0024871826,-0.01789856,-0.030212402,0.036956787,-0.0011205673,-0.014373779,0.02798462,0.008155823,0.0107803345,-0.019927979,-0.041931152,-0.00907135,0.103027344,0.020599365,0.02067566,-0.002998352,0.04055786,-0.031341553,0.013847351,-0.024093628,-0.020217896,0.04574585,-0.015899658,0.010772705,0.030685425,0.014541626,-0.033569336,0.013175964,-0.005264282,-0.0074005127,0.03479004,0.017669678,-0.015174866,0.037078857,0.06347656,0.025360107,0.02859497,-0.022125244,0.022476196,-0.013710022,0.02217102,-0.006816864,0.008003235,0.011253357,0.0060768127,0.002286911,-0.055145264,0.056884766,-0.019210815,-0.050231934,-0.023605347,-0.016571045,-0.022338867,0.03253174,-0.023635864,0.0043029785,-0.005142212,0.018722534,-0.0022888184,0.022644043,-0.041412354,0.014320374,0.042022705,0.036621094,0.018188477,-0.06317139,-0.016281128,0.025634766,-0.059692383,-0.004295349,0.013938904,0.0423584,0.020462036,-0.03488159,-0.056762695,0.0044517517,-0.02003479,0.081848145,0.017471313,0.0