INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('기후재난_피해', '기후재난 피해', 'ENVIRONMENT', '["태풍 피해", "홍수 이재민", "기후재난", "자연재해 사상자"]', NULL, '태풍·홍수·폭염·산불 등 기후 관련 자연재해가 발생하거나 직후인 시기. 한국의 경우 매년 7~9월 태풍 시즌과 집중호우 시기가 특히 민감하며, 2022년 서울 강남 침수, 2023년 충청·전북 폭우 등 특정 재난 직후 피해 지역 주민들이 느끼는 상실감이 매우 크다. 재난 발생 시 광고 집행을 일시 중단하는 것이 글로벌 표준이 되어가고 있다.', '[]', '[0.022033691,0.0513916,0.06036377,0.046295166,-0.014312744,-0.028869629,-0.002796173,-0.026306152,-0.043884277,7.748604e-07,0.02722168,0.03540039,-0.06762695,-0.014312744,0.009292603,-0.013198853,-0.0058403015,-0.009002686,-0.044830322,0.027648926,-0.017852783,-0.016036987,-0.035095215,-0.027893066,0.0129776,-0.004688263,0.0052757263,0.072021484,0.088012695,0.023269653,0.026672363,-0.017807007,-0.041534424,-0.024765015,0.01953125,-0.01789856,0.003660202,-0.0027561188,-0.0052261353,0.023513794,0.00068187714,-0.0069732666,-0.045898438,0.0069885254,-0.01725769,0.044525146,0.026290894,0.04434204,0.05871582,0.032287598,0.048461914,0.036224365,0.009750366,0.033599854,0.019119263,-0.010528564,-0.016448975,0.050750732,-0.005958557,-0.080200195,0.064941406,0.004878998,-0.061553955,0.022888184,0.0057754517,-0.044189453,0.018341064,-0.00090408325,0.004753113,0.0033073425,0.003124237,-0.0032081604,0.08557129,-0.031036377,0.01852417,0.02520752,-0.020217896,-0.019882202,0.018218994,-0.02961731,0.054534912,0.06793213,-0.046325684,0.03111267,-0.008087158,-0.02255249,-0.074523926,0.04144287,-0.008277893,0.020385742,-0.04324341,0.049713135,0.012496948,0.008666992,-0.027999878,-0.041229248,0.023010254,-0.021774292,0.014259338,0.039398193,-0.013542175,-0.034423828,0.041290283,-0.003791809,-0.023406982,-0.01852417,-0.04824829,0.024810791,0.004337311,-0.029403687,0.02809143,0.036865234,-0.03869629,0.030014038,-0.052581787,0.018585205,0.013153076,-0.022232056,-0.009841919,-0.042663574,-0.0138549805,0.051696777,0.03387451,0.009391785,-0.009757996,0.041381836,0.011039734,-