INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('열악한_노동환경_항거_분신', '열악한 노동환경 항거 분신', 'LABOR_HUMAN_RIGHTS', '["전태일 분신", "노동자 죽음", "근로기준법 위반", "노동 착취 항거"]', '11-13', '1970년 11월 13일, 평화시장 재단사였던 전태일 열사가 ''근로기준법을 준수하라'', ''우리는 기계가 아니다''를 외치며 분신 사망한 날. 당시 하루 14~16시간 노동, 폐 질환을 유발하는 열악한 환경에서 일하던 봉제 노동자들의 현실을 사회에 알린 사건으로, 한국 노동운동의 상징적 전환점이 되었다. 이후 노동조합 결성과 노동법 개선 운동이 본격화되었다.', '[]', '[-0.014533997,0.025161743,-0.017852783,0.030334473,-0.000102221966,-0.01033783,-0.021377563,0.04058838,-0.015289307,-0.026657104,0.027450562,0.015434265,-0.00041604042,0.031341553,0.0032634735,-0.004962921,-0.029266357,-0.023727417,-0.020980835,0.0074691772,0.016647339,-0.014656067,-0.02810669,0.06768799,-0.024276733,-0.04196167,0.026245117,0.017120361,-0.039489746,-0.008605957,0.0044021606,-0.014419556,0.0078125,-0.021606445,0.008010864,-0.0020980835,0.05734253,0.004562378,-0.012397766,0.0023345947,0.010917664,-0.08251953,-0.007171631,0.080200195,-0.040100098,0.018051147,-0.055725098,0.008331299,0.007019043,-0.0043411255,0.029724121,-0.0049095154,-0.021728516,0.027755737,0.021728516,0.00818634,-0.00730896,0.033172607,-0.03414917,0.029449463,0.013946533,-0.0015106201,-0.00623703,0.023406982,0.0004582405,-0.040283203,0.0027198792,0.034698486,0.018585205,-0.0011806488,0.0019836426,0.020187378,0.0036792755,0.013809204,-0.03326416,0.015380859,-0.0473938,0.06060791,0.01828003,-0.0006957054,0.01979065,-0.01687622,0.0075569153,0.08477783,-0.018585205,-0.01751709,-0.04397583,-0.021133423,0.026473999,-0.017456055,-0.037078857,0.002784729,0.007820129,0.028274536,0.032043457,-0.029754639,-0.019561768,0.0009217262,-0.00028920174,0.026489258,-0.03768921,-0.058746338,0.02822876,0.015945435,0.01966858,0.020874023,-0.027267456,-0.0048828125,-0.007247925,0.010574341,0.0413208,-0.03829956,-0.021621704,0.0063972473,0.018676758,-0.0016784668,0.025161743,-0.044525146,0.045043945,-0.025772095,0.037902832,0.008628845,0.014907837,0