INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('세계_인권의_날_UN_세계인권선언_기념일', '세계 인권의 날 (UN 세계인권선언 기념일)', 'LABOR_HUMAN_RIGHTS', '["인권 세탁", "공급망 인권 침해", "인권 위선 광고", "강제 노동 기업"]', '12-10', '1948년 12월 10일 유엔총회에서 세계인권선언이 채택된 것을 기념하는 날. 유엔이 지정한 세계 인권의 날로, 매년 이 날을 전후해 각국의 인권 침해 현황이 국제적으로 조명된다. 글로벌 기업의 광고에서 인권·다양성·포용성을 내세울 때, 공급망 전반에서의 실제 인권 준수 여부가 검증의 기준이 되고 있다.', '[]', '[0.010467529,0.07092285,0.021377563,0.05886841,0.020507812,-0.041381836,0.015457153,0.012756348,-0.0014848709,-0.061035156,0.0519104,0.023925781,-0.04751587,-0.045135498,0.048065186,0.013465881,-0.06451416,0.0068206787,-0.011001587,-0.005420685,0.0028591156,0.0045204163,-0.008125305,0.10601807,-0.020477295,0.007926941,-0.006652832,0.04925537,0.015388489,0.036102295,0.030258179,-0.01234436,-0.0028839111,-0.034240723,0.054718018,-0.0013570786,0.026885986,0.015197754,-0.018432617,-0.019119263,-0.020553589,-0.045898438,0.024261475,0.0061149597,-0.02268982,0.0042915344,-0.046722412,0.018676758,0.05682373,0.042510986,-0.012367249,0.019515991,0.05178833,-0.03881836,-0.02017212,-0.015098572,-0.017059326,0.051971436,-0.04788208,-0.048950195,0.06451416,0.020614624,-0.0026874542,-0.016067505,-0.025482178,-0.007007599,0.011894226,0.014282227,-0.0015745163,0.033599854,0.05316162,0.025405884,0.031280518,0.018478394,0.012214661,0.041046143,-0.008132935,0.04272461,-0.014961243,0.031158447,0.017227173,-0.015853882,-0.087402344,0.029678345,-0.010940552,-0.028640747,-0.025604248,-0.030044556,0.009780884,0.024429321,-0.041381836,0.012619019,-0.0019140244,0.018127441,0.0008368492,-0.020721436,-0.004714966,0.024765015,0.04949951,0.023513794,-0.021377563,-0.03048706,0.007331848,0.0007376671,-0.037353516,0.0029964447,-0.037231445,0.0067710876,-0.02671814,-0.03439331,-0.03262329,0.02166748,-0.042785645,0.05026245,0.06097412,-0.03451538,-0.0736084,-0.008972168,0.045959473,-0.0035686493,-0.01687622,-0.019561768,0.0057868958,0.030822754,-0.04898071