INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('대량_해고_및_노동자_연쇄_자살', '대량 해고 및 노동자 연쇄 자살', 'LABOR_HUMAN_RIGHTS', '["쌍용차 해고", "정리해고 트라우마", "해고 노동자 자살", "구조조정 비극"]', NULL, '2009년 쌍용자동차가 기업 회생 절차 중 2,646명을 정리해고하면서 발생한 장기 노사 분규. 해고 노동자들이 평택 공장을 점거하며 77일간 파업을 벌였고, 진압 과정에서 물대포·최루액 등이 사용되어 국제적 비판을 받았다. 이후 해고 노동자와 가족 30명 이상이 극단적 선택이나 과로사 등으로 사망하면서 ''쌍용차 사태''는 한국 사회에서 구조조정과 해고의 인간적 비용을 상징하는 비극이 되었다.', '[]', '[-0.0046157837,0.045776367,0.04324341,0.0138549805,0.0027618408,-0.03955078,-0.045043945,0.04949951,0.01953125,-0.041503906,0.054473877,-0.024154663,-0.028930664,0.013397217,0.029251099,-0.013328552,-0.029464722,-0.008972168,-0.014465332,-0.0056037903,0.04547119,0.04046631,-0.0012979507,0.038757324,0.011878967,0.025390625,-0.0034370422,-0.0006904602,-0.037719727,-0.03768921,-0.000808239,-0.009750366,-0.004272461,-0.037506104,0.04208374,-0.001540184,0.004787445,-0.010345459,-0.010429382,-0.00070667267,0.035308838,-0.068603516,0.011955261,0.037506104,-0.011451721,-0.019256592,0.016311646,0.039855957,0.052490234,0.021148682,-0.013122559,0.029891968,0.011451721,0.015563965,0.02178955,0.023117065,0.009681702,-0.021530151,-0.0053520203,-0.027374268,0.0736084,-0.04559326,0.010627747,0.032073975,-0.000872612,-0.024475098,0.013687134,0.026550293,-0.025482178,0.0048065186,0.02130127,-0.023803711,-0.004257202,0.023956299,0.018753052,-0.013511658,0.027435303,0.030090332,0.0052375793,0.019363403,0.013809204,-0.017807007,0.011810303,0.0050621033,-0.010231018,-0.04119873,-0.101257324,-0.033081055,-0.017654419,-0.020507812,-0.07159424,0.027862549,0.029647827,0.0044555664,0.031143188,-0.07019043,-0.022094727,0.009384155,0.06506348,0.03668213,-0.005947113,0.0053901672,0.040008545,0.020568848,0.01701355,-0.03302002,-0.023254395,-0.008613586,0.003200531,-0.024536133,0.05206299,0.015617371,-0.07299805,0.0390625,0.025161743,0.018051147,0.004146576,0.010482788,0.022460938,0.016494751,-5.5730343e-05,-0.0111