INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('한국_진보_보수_이념_갈등_및_민주화_상징_논쟁', '한국 진보·보수 이념 갈등 및 민주화 상징 논쟁', 'ETC', '["진보·보수 갈등", "이념 대립 자극", "정치 편향 광고", "운동권 표현"]', NULL, '1980년대 민주화 운동의 상징 노래인 ''임을 위한 행진곡''을 비롯해 민주화 운동과 관련된 구호·이미지·언어는 한국 사회에서 정치적으로 극도로 민감한 상징이다. 진보 진영에서는 민주주의 투쟁의 상징으로, 보수 진영 일부에서는 좌파 이념의 상징으로 인식하는 등 해석이 크게 엇갈린다. 5.18 기념식에서의 제창 여부가 매년 정치적 이슈가 될 만큼 첨예한 갈등 소재이며, 이러한 상징을 광고에 무분별하게 사용할 경우 특정 정치 성향을 지지하는 것으로 오해받아 반대 진영 소비자 이탈을 초래할 수 있다.', '[]', '[0.015167236,0.036376953,-0.03137207,0.04525757,0.024215698,-0.014045715,-0.045806885,-0.01159668,-0.007331848,-0.00024342537,0.06817627,-0.009811401,-0.044067383,0.030151367,0.053466797,-0.019454956,-0.010231018,-0.029800415,-0.02911377,0.02961731,0.01789856,-0.031433105,-0.030944824,0.029205322,0.001616478,0.0069236755,0.0038719177,0.033416748,0.019958496,-0.0043411255,0.04876709,-0.02394104,-0.025436401,-0.11114502,-0.061309814,-0.019744873,0.021469116,0.0009355545,0.0154953,-0.03881836,-0.011062622,-0.018493652,-0.021759033,0.019165039,0.0075035095,0.03778076,-0.0020389557,-0.002872467,0.040740967,0.019821167,0.0002603531,0.04107666,0.02998352,-0.021728516,0.0065460205,0.055358887,-0.020050049,0.008422852,-0.010566711,-0.041534424,0.050994873,-0.0137786865,-0.050689697,-0.0060272217,-0.03186035,-0.020080566,0.0075416565,0.009902954,0.019592285,-0.0077781677,0.035736084,-0.023025513,0.05255127,-0.013572693,-0.041656494,0.02243042,0.011123657,0.030029297,-0.0045547485,-0.023239136,0.01386261,0.03253174,-0.038909912,0.06689453,0.0006508827,-0.0029640198,-0.076171875,0.020645142,0.022338867,0.035064697,-0.06628418,0.03375244,0.011238098,0.037322998,0.005268097,-0.0052986145,0.01902771,-0.008934021,0.06048584,0.040740967,-0.028701782,0.030334473,0.07574463,-0.016479492,0.05105591,-0.06866455,-0.025268555,-0.030151367,-0.031585693,-0.018051147,0.0029907227,0.037078857,-0.038146973,0.020935059,0.08581543,-0.017211914,0.02265930