INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('일본군_위안부_성노예_강제_동원', '일본군 위안부 성노예 강제 동원', 'HISTORY', '["위안부", "성노예", "일본군 위안부", "강제 동원 성착취", "정신대"]', '08-14', '1991년 8월 14일, 故 김학순 할머니가 일본군 위안부 피해 사실을 최초로 공개 증언한 날로, 이후 ''세계 위안부 기림일''로 지정되었다. 일제강점기 일본군은 조선·중국·동남아시아 등지에서 여성들을 전쟁터 성노예로 강제 동원했으며, 피해 여성은 최소 20만 명으로 추산된다. 일본 정부의 공식 사과와 법적 배상을 요구하는 운동이 수십 년째 지속되고 있으며, 매주 수요일 서울 일본대사관 앞에서 수요시위가 열리고 있다.', '["KR-004"]', '[-0.007221222,0.008796692,0.0715332,0.04650879,0.0030117035,-0.0047073364,-0.015525818,0.04373169,-0.021118164,-0.02468872,0.052642822,0.03543091,-0.004711151,0.010688782,0.014129639,0.021987915,0.012336731,0.021911621,-0.0231781,-0.0042152405,-0.023040771,-0.012535095,-0.027175903,0.00046348572,0.025421143,-0.01361084,0.050323486,0.031204224,0.019943237,-0.0390625,0.014595032,-0.026046753,-0.040374756,0.0064811707,0.017868042,0.00084400177,0.07043457,0.008407593,0.0004246235,-0.02218628,0.016967773,-0.0463562,0.017028809,0.019470215,-0.013458252,-0.0046653748,-0.0017662048,0.022354126,0.043792725,-0.021835327,-0.01335907,0.038085938,0.013031006,0.016021729,0.029190063,0.018371582,0.019714355,0.036590576,0.010429382,-0.0013074875,0.035247803,0.0028972626,-0.09387207,0.048980713,-0.0003902912,-0.06149292,0.013183594,0.009262085,0.007183075,0.02609253,0.019897461,-0.009819031,0.055755615,-0.017074585,-0.0068588257,0.03062439,0.02784729,0.021057129,-0.024429321,-0.0045166016,0.043823242,0.052490234,-0.06732178,0.06591797,0.0074806213,0.048583984,-0.060760498,0.028564453,0.002779007,0.02015686,-0.09472656,0.016784668,-0.07244873,0.011405945,0.010169983,0.019088745,-0.010231018,0.0070724487,0.03488159,-0.0049743652,-0.03274536,-0.016098022,0.006313324,0.0035095215,0.03591919,0.03878784,-0.025741577,-0.003572464,-0.0042533875,0.02041626,0.043823242,-0.0038261414,-0.025375366,0.02507019,0.07659912,-0.025817871,0.027252197,-0.02822876,0.02885437,0.006340027,-0.028305054,0.0301971