INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('일제_강제징용_노동_착취_및_배상_거부', '일제 강제징용 노동 착취 및 배상 거부', 'HISTORY', '["강제징용", "징용 피해자", "일본 기업 배상 거부", "강제노동"]', NULL, '일제강점기 동안 약 78만 명의 조선인이 일본·사할린·남태평양 등지의 탄광·군수공장·토목공사 현장에 강제 동원되어 혹독한 노동 착취를 당한 사건. 2018년 대법원이 일본 기업(신일철주금·미쓰비시중공업)의 강제징용 피해자 배상 판결을 내렸으나 일본 정부가 이를 거부하며 한일 외교 갈등이 극도로 고조되었다. 일본의 수출 규제와 한국의 불매운동으로 이어지며 경제적 파장도 컸다.', '[]', '[-0.005466461,0.034973145,0.033813477,0.040771484,0.031143188,-0.028762817,-0.07318115,0.036468506,0.0016183853,-0.06210327,0.066101074,-0.004901886,-0.029006958,0.0107421875,0.032684326,0.0103302,-0.005168915,-0.026397705,-0.043121338,-0.024124146,0.023956299,0.04260254,-0.01637268,-0.0020389557,0.027999878,0.01725769,-0.015144348,0.019195557,0.009277344,-0.027999878,-0.0007662773,-0.027297974,-0.014205933,-0.04638672,0.032348633,-0.029312134,0.025024414,0.040771484,-0.01890564,-0.040130615,0.0066375732,-0.07312012,-0.014556885,-0.0008368492,-0.06036377,0.0011224747,0.018218994,0.018127441,0.041809082,-0.015541077,-0.0042419434,0.042663574,0.010871887,-0.0107803345,0.046722412,0.0061683655,0.02835083,0.016708374,-0.007633209,-0.03262329,0.047027588,-0.030960083,-0.040222168,-0.0126571655,-0.03414917,-0.02619934,0.020767212,0.029418945,-0.013328552,-0.0074424744,0.040161133,0.0009822845,0.015556335,0.009376526,-0.0052871704,-0.019226074,0.0758667,0.030181885,0.011703491,0.028823853,0.04147339,0.05432129,-0.045959473,0.07775879,-0.0033416748,-0.004901886,-0.057525635,0.0069999695,-0.05078125,0.007797241,-0.052978516,0.04385376,-0.025375366,0.08996582,0.03237915,-0.05319214,-0.0031394958,-0.012123108,0.046173096,0.022445679,-0.011077881,-0.0060806274,0.026275635,0.057647705,0.052490234,0.019012451,-0.032073975,-0.03955078,0.0010976791,0.012130737,0.11816406,0.033843994,-0.070739746,0.039733887,0.0121536255,-0.008850098,-0.003742218,0.003730774,0.016021729,-0.030944824,0.009162903,0.005428314,0.007041931,-0