INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('고문_조작_의혹_국가_권력_남용', '고문 조작 의혹 국가 권력 남용', 'HISTORY', '["박종철 고문치사", "남영동 대공분실", "물고문", "국가 고문"]', '01-14', '1987년 1월 14일, 서울대 학생 박종철이 치안본부 남영동 대공분실에서 경찰의 물고문을 받다 사망한 사건. 당국은 처음에 ''책상을 탁 치니 억 하고 쓰러졌다''며 사인을 은폐했으나, 이후 고문치사 사실이 폭로되면서 사회 전반의 공분을 불러일으켰다. 이 사건은 1987년 6월 민주항쟁의 중요한 기폭제가 되었으며, 국가 권력에 의한 인권 침해의 대표 사례로 기록되고 있다.', '["KR-002", "KR-010"]', '[0.007881165,0.08935547,-0.023635864,0.02293396,-0.022628784,0.00573349,-0.011116028,0.01171875,-0.00680542,-0.018508911,0.043792725,0.020401001,-0.032684326,0.016616821,0.017974854,-0.013633728,-0.04623413,0.005405426,-0.047088623,0.028945923,0.05596924,-0.0018081665,-0.030883789,0.048828125,-0.02583313,0.02734375,0.010246277,-0.021957397,-0.06402588,-0.021270752,0.032104492,0.0041656494,0.010871887,-0.07745361,-0.015274048,-0.004962921,0.00869751,0.025939941,-0.007835388,-0.022918701,-0.00087594986,-0.03744507,-0.0002169609,0.044128418,-0.036743164,-0.02798462,-0.0043754578,0.037078857,0.03778076,0.030075073,-0.0110321045,0.08001709,0.02279663,-0.03036499,0.053649902,0.036193848,-0.04763794,-0.025390625,-0.004776001,-0.0075569153,0.036865234,-0.03149414,-0.034179688,0.03289795,-0.0031814575,-0.070129395,0.0043525696,0.008285522,-0.008163452,0.05923462,0.040771484,0.024215698,0.03189087,-0.013305664,0.007820129,-0.0030574799,0.017837524,0.031585693,-0.04498291,-0.0049438477,-0.022567749,0.029388428,-0.038726807,0.020812988,-0.008796692,-0.024215698,-0.07019043,-0.008934021,-0.034484863,0.0075798035,-0.070251465,0.025909424,0.021118164,0.02407837,0.04949951,0.024490356,-0.01033783,0.0385437,0.03579712,0.050750732,-0.057037354,0.0055160522,-0.018295288,0.00025177002,0.032989502,0.011772156,-0.013717651,-0.0096206665,-0.03540039,-0.027374268,0.036743164,0.022720337,-0.10809326,0.004650116,0.028564453,0.035064697,0.042663574,-0.033813477,-0.030471802,-0.001821518,-0.018173218,-0.0029468536,0.019