INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('사법부에_의한_민주인사_사형_집행_사법_살인', '사법부에 의한 민주인사 사형 집행 (사법 살인)', 'HISTORY', '["인혁당", "사법 살인", "긴급조치", "재판 조작"]', '04-09', '1975년 4월 9일, 인민혁명당 재건위원회 사건 관련자 8명이 대법원 판결 18시간 만에 전격 사형 집행된 날. 국제앰네스티는 이를 ''사법 살인(Judicial Murder)''으로 규정했으며, 2007년 재심에서 8명 전원이 무죄 판결을 받아 국가에 의한 조작 재판이었음이 확인되었다.', '[]', '[0.018478394,0.070129395,0.027297974,0.0413208,0.016281128,-0.0027008057,-0.0152282715,0.026672363,0.026626587,-0.014884949,0.060821533,0.03366089,-0.028915405,0.022613525,0.005859375,-0.018173218,-0.010955811,0.023925781,-0.011329651,0.011672974,0.017166138,-0.025421143,0.021697998,0.041259766,0.03164673,0.024505615,-0.012237549,-0.0071983337,0.036193848,-0.015220642,0.02456665,0.0057754517,0.042541504,-0.09631348,0.02394104,0.009361267,-0.011138916,-0.017684937,0.0019226074,0.0011148453,0.010650635,-0.059417725,-0.017684937,0.050933838,-0.038482666,0.002325058,0.029891968,0.039794922,0.039733887,0.0635376,0.024505615,0.033355713,0.032836914,0.014251709,0.015975952,0.06781006,0.012390137,0.022888184,-0.008628845,-0.024368286,0.08081055,0.0010309219,-0.027191162,0.02218628,-0.06591797,-0.05166626,-0.016586304,0.030593872,0.014801025,0.023147583,0.0060768127,0.025146484,0.033966064,-0.016830444,-0.042297363,0.033294678,-0.0012588501,0.03439331,-0.07080078,0.032318115,-0.009597778,-0.01737976,-0.03463745,0.064086914,-0.026885986,-0.017089844,-0.09240723,-0.038879395,0.0003271103,-5.763769e-05,-0.02722168,0.030899048,-0.0038089752,-0.0015926361,0.05065918,-0.06561279,-0.006454468,-0.016021729,0.049224854,0.06903076,-0.012672424,-0.0035686493,0.05215454,0.019866943,0.012039185,-0.012001038,-0.0015230179,0.0423584,-0.046081543,-0.024139404,0.036834717,-0.01637268,-0.04373169,0.026000977,0.01626587,0.0023155212,0.018173218,-0.052642822,-0.042175293,0.04776001,-0.009590149,0.016098022,0.0077171326,-0.01802063,-0.036590576,0.018188477,-0.0129776,-0.0028305