INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('부마항쟁_진압_및_유신_체제_폭력', '부마항쟁 진압 및 유신 체제 폭력', 'HISTORY', '["부마민주항쟁", "유신 철폐", "부산 마산 시위", "계엄 진압"]', '10-16', '1979년 10월 16일 부산, 18일 마산에서 박정희 유신 독재에 반대하는 학생·시민들이 대규모 시위를 벌인 민주화 운동. 정부는 부산에 비상계엄, 마산·창원에 위수령을 선포하고 군대를 투입해 강제 진압했다. 이 항쟁은 10.26 박정희 대통령 암살로 이어지는 역사적 배경이 되었으며, 2019년 국가 기념일로 지정되었다. 부산·경남 지역 기반 광고에서 이 사건에 대한 역사 인식 부재는 해당 지역 소비자와의 감정적 단절을 초래할 수 있다.', '[]', '[-0.026565552,0.013687134,0.026535034,0.03543091,-0.005886078,-0.02407837,0.00573349,0.002292633,-0.020858765,0.0046463013,0.0038051605,-0.014968872,-0.059570312,0.01914978,0.011405945,0.047027588,-0.04638672,0.024719238,-0.017791748,-0.008705139,0.05227661,-0.016113281,0.022521973,0.034210205,0.026992798,0.030136108,0.010932922,-0.035705566,0.008018494,0.01423645,0.010360718,0.0041618347,-0.0013771057,-0.054656982,0.0011692047,0.019714355,0.038391113,0.015029907,0.027313232,-0.0027179718,0.0030002594,-0.009468079,-0.045135498,0.033477783,0.0067749023,0.03881836,-0.042633057,0.019943237,0.031829834,0.055725098,0.0024662018,0.008201599,-0.0028324127,-0.041229248,0.0052833557,0.029800415,0.01259613,-0.014259338,0.01171875,-0.021240234,0.03845215,-0.049316406,-0.047088623,0.04196167,0.01373291,-0.043151855,0.05316162,0.0017023087,-0.005218506,0.054779053,0.023605347,-0.03567505,0.056152344,0.002708435,0.010017395,0.007129669,0.026779175,0.037628174,-0.054595947,-0.007106781,0.007507324,-0.012435913,0.0010509491,0.033447266,-0.055267334,-0.027175903,-0.09680176,0.020446777,0.0121154785,0.017990112,-0.020858765,0.041137695,0.01651001,0.05908203,0.076049805,-0.035827637,0.023788452,-0.026763916,0.033416748,0.034942627,0.0024814606,-0.0056495667,0.012039185,0.0077934265,0.0005893707,-0.023498535,0.014526367,0.014656067,0.009033203,0.024993896,0.016677856,0.037231445,-0.025039673,0.05996704,0.020721436,-0.002981186,-0.003540039,-0.07043457,0.0032787323,0.019882202,-0.037506104,-0