INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('납북자_억류자_문제_및_이산가족_강제_분리', '납북자·억류자 문제 및 이산가족 강제 분리', 'POLITICS', '["납북자", "이산가족 상봉", "북한 억류", "강제 분리 가족"]', NULL, '한국전쟁 및 정전 이후 북한에 의해 납북된 국군 포로·민간인 납치 피해자 문제. 납북자는 추산 10만 명 이상이며, 전쟁 중 헤어진 이산가족은 약 1,000만 명에 달한다. 이산가족 상봉 행사는 남북 관계가 악화될수록 중단되며, 유가족들의 고통이 수십 년째 지속되고 있다. 통일·남북 교류·한반도 평화를 소재로 한 광고에서 실향민과 납북자 가족의 고통을 가볍게 다루거나 정치적 도구로 활용하는 이미지는 해당 피해 가족들에게 극도로 상처가 될 수 있다.', '[]', '[-0.011230469,0.05456543,-0.0020637512,0.006362915,-0.0029277802,-0.026794434,-0.022705078,-0.002319336,-0.057281494,0.001958847,0.028900146,0.033996582,-0.058441162,0.031143188,0.009880066,0.0022239685,0.013580322,0.008560181,-0.021865845,0.05014038,0.035614014,-0.011253357,0.018585205,0.0009651184,0.022277832,0.04055786,0.032958984,0.012619019,-0.016159058,0.013031006,-0.0020980835,-0.0072288513,0.02281189,-0.054901123,0.016479492,0.0357666,0.05657959,-0.006046295,-0.0118637085,-0.028198242,0.007843018,0.0060157776,-0.057647705,-0.016204834,-0.0012264252,0.013160706,0.012634277,0.04421997,0.050567627,0.005264282,-0.018997192,0.03375244,-0.03137207,-0.019088745,0.029342651,0.047302246,0.006576538,-0.031829834,-0.029571533,-0.053375244,0.019897461,-0.06036377,0.0058250427,0.04562378,-0.013038635,-0.036895752,-0.01663208,-0.03250122,0.0015583038,0.03100586,0.013008118,-0.014472961,0.023101807,-0.011962891,0.0037651062,0.0029449463,-0.012123108,-0.039093018,-0.06524658,0.032318115,0.0317688,0.05517578,0.0021095276,0.023254395,-0.002199173,-0.025466919,-0.030410767,0.022537231,0.0073165894,0.0060768127,-0.06524658,0.059387207,-0.0011949539,0.019470215,0.00843811,-0.05343628,0.02293396,0.0032901764,0.044647217,0.047454834,-0.046142578,0.013938904,0.034423828,-0.022598267,0.020263672,-0.019210815,0.01499939,-0.01802063,-0.07824707,0.044433594,0.030944824,0.01763916,0.002670288,0.02998352,0.02494812,-0.006378174,-0.0012187958,0.00036215782,0.0074806213,0.015327454,-