INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('국가보안법을_이용한_사상_표현_탄압', '국가보안법을 이용한 사상·표현 탄압', 'POLITICS', '["국가보안법", "이적 표현물", "사상 검열", "표현의 자유 탄압"]', NULL, '1948년 제정된 국가보안법은 반국가 단체(북한 포함) 활동을 처벌하는 법률로, 냉전 시기에는 정치적 반대자를 탄압하는 도구로 광범위하게 악용되었다. 현재도 존재하는 이 법은 표현의 자유를 위축시킨다는 국제 인권 단체의 비판을 받고 있다. 한반도 평화·통일·북한 관련 콘텐츠를 광고에 활용할 경우 국가보안법 위반 소지 여부를 법적으로 검토해야 하며, 특히 정치·미디어·교육 관련 광고에서 민감한 이슈다.', '[]', '[0.033691406,0.030212402,0.043060303,0.081970215,-0.0335083,-0.019500732,-0.0390625,-0.008666992,-0.021835327,-0.047546387,0.035003662,0.020385742,0.019378662,0.020050049,-0.0034484863,-0.036895752,-0.023391724,0.01966858,-0.01134491,0.004798889,0.04257202,-0.014175415,-0.007221222,0.011764526,0.0024471283,0.008155823,0.011306763,-0.0073928833,-0.04345703,0.025985718,0.0178833,-0.017700195,0.018981934,-0.090270996,0.022109985,-0.012008667,0.041259766,0.0038204193,0.023452759,-0.035736084,0.032348633,-0.053131104,-0.016540527,0.009307861,-0.036254883,0.04888916,0.00579834,0.0054092407,0.019241333,-0.0009813309,-0.03668213,-0.005012512,-0.0013132095,0.024719238,-0.01828003,0.047821045,-0.022979736,-0.010353088,0.022979736,0.0031871796,0.010543823,-0.029525757,-0.060821533,0.03414917,-0.05609131,-0.010673523,-0.0020275116,-0.010345459,-0.029464722,0.031051636,0.03652954,0.002571106,0.0413208,-0.0029697418,0.0011510849,0.0007634163,-0.026168823,0.0635376,-0.029907227,-0.025756836,0.019866943,0.014175415,-0.038116455,0.04534912,-0.020996094,0.025344849,-0.04711914,0.021759033,-0.025909424,0.010627747,-0.030197144,0.010444641,-0.006088257,0.02381897,0.014122009,0.0031490326,-0.0017709732,-0.0075531006,0.07067871,0.029708862,-0.025604248,0.0736084,0.03591919,0.022506714,0.04675293,-0.00869751,-0.0047950745,0.029373169,-0.011856079,0.021316528,0.021865845,-0.01259613,-0.055511475,0.021820068,0.024215698,-0.019378662,-0.016342163,-0.015594482,0.011413574,0.017623901,-0.033355713,-0.054992676,0.0556640