INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('다문화_가정_혐오_및_외국인_배타_정서', '다문화 가정 혐오 및 외국인 배타 정서', 'DISCRIMINATION', '["다문화 혐오", "외국인 혐오", "반다문화", "인종 혐오 표현"]', NULL, '한국의 다문화 가정(한국인과 외국인 배우자 사이의 가정)은 전체 가구의 약 4%를 차지하지만, 다문화 자녀에 대한 학교폭력·따돌림, 외국 출신 부모에 대한 차별 등이 사회 문제로 지속되고 있다. 온라인 커뮤니티를 중심으로 반다문화·외국인 혐오 정서가 표출되며, 특히 특정 국적(중국·동남아시아 등)에 대한 비하 표현이 빈번하다.', '[]', '[0.037139893,0.0050735474,0.020492554,0.06378174,0.013122559,-0.033172607,-0.017120361,-0.026062012,-0.04284668,-0.028335571,-0.0005083084,-0.01727295,-0.01676941,-0.0034160614,-0.007129669,0.03225708,0.010848999,-0.006587982,-0.018447876,0.011497498,0.05050659,-0.017562866,-0.00039052963,0.03186035,-0.013435364,0.015449524,-0.010726929,0.011207581,-0.016815186,-0.017868042,0.0022277832,-0.014640808,-0.009742737,-0.07720947,0.017913818,0.033233643,-0.025100708,-0.015579224,0.039367676,-0.052886963,-0.00605011,0.003736496,-0.017074585,-0.00881958,-0.03756714,0.07696533,0.0054397583,0.019317627,0.039398193,0.015068054,-0.024520874,0.060394287,-0.019882202,-0.013923645,0.015296936,0.028167725,0.0033416748,0.010147095,0.010505676,-0.032440186,0.057769775,-0.017227173,-0.059051514,0.0023727417,-0.028671265,-0.024475098,-0.048217773,-0.020599365,-0.038391113,0.058380127,0.043762207,0.02696228,0.0050315857,0.020828247,-0.0033836365,-0.03665161,-0.04058838,0.0065307617,-0.012199402,-0.0103302,0.0146102905,0.028411865,-0.013961792,0.04840088,-0.008743286,-0.017562866,-0.08929443,-0.020248413,-0.027786255,0.0022220612,-0.02961731,0.049346924,-0.007820129,-0.0014152527,0.02293396,-0.03933716,0.0069007874,-0.059631348,0.030761719,0.02230835,-0.030151367,-0.03289795,0.031234741,-0.0029830933,0.040496826,-0.06329346,-0.028076172,-0.03765869,-0.05480957,0.012649536,-0.038970947,0.021820068,-0.045684814,0.0077552795,0.00459671,0.025283813,0.040893555,-0.044952393,0.010375977,0.025970459,-0.03756714,0.021087646,0.020095825,-0.049835205,-0.02