INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('유명인_자살_모방_효과_베르테르_효과', '유명인 자살 모방 효과 (베르테르 효과)', 'CHILD_PROTECTION', '["연예인 자살 모방", "베르테르 효과", "자살 보도 파급", "유명인 극단적 선택"]', NULL, '유명 연예인이나 공인의 자살 이후 사회 전반에 모방 자살이 급증하는 ''베르테르 효과''는 한국에서 반복적으로 관찰되어 왔다. 특히 2008~2010년대 여러 한류 스타의 자살 이후 통계적으로 자살률이 증가한 것이 확인되었다. 언론의 자살 보도 준칙(자살 방법 기술 금지, 미화 금지 등)이 있음에도 SNS를 통해 관련 정보가 확산된다.', '[]', '[0.01864624,0.05960083,0.030975342,0.055419922,-0.05670166,0.023986816,-0.017501831,0.032226562,0.026504517,-0.043395996,0.038116455,-0.008857727,-0.052246094,0.021026611,0.020690918,-0.015426636,-0.028030396,0.0340271,-0.02142334,-0.04714966,0.023406982,-0.029647827,0.003944397,0.029434204,0.033996582,-0.023788452,0.001490593,-0.021148682,-0.047943115,0.012069702,0.030014038,-0.020446777,0.0003938675,-0.055236816,-0.011421204,-0.004306793,0.03881836,-0.008628845,0.006767273,-0.022506714,0.055389404,-0.008682251,-0.010223389,0.040740967,-0.04660034,0.047973633,-0.029510498,-0.031219482,0.030838013,0.04269409,-0.026504517,0.04449463,0.0026741028,0.04537964,-0.011833191,0.035949707,-0.023986816,-0.022735596,0.011833191,0.0155181885,0.052581787,-0.014152527,0.00091552734,0.02406311,-0.058746338,-0.057739258,-0.046783447,0.0071525574,-0.007255554,0.038116455,0.03387451,-0.0044784546,0.03161621,0.040100098,0.0066070557,-0.017349243,0.02911377,0.048461914,0.0016860962,-0.0034732819,0.012825012,0.014823914,-0.031173706,0.045288086,-0.0050086975,-0.01008606,-0.06829834,-0.021530151,-0.011039734,0.022460938,-0.05432129,0.038726807,-0.022583008,0.028396606,0.06878662,-0.016113281,-0.030151367,-0.039855957,0.055145264,0.026824951,-0.006767273,-0.014122009,0.045288086,-0.030303955,0.019561768,-0.043273926,-0.0079422,0.033050537,-0.022888184,-0.015464783,0.023254395,0.0209198,-0.06185913,0.029006958,0.010513306,-0.036224365,0.0385437,-0.011940002,0.015464783,0.03390503,0.0055389404,0.035583496,-0.005001068,-0.01499176,-0