INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('산업현장_중대재해_및_노동자_사망', '산업현장 중대재해 및 노동자 사망', 'LABOR_HUMAN_RIGHTS', '["중대재해", "산업재해 사망", "산재 은폐", "건설 현장 사망"]', NULL, '한국의 산업재해 사망률은 OECD 주요국 대비 높은 수준이며, 매년 약 800~900명의 노동자가 산업재해로 사망한다. 2022년 중대재해처벌법이 시행되었으나 실효성 논란이 지속되고 있으며, 건설·제조·물류 현장에서의 반복적 사망 사고가 보도될 때마다 ''안전제일'', ''사람이 먼저'' 등의 슬로건을 내건 기업이 산재 사망 사고를 낸 경우 위선 논란이 즉각적으로 터진다. 건설·물류·제조 업종의 기업 이미지 광고에서 안전 관련 수치와 실천이 뒷받침되지 않으면 심각한 신뢰 훼손이 발생한다.', '[]', '[0.033843994,0.07861328,0.03842163,0.016967773,0.01914978,-0.0026874542,-0.024520874,0.028656006,0.047668457,-0.03515625,0.04449463,-0.035217285,-0.047180176,0.00069761276,0.023742676,-0.010017395,-0.033294678,-0.0062294006,-0.012382507,0.004737854,0.019577026,-0.008422852,-0.020721436,0.033996582,0.007007599,0.033996582,0.026123047,0.008094788,-0.030532837,-0.036743164,0.04046631,-0.019836426,-0.024490356,-0.03277588,0.03616333,0.014976501,0.0013103485,-0.037597656,0.0023479462,-0.006843567,0.032958984,-0.038879395,0.008979797,0.015563965,-0.023162842,-1.0728836e-05,0.014770508,0.0063171387,0.019226074,0.021636963,0.010787964,0.021057129,0.035888672,0.0056915283,0.00907135,0.017349243,0.010665894,-0.023544312,0.02204895,-0.039489746,0.04663086,-0.011650085,-0.041107178,0.015853882,-0.022659302,-0.036102295,-0.003129959,0.028152466,0.013343811,0.0013494492,-0.0046691895,-0.029968262,0.017730713,0.046081543,-0.025680542,-0.020477295,0.00182724,0.005657196,-0.006652832,0.051513672,-0.0061035156,-0.0084991455,-0.01927185,0.041625977,-0.038330078,-0.04046631,-0.078063965,-0.03366089,-0.015296936,0.046875,-0.09069824,0.012260437,0.07531738,0.022918701,0.024459839,-0.061798096,0.060791016,0.022567749,0.032409668,0.03387451,-0.0006933212,-0.0028362274,0.039123535,-0.021652222,-0.023986816,0.0065994263,-0.006828308,-0.036102295,-0.0015764236,-0.04135132,0.057037354,0.012138367,-0.07885742,0.04510498,0.023117065,0.011749268,0.013198853,0.0349731