INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('4대강_사업으로_인한_생태계_파괴', '4대강 사업으로 인한 생태계 파괴', 'ENVIRONMENT', '["4대강 사업", "녹조 라떼", "강 생태계 파괴", "보 건설 부작용"]', NULL, '이명박 정부(2009~2012년)가 추진한 4대강 살리기 사업은 22조 원의 예산을 투입해 한강·낙동강·금강·영산강에 대형 보(洑) 16개를 건설한 사업. 완공 직후부터 녹조 창궐, 물고기 떼죽음, 모래톱 생태계 파괴 등 심각한 환경 문제가 잇따랐으며, ''녹조 라떼''라는 신조어가 생겨날 정도로 수질 악화가 심각해졌다. 환경 단체·학계의 지속적 비판으로 감사원이 사업 문제점을 지적했으며, 일부 보가 개방 또는 철거되었다. 수질·환경·친환경 관련 광고에서 4대강 이미지를 긍정적으로 소비하는 것은 환경 단체와 지역 주민의 반발을 초래한다.', '[]', '[0.0042037964,0.05480957,0.076660156,0.025482178,-2.0325184e-05,0.013214111,-0.041259766,0.031677246,-0.016311646,-0.0014266968,0.08618164,-0.043029785,-0.022445679,0.0079956055,0.020629883,-0.013900757,-0.04849243,-0.019989014,-0.0513916,0.032562256,0.007663727,-0.039031982,-0.0289917,-0.0029468536,0.0015935898,0.018188477,0.024612427,0.016036987,0.04940796,-0.035339355,-0.009338379,-0.019882202,0.014732361,-0.011451721,0.010871887,-0.014518738,0.012390137,-0.03677368,-0.00944519,-0.028305054,0.035980225,-0.005722046,-0.01713562,-0.002483368,0.022750854,0.048461914,-0.037902832,0.032409668,0.057250977,0.042877197,0.022842407,0.026016235,0.014190674,-0.052001953,0.012283325,0.029327393,0.009536743,-0.02381897,-0.029663086,0.00012588501,0.08630371,0.002960205,0.012420654,0.027359009,-0.056793213,-0.0046539307,-0.033813477,0.046173096,-0.03918457,0.015136719,-0.038757324,-0.04727173,0.02859497,-0.0052986145,0.012016296,-0.013679504,0.045715332,-0.037963867,-0.0317688,-0.024414062,0.038482666,0.04345703,-0.009010315,0.04937744,-0.010650635,-0.041992188,-0.039642334,-0.012718201,-0.030639648,0.055755615,-0.03643799,0.03338623,-0.03289795,-0.0024356842,-0.0037784576,-0.054351807,0.0027675629,0.020080566,0.002418518,0.07623291,-0.012321472,-0.0256958,0.04244995,-0.0056152344,-0.008735657,-0.011238098,-0.021820068,-0.0019721985,0.018295288,-0.02633667,-0.017044067,-0.029937744,-0.018875122,0.038238525,0.019454956,0.0032