INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('한중_역사_문화_갈등_동북공정', '한중 역사·문화 갈등 및 동북공정', 'HISTORY', '["동북공정", "한복 중국 기원", "김치 중국 것", "한국 문화 중국 소유", "중국 문화공정"]', NULL, '중국 정부가 고구려·발해 등 한국 고대사를 중국사로 편입하려는 ''동북공정'' 프로젝트와, 한복·김치 등 한국 전통문화를 중국 문화로 주장하는 행위가 지속되면서 한국 내 반중 감정이 구조적으로 고조된 현상이다. 이는 단발성 사건이 아니라 역사 인식을 둘러싼 장기적 외교·문화 갈등으로, 한국 소비자의 민족 정체성과 맞닿아 있다.', '["KR-020"]', '[-0.005218506,0.009376526,0.02243042,0.031173706,0.003709793,-0.020111084,-0.02720642,0.036834717,-0.058898926,0.016540527,0.026153564,0.016082764,-0.061523438,-0.004535675,-0.0037231445,0.014511108,-0.04437256,-0.030731201,0.042938232,0.030761719,0.03152466,0.02519226,-0.031066895,0.012832642,-0.014030457,-0.0034637451,0.008880615,0.016448975,0.0037078857,-0.023590088,-0.01940918,-0.013069153,-0.05279541,-0.048583984,0.040618896,0.02458191,0.00080776215,0.014137268,0.03274536,0.00096940994,0.03201294,-0.05859375,-0.008651733,0.00894165,0.040100098,0.027267456,0.035095215,0.0021972656,0.0015077591,0.014190674,-0.032318115,0.05596924,0.023834229,0.009254456,0.037628174,0.060394287,0.013160706,-0.031234741,-0.011276245,-0.021484375,0.06365967,-0.06567383,-0.033966064,0.05731201,-0.029678345,-0.040100098,-0.030517578,-0.0052223206,-0.031555176,-0.03527832,0.023757935,0.009536743,0.00053215027,-0.03817749,0.0116119385,0.00051021576,0.025909424,0.027938843,0.018951416,-0.015777588,0.0010251999,-0.0017738342,0.004020691,0.038970947,0.011016846,-0.027389526,-0.047546387,0.0029449463,-0.014434814,0.039642334,-0.02772522,0.020935059,-0.014633179,0.03463745,0.015426636,-0.008872986,0.02961731,0.064331055,0.028839111,0.026565552,-0.056732178,0.00047326088,0.004737854,0.025344849,0.012451172,0.008003235,0.0029392242,-0.02255249,-0.04788208,0.019210815,-0.015090942,0.00085544586,-0.032836914,0.023376465,0.047851562,0.009231567,0.004486084,-0.036254883,-0.019042969,0.014266968,-0.07867432,-0.020019531,0.020553589,-0.037963867,-0