INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('미세먼지_및_대기오염_피해', '미세먼지 및 대기오염 피해', 'ENVIRONMENT', '["미세먼지", "초미세먼지", "대기오염", "중국발 황사", "실외 활동 자제"]', NULL, '봄철(3~5월)과 겨울철(11~2월)에 특히 심해지는 미세먼지(PM10)·초미세먼지(PM2.5) 문제는 한국인의 건강과 일상생활에 큰 영향을 미치는 고질적 환경 문제다. 중국발 황사·스모그와 국내 석탄 발전소·자동차 배기가스가 주요 원인으로 꼽히며, 마스크 착용·야외 활동 자제가 일상화되었다. 야외 활동·스포츠·레저·관광 광고에서 오염된 하늘이나 마스크를 연상시키는 장면을 무심코 포함하거나, 반대로 미세먼지가 심각한 날 ''맑은 공기 속 야외 활동''을 조장하는 광고는 소비자 불신을 야기한다.', '[]', '[0.007858276,0.041290283,0.039489746,0.0440979,0.009521484,4.196167e-05,-0.0045318604,-0.01574707,0.00015091896,-0.00592041,-0.012611389,0.0021705627,-0.06329346,0.031097412,-0.0012874603,0.04055786,-0.042175293,-0.038116455,-0.028671265,0.02508545,0.02758789,0.049743652,0.028396606,-0.0077056885,-0.0006933212,0.03164673,0.020477295,-0.024871826,0.05718994,0.024490356,0.0060691833,-0.01977539,0.00094890594,-0.053649902,0.014724731,-0.008796692,-0.012161255,0.0035972595,-0.0010433197,-0.015914917,0.023956299,-0.02986145,-0.011146545,0.01411438,-0.017654419,-0.004589081,0.039031982,-0.027328491,0.07739258,0.0446167,0.023910522,0.03161621,0.064575195,0.022964478,0.05218506,0.007396698,-0.013809204,0.007785797,0.01209259,-0.008865356,0.04397583,-0.046539307,-0.047546387,0.049743652,-0.024673462,-0.030776978,0.058258057,0.023117065,-0.03793335,0.0004069805,0.032226562,-0.0022239685,0.07086182,-0.026641846,0.0259552,-0.008728027,0.02067566,-0.0036087036,0.008560181,-0.035949707,0.0049057007,0.016693115,-0.0059318542,0.026931763,-0.061950684,-0.05026245,-0.04385376,0.03186035,-0.035583496,0.012687683,-0.076660156,0.0039787292,0.029769897,-0.0048332214,0.045654297,-0.008468628,-0.01209259,0.003206253,0.011077881,0.05392456,0.016189575,-0.024993896,0.028182983,0.038330078,-0.049438477,-0.032958984,-0.020935059,0.022384644,-0.004184723,-0.007896423,0.057006836,0.030792236,-0.052124023,0.052215576,-0.017074585,0.046783447,-0.029174805,0.017700195,-0.01