INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('딥페이크_AI_허위정보_및_가짜뉴스_유포', '딥페이크·AI 허위정보 및 가짜뉴스 유포', 'ETC', '["딥페이크 허위정보", "AI 가짜뉴스", "조작 영상", "허위 정보 유포"]', NULL, 'AI 기술의 발전으로 실제와 구분하기 어려운 딥페이크 영상·음성·이미지가 범람하면서, 정치인·연예인·일반인의 발언을 조작한 허위 정보가 SNS를 통해 급속히 퍼지는 현상이 사회 문제가 되고 있다. 선거철·정치 갈등 시기에 딥페이크 선거 광고가 사용된 사례가 국내외에서 보고되었으며, 사기·보이스피싱에도 AI 음성 합성이 활용된다.', '[]', '[-0.0013847351,-0.033294678,-0.03778076,0.045043945,0.03579712,-0.003534317,-0.030563354,0.06549072,-0.032409668,0.014724731,0.06384277,-0.040130615,-0.03173828,-0.02368164,0.0045166016,-0.028442383,-0.061950684,-0.06274414,-0.00032019615,0.027160645,-0.031433105,-0.028686523,0.033050537,-0.006275177,0.016357422,0.004814148,0.028259277,0.008392334,-0.0057754517,0.01637268,-0.011009216,-0.03036499,0.03878784,-0.050842285,0.018447876,0.04257202,-0.03967285,-0.011291504,-0.0006184578,0.027038574,0.03515625,0.01953125,0.0055160522,0.022491455,-0.011749268,-0.05618286,-0.03845215,0.004196167,0.020965576,0.06542969,-0.005531311,0.03765869,-0.0413208,-0.0287323,0.010719299,0.08288574,0.017059326,-0.01876831,0.0026741028,0.008850098,0.00015032291,-0.011924744,0.021850586,0.034484863,-0.054626465,-0.0006132126,-0.007659912,0.016464233,-0.03010559,0.012802124,0.03491211,0.038330078,0.01651001,-0.018341064,-0.0031776428,-0.074157715,-0.025024414,0.080078125,0.015579224,-0.012878418,0.013748169,0.022277832,-0.039215088,-0.0024223328,0.024536133,-0.039215088,-0.057373047,-0.019851685,-0.07684326,0.012390137,-0.041229248,0.024276733,-0.0078125,0.010437012,-0.034118652,0.044677734,0.035308838,0.0124053955,0.041778564,0.0059051514,0.010482788,-0.025375366,0.005004883,0.011817932,0.06439209,-0.03475952,-0.01727295,-0.0423584,0.02229309,0.017150879,-0.03640747,-0.018676758,-0.09741211,-0.0020866394,0.014961243,-0.04458618,0.003414154,0.019943237,0.047912598,0.010231018,-0.059020996,0.022842407,0.04083252,0.007171631,-0.028305054,0.021636963,-0.0