INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('일본_오염수_해양_방류_및_수산물_안전_불안', '일본 오염수 해양 방류 및 수산물 안전 불안', 'ETC', '["후쿠시마 오염수", "ALPS 처리수 방류", "수산물 방사능", "해양 오염"]', NULL, '2023년 8월, 일본 정부가 후쿠시마 원전 처리수(오염수)를 태평양에 방류하기 시작하면서 한국 내 수산물 소비 공포와 한일 외교 갈등이 동시에 폭발했다. 수산물·해산물·해양 관광 관련 광고에서 일본산 원산지 표기 문제, 방사능 안전성 강조 또는 부정, 오염수를 연상시키는 이미지는 소비자 불안을 자극하여 즉각적인 부정적 반응을 유발한다.', '[]', '[0.0231781,0.0017204285,0.048217773,0.058441162,0.0007557869,-0.0023765564,-0.037628174,0.007411957,0.049194336,-0.004005432,0.04144287,-0.08850098,-0.05770874,0.0016269684,-0.029937744,-0.03164673,-0.028137207,-0.044128418,-0.019622803,-0.036590576,0.016464233,-0.027175903,-0.024719238,-0.008979797,0.032440186,-0.02293396,0.037078857,0.029312134,0.0003476143,0.01272583,0.0009880066,-0.032714844,-0.006275177,-0.010650635,0.02319336,-0.022460938,0.037597656,-0.022415161,-0.007247925,-0.04031372,0.035614014,-0.011413574,-0.0071258545,-0.0045700073,0.0065231323,0.030532837,0.02154541,-0.062561035,0.06237793,-0.0059165955,0.06878662,0.053863525,0.043548584,-0.062561035,0.03125,-0.019561768,-0.012168884,0.025283813,0.033416748,-0.026504517,0.028167725,-0.05117798,-0.043792725,-0.00504303,-0.047698975,0.0027599335,0.05899048,-0.013885498,-0.05984497,0.0035247803,0.004371643,-0.015510559,0.038146973,-0.028762817,0.01727295,-0.018875122,-0.030151367,0.0066184998,0.020950317,0.005279541,-0.031433105,0.09362793,-0.08581543,0.024627686,0.0085372925,0.03414917,-0.027923584,0.001663208,-0.044433594,0.056549072,-0.07659912,0.040100098,-0.027877808,0.06311035,0.01159668,-0.025146484,-0.009185791,0.010482788,0.038970947,0.04763794,-0.008911133,-0.040405273,0.04647827,0.007965088,0.0054244995,-0.0440979,-0.04284668,-0.013847351,0.03842163,-0.01878357,0.09118652,-0.009963989,-0.058502197,0.027435303,-0.027175903,0.009605408,-0.0061836243,-0.009643555,0.017913818,-0.03881836,-0.04107666,0.007259369,0.009475708,-0.014823914,-0.01890564,