INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('온라인_젠더갈등_및_손모양_기호_논쟁', '온라인 젠더갈등 및 손모양 기호 논쟁', 'GENDER', '["집게손가락", "메갈리아", "남혐", "여혐", "손모양 기호", "메갈 손"]', NULL, '2015년 메갈리아 커뮤니티 등장 이후 한국 온라인 공간에서 특정 손 모양(집게손가락, 엄지·검지 원형 등)이 남성 혐오 또는 여성 혐오 기호로 해석되는 논쟁이 반복적으로 발생하고 있다. 이 갈등은 온라인 커뮤니티를 중심으로 시작되어 현실의 소비자 불매운동으로 이어지는 양상을 반복하며, 한국 사회 젠더갈등의 상징적 현상 중 하나로 자리잡았다.', '["KR-006", "KR-007", "KR-008", "KR-009", "KR-015", "KR-016", "KR-024", "KR-027", "KR-028", "KR-040"]', '[0.004753113,0.01159668,-0.003566742,0.053588867,0.0011367798,-0.0016832352,0.00044989586,0.018188477,-0.016784668,-0.0390625,0.00818634,-0.022125244,-0.008026123,0.012168884,-0.043945312,-0.026153564,-0.0024356842,-0.03414917,0.01335907,0.023101807,-0.012489319,-0.014915466,0.0039043427,0.03717041,-0.021560669,0.05154419,-0.006134033,0.033599854,-0.014289856,0.014289856,0.029342651,-0.026870728,0.014427185,-0.035125732,-0.031341553,-0.0058670044,-0.034240723,-0.00036883354,0.016036987,-0.021987915,0.016326904,-0.03781128,-0.008636475,0.022720337,-0.04171753,0.017608643,-0.030258179,-0.029251099,0.037506104,0.00983429,-0.011192322,0.0026302338,-0.015899658,0.027877808,-0.020370483,0.016525269,-0.025177002,0.012107849,-0.006416321,-0.013435364,0.025741577,-0.0058631897,-0.032348633,-0.033599854,-0.005138397,0.0066986084,-0.020431519,-0.031677246,-0.0013275146,0.026992798,0.06585693,-0.019104004,0.04711914,0.02708435,-0.010627747,-0.019973755,-0.03717041,0.0073547363,0.014053345,0.033325195,0.03250122,0.07702637,0.005886078,0.03387451,-0.0040626526,0.02279663,-0.10668945,-0.029403687,-0.014778137,0.024993896,-0.085754395,0.025970459,-0.010498047,0.0023899078,0.019515991,-0.05984497,-0.015235901,-0.01449585,0.03970337,0.055236816,0.0024681091,-0.014091492,0.012779236,0.005584717,0.027572632,-0.037231445,0.0075263977,-0.011184692,-0.013450623,-0.011398315,0.009803772,0.00019156933,-0.063964844,0.0026359558,0.026229858,0.012229