INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('성별_고정관념_및_성차별', '성별 고정관념 및 성차별', 'GENDER', '["여성 비하", "남성 비하", "성역할 강요", "여자니까", "남자니까", "여성 성상품화", "육아 고정관념"]', NULL, '특정 성별에 사회적 역할과 능력을 고정하는 편견으로, 여성을 수동적·장식적 존재로 묘사하거나 남성에게 과도한 경제적 책임을 당연시하는 구조적 차별이다. 한국에서는 2015년 이후 페미니즘 운동의 확산과 함께 성별 고정관념에 대한 사회적 감수성이 급격히 높아졌으며, 이에 민감하게 반응하는 소비자층이 두텁게 형성되어 있다.', '["KR-005", "KR-013", "KR-014", "KR-018", "KR-025", "INTL-013", "INTL-018", "KR-035", "INTL-027", "KR-039", "KR-043", "KR-044"]', '[-0.014595032,0.048858643,0.010482788,0.03427124,0.027053833,0.0079422,0.009010315,0.034210205,0.0028839111,-0.033813477,0.025405884,-0.007396698,-0.012794495,0.042510986,0.0038452148,-0.021011353,-0.010025024,-0.007904053,0.010917664,0.02218628,0.03515625,-0.050994873,-0.006778717,0.024734497,-0.029541016,0.044769287,-0.022491455,0.062927246,-0.050231934,0.01777649,0.02696228,-0.016204834,0.031707764,-0.06726074,-0.00920105,0.015213013,-0.01763916,0.003370285,0.07562256,-0.024856567,0.039855957,-0.03050232,-0.019317627,-0.012008667,0.0026359558,0.021072388,0.01260376,-0.019607544,0.0105896,0.0132369995,-0.0055732727,0.010917664,0.009437561,-0.010734558,0.019378662,0.054534912,-0.02142334,-0.021591187,-0.0065460205,0.0024738312,0.030853271,-0.02381897,-0.031433105,0.048065186,0.022125244,-0.03338623,-0.029556274,-0.0038318634,-0.027709961,0.020980835,0.06958008,0.00440979,0.017471313,0.050476074,-0.032806396,-0.024887085,-0.0024528503,-0.027023315,-0.004589081,0.0012588501,0.0014629364,0.03274536,-0.0034637451,0.049041748,0.030960083,-0.022415161,-0.052520752,0.012290955,-0.047698975,0.036346436,-0.062805176,-0.009773254,-0.03338623,0.020935059,0.0035190582,-0.026855469,0.049102783,0.024719238,0.043060303,0.028030396,0.022705078,0.03857422,0.058380127,-0.010574341,0.048736572,-0.006713867,-0.0036849976,-0.020553589,-0.034729004,-0.009719849,-0.0015163422,0.026947021,-0.035583496,-0.022232056,0.00079774857