INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('연애_이성관계_성별_고정관념', '연애·이성관계 성별 고정관념', 'GENDER', '["남친 없는 여자", "남자친구 사귀기", "어장관리", "계산은 남자가", "명품백 얻는 법", "데이트비용 남성 부담"]', NULL, '이성 관계에서 특정 성별에 경제적 의존이나 수동성을 당연시하는 사회적 편견. 여성을 소비 수혜자로, 남성을 결제 주체로 고정하는 구조를 정상화하는 태도가 이에 해당하며, 한국 사회에서 젠더갈등과 맞물려 매우 민감한 영역이다.', '["KR-032", "KR-033", "KR-047", "KR-048", "KR-049"]', '[0.002981186,-0.006793976,-0.018585205,0.023834229,-0.032989502,-0.01902771,-0.0030441284,-0.003074646,-0.028274536,-0.054595947,0.012527466,-0.04421997,-0.000667572,0.03326416,-0.009407043,0.008407593,0.0016841888,-0.0025806427,0.0075950623,0.036621094,0.038238525,-0.027175903,0.0096206665,0.00440979,-0.050323486,0.068115234,0.01739502,0.038513184,-0.052001953,0.01423645,-0.0013418198,-0.019104004,0.04144287,-0.07727051,-0.009544373,0.07647705,0.012741089,-0.017074585,0.02670288,-0.028289795,0.024871826,-0.012481689,-0.019699097,-0.04345703,0.036254883,0.010879517,-0.0029468536,0.025024414,0.046936035,-0.031204224,-0.01524353,0.012901306,0.004962921,0.012832642,0.046417236,0.015991211,-0.02293396,-0.012489319,0.018432617,0.006942749,0.051086426,-0.009628296,-0.053619385,0.029586792,-0.010749817,-0.04953003,-0.050689697,0.028137207,-0.05239868,0.01776123,0.039154053,-0.004219055,0.01737976,0.051727295,0.02784729,-0.013313293,-0.002286911,-0.001821518,-0.01436615,-0.0022144318,0.008628845,0.028823853,-0.038513184,0.06451416,0.022583008,-0.049194336,-0.08654785,-0.01235199,-0.013748169,0.03112793,-0.08929443,-0.01159668,-0.021850586,-0.01852417,0.029281616,-0.026611328,0.045928955,0.031402588,0.015174866,0.012367249,-0.013969421,0.008796692,0.04675293,0.002105713,0.0127334595,-0.011291504,-0.013839722,0.007205963,-0.027130127,0.015991211,-0.0141067505,0.010429382,-0.057006836,0.010276794,0.011123657,-0.027191162,-0.011917114,0.030685425,-0.008308411,0.010040283,-0.03668213,-0.003129959,0.028198242,-0.01939392,-0.05441284,0.031