INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('소수민족_문화_전용_및_고정관념', '소수민족 문화 전용 및 고정관념', 'DISCRIMINATION', '["히스패닉 희화화", "아시아 고정관념", "문화 전용", "소수민족 캐릭터", "문화 왜곡"]', NULL, '특정 민족의 문화를 해당 공동체의 맥락과 동의 없이 가져다 단순화·희화화하거나 상업적으로 소비하는 행위를 문화 전용(Cultural Appropriation)이라 한다. 이는 해당 민족의 역사적 억압 경험과 맞물려 심각한 문화적 모욕으로 받아들여지며, 특히 역사적으로 차별받아온 소수 집단의 문화를 주류 집단이 착취적으로 소비할 때 더욱 심각해진다.', '["INTL-023"]', '[0.030151367,0.0049552917,-0.008544922,0.049316406,0.019744873,-0.029220581,-0.050842285,0.039215088,-0.017211914,-0.0435791,0.011909485,-0.027694702,-0.04333496,0.054260254,-0.010047913,-0.007335663,-0.033172607,-0.02458191,0.042175293,0.020553589,0.030792236,0.033355713,-0.044769287,0.05996704,-0.02456665,0.026687622,-0.021896362,0.09320068,0.027008057,-0.004901886,-0.009788513,-0.013656616,-0.04095459,-0.023284912,0.014350891,0.0287323,0.00046038628,0.022384644,0.032043457,-0.030044556,0.0032978058,-0.025238037,-0.024963379,-0.017929077,0.011550903,0.0395813,0.0014772415,-0.0030937195,0.004753113,0.013847351,-0.02067566,0.036895752,-0.0211792,-0.04559326,-0.0031986237,0.06185913,-0.033355713,0.0014944077,-0.029541016,-0.036895752,0.041656494,-0.008491516,-0.013244629,0.013290405,-0.017364502,0.037200928,0.0009069443,-0.011024475,-0.014564514,0.014411926,0.020828247,-0.0018873215,0.016113281,0.01727295,0.013244629,-0.03640747,-0.0029621124,-0.0003695488,-0.040039062,-0.017227173,0.00730896,0.023849487,-0.00844574,0.07659912,-0.03982544,-0.008735657,-0.070739746,-0.026275635,-0.042175293,0.008934021,-0.05001831,0.033325195,-0.033111572,0.031585693,0.022857666,-0.043670654,0.02609253,-0.02293396,0.04156494,0.052459717,-0.02508545,-0.050476074,0.027252197,-0.028518677,0.013504028,-0.0022830963,-0.010192871,-0.028930664,-0.043273926,0.0010318756,-0.018112183,-0.01184845,-0.04058838,0.076538086,0.01625061,-0.027801514,-0.012832642,-0.019989014,0.026123047,0.016525269,-0.01083374,-0.0395813,-0.0093917