INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('이스라엘_팔레스타인_분쟁', '이스라엘·팔레스타인 분쟁', 'POLITICS', '["이스라엘", "팔레스타인", "Gaza", "가자지구", "중동 갈등", "BDS 운동"]', NULL, '1948년 이스라엘 건국 이후 지속되어 온 이스라엘과 팔레스타인 간의 영토·주권 분쟁. 2023년 10월 하마스의 기습 공격과 이스라엘의 가자지구 대규모 군사 작전으로 국제 여론이 극도로 양극화되었다. 어느 한쪽을 지지하는 것으로 해석되는 어떤 행위도 반대편으로부터 즉각적인 반발을 부른다.', '["INTL-010"]', '[0.0041122437,0.033294678,0.017547607,0.030654907,-0.047058105,0.044952393,0.014122009,0.058441162,0.010269165,-0.032562256,0.0011692047,-0.0018424988,-0.055389404,-0.008262634,0.023498535,0.020248413,-0.032165527,0.0010633469,0.0078125,0.0015211105,0.0093688965,-0.015144348,-0.0038909912,0.042114258,-0.03201294,0.0044441223,-0.011558533,0.07904053,-0.027389526,0.026626587,0.06878662,-0.0206604,0.011543274,-0.026641846,-0.012702942,0.010871887,-0.004589081,0.0020198822,0.009284973,0.0056419373,-0.009689331,0.040740967,-0.06842041,-0.00020313263,0.053771973,-0.014312744,0.012321472,0.038970947,0.011146545,0.0113220215,0.02243042,0.052764893,-0.00040555,0.023971558,-0.00019943714,0.01184845,-0.02104187,-0.05117798,-0.025604248,0.05303955,0.010795593,-0.007659912,0.030273438,-0.00052309036,-0.03878784,0.012207031,0.033203125,-0.0011224747,0.0234375,-0.020202637,-0.012763977,0.02558899,0.016555786,-0.016967773,0.017349243,-0.044952393,-0.0025024414,-0.015052795,-0.0028896332,0.027023315,-0.014816284,0.06323242,0.020736694,0.022506714,-0.035980225,-0.024337769,-0.03289795,-0.04498291,0.03366089,0.038330078,-0.046691895,-0.05215454,-0.021820068,0.021057129,-0.03866577,-0.0034313202,0.047698975,-0.033111572,0.023498535,0.0023880005,-0.024780273,-0.0051078796,0.03668213,0.010322571,-0.021270752,-0.0077400208,-0.005317688,-0.014411926,0.031066895,-0.022964478,0.0038700104,0.05218506,-0.044281006,0.02029419,0.032562256,-0.040618896,0.027511597,-0.046905518,0.00040960312,-0.053375244,-0.068725586,0.020065308,0.019378662,-0.007797241,-0.05206299,-0.04104614