INSERT INTO public.sensitive_events (id, title, category, trigger_expressions, event_date, description, linked_issues, embedding) VALUES ('신장_위구르_강제노동_인권_탄압', '신장 위구르 강제노동 및 인권 탄압', 'LABOR_HUMAN_RIGHTS', '["위구르 강제노동", "신장 면화", "중국 공급망 인권", "BCI 면화", "위구르 탄압"]', NULL, '중국 신장 위구르 자치구에서 중국 당국이 위구르족을 강제 수용소에 구금하고 강제노동에 동원하고 있다는 국제 인권 단체·서방 정부의 고발이 이어지고 있는 현재진행형 인권 탄압 사건이다. 신장산 면화는 전 세계 의류 공급망과 연결되어 있어, 공급망 투명성이 기업 윤리의 핵심 이슈로 부상했다.', '["INTL-020"]', '[0.008369446,0.0925293,0.043670654,0.078186035,-0.020751953,-0.03262329,0.010772705,0.030075073,-0.00094270706,-0.06506348,0.03488159,0.055419922,-0.08807373,0.012535095,0.01763916,0.02067566,-0.038482666,-0.008331299,0.0010194778,-0.003704071,0.022369385,0.026229858,0.008636475,0.0073127747,-0.015090942,-0.0010757446,0.01083374,0.024932861,0.031463623,0.015686035,0.03253174,-0.008285522,-0.014877319,-0.028396606,0.056488037,-0.0119018555,0.03302002,0.026473999,0.03515625,-0.03375244,0.009178162,-0.063964844,-0.04763794,0.034332275,-0.017593384,0.025863647,0.002298355,0.010322571,0.011993408,0.025161743,0.0066375732,0.08239746,0.02835083,0.0004312992,0.025115967,0.04989624,-0.0115356445,-0.004764557,0.010444641,-0.002128601,-0.0038719177,-0.01512146,-0.03845215,0.03201294,-0.022964478,-0.042999268,0.013328552,0.024932861,0.00617218,-0.035461426,0.048950195,-0.005428314,0.03302002,0.04550171,0.01234436,0.006816864,0.037628174,0.07720947,-0.009178162,0.031036377,0.006046295,0.011375427,-0.027893066,0.052337646,-0.035003662,-0.01171875,-0.06866455,-0.003932953,-0.017959595,-0.005054474,-0.074645996,-0.0039043427,-0.022506714,0.05419922,0.0065994263,-0.03326416,0.036193848,0.04916382,0.05935669,0.04586792,-0.008850098,0.00869751,0.060028076,0.026062012,-0.018112183,0.020843506,-0.049865723,0.03955078,-0.03817749,0.012374878,0.024230957,-0.01335907,-0.06665039,-0.0209198,0.07159424,-0.06311035,-0.037261963,-0.0236969,-0.0069351196,0.0076522827,-0.012794495,0.0035877228,0.011253357,-0.017822266,-0.080444336,0.00223732,-0.020645142