INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-003', 'KR', 'DISASTER', '스타벅스 코리아 세월호 참사일 ''사이렌 클래식 머그'' 이벤트', '2024-04-16', '2024년 4월 16일 세월호 참사 10주기 당일, 스타벅스 코리아가 ''사이렌 클래식 민트 머그 237ml''를 신제품으로 출시했다. 스타벅스 로고 속 사이렌은 그리스신화에서 배를 난파시키는 존재로, 세월호 참사일에 배 침몰을 연상시키는 이름의 제품을 홍보한다는 논란이 일었다. 237ml 용량이 세월호 초기 실종자 수(237명)와 일치한다는 점도 논란을 더했다.', '선박_침몰_및_구조_실패', '["https://imnews.imbc.com/news/2026/politics/article/6824828_36911.html", "https://www.asiatoday.co.kr/kn/view.php?key=20260522010006654"]', '스타벅스 코리아는 2024년 4월 16일 세월호 참사 10주기에 ''사이렌 클래식 민트 머그 237ml''를 출시했다. 이 제품명과 237ml 용량이 세월호 초기 실종자 수와 일치해 논란이 일었다. 이재명 대통령은 이를 "패륜행위"라고 비판하며, 스타벅스의 마케팅이 유가족과 국민의 슬픔을 조롱하는 것이라고 주장했다. 논란이 커지자 스타벅스는 공식 사과문을 발표하고 대표가 해임되었으며, 정부 차원에서 불매 선언이 이어졌다.', '[0.017730713,0.021850586,-0.020690918,-0.027435303,-0.01675415,-0.009170532,0.02835083,0.07977295,-0.007896423,-0.02532959,0.026184082,-0.016357422,-0.06542969,-0.007881165,0.012336731,0.024978638,-0.05343628,0.0099105835,-0.081604004,0.0155181885,-0.0042495728,-0.01108551,-0.029144287,0.022415161,0.01751709,-0.0038452148,-0.018127441,0.017120361,0.053253174,0.021865845,0.022644043,-0.014129639,0.005088806,-0.041229248,-0.00020337105,0.0143966675,-0.010688782,-0.029556274,0.0061187744,-0.0015048981,-0.0715332,-0.026367188,0.026275635,0.028411865,0.022003174,0.0045433044,-0.001748085,-0.013305664,0.043518066,0.052459717,0.021224976,0.016281128,0.042816162,-0.027862549,-0.0029945374,-0.01651001,-0.025680542,0.014511108,-0.011268616,0.024093628,0.041168213,-0.033050537,0.009994507,-0.024337769,0.0014209747,0.0053138733,0.024795532,0.037994385,-0.028305054,0.03253174,0.03878784,0.091796875,0.0025291443,-0.004459381,-0.057403564,-0.020080566,-0.04574585,-0.0044136047,-0.020126343,-0.00017499924,-0.029296875,-0.025253296,0.0025672913,0.025680542,-0.040618896,-0.04916382,-0.027145386,-0.016708374,-0.02772522,0.0345459,-0.017608643,0.011024475,-0.0028