INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-004', 'KR', 'HISTORY', '유니클로 후리스 25주년 ''80년도 더 된 일'' 위안부 조롱 광고 논란', '2019-10-18', '2019년 10월 유니클로가 후리스 출시 25주년 기념 글로벌 광고를 한국에서 방영할 때 한국판에만 ''80년도 더 된 일을 어떻게 기억하냐''는 문구가 추가됐다. 이는 일본군 위안부 피해자들의 증언을 무력화할 때 극우 세력이 즐겨 쓰는 논리와 동일해 위안부 피해자 모독 논란이 폭발했다. 당시 일본 수출규제 불매운동이 한창이던 시기와 맞물려 더욱 증폭됐다.', '일본군_위안부_성노예_강제_동원', '["https://www.hankookilbo.com/News/Read/201910181447328960", "https://www.ytn.co.kr/_ln/0103_201910211245470928"]', '유니클로는 2019년 10월 후리스 출시 25주년 기념 광고에서 "80년도 더 된 일을 어떻게 기억하냐"는 문구를 한국판에 추가해 위안부 피해자 조롱 논란에 휘말렸다. 이 문구는 일본군 위안부 피해자들의 증언을 무력화하는 극우 세력의 논리와 유사하다는 비판을 받았다. 유니클로는 광고의 의도가 세대 간 나이 차이를 부각하기 위한 것이라며 정치적 의도는 없다고 해명했으나, 논란이 커지자 광고 송출을 중단했다. 전문가들은 광고주인 유니클로의 책임이 크다고 지적하며, 이번 사건이 일본 불매운동에 다시 불을 지필 것이라는 우려가 제기되었다.', '[-0.024139404,0.0078086853,-0.031051636,0.033691406,0.003376007,-0.013259888,-0.021255493,0.030090332,-0.022720337,0.0048942566,0.012107849,-0.023483276,-0.039367676,-0.055633545,-0.0006327629,0.006629944,-0.081604004,-0.029205322,-0.028167725,-0.014427185,0.045043945,0.011054993,-0.0036449432,0.030517578,0.039520264,-0.003730774,0.012435913,0.019424438,0.05114746,-0.014984131,-0.02355957,-0.020233154,0.006542206,-0.028457642,0.008094788,-0.0010738373,0.039642334,-0.005634308,0.034820557,-0.009353638,0.07116699,-0.010322571,0.038970947,-0.00081443787,0.019256592,0.03375244,-0.019226074,0.05126953,0.03955078,0.035614014,0.0002799034,0.06744385,-0.022262573,0.005908966,0.010787964,-0.0051498413,-0.0014419556,-0.01739502,0.00566864,-0.028060913,-0.00056028366,-0.061706543,-0.0004632473,-0.0004284382,-0.031707764,-0.031280518,-0.001408577,0.03488159,-0.026229858,-0.004886627,0.045135498,0.0070877075,0.037353516,0.0030670166,-0.020141602,0.011543274,0.023284912,0.032287598,0.040039062,-0.06549072,0.005092621,0.01525116,-0.04876709,0.04623413,-0.025253296,0.032714844,-0.031188965,-0.018341064,-0.014335632,0