INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-005', 'KR', 'GENDER', '서울우유 유기농 우유 ''여성=젖소'' 광고 논란', '2021-11-29', '2021년 11월 29일 서울우유가 유기농 우유를 홍보하기 위해 남성이 몰래 카메라로 여성들을 촬영하다가 나뭇가지를 밟는 순간 여성들이 젖소로 변하는 영상 광고를 유튜브에 공개했다. 여성을 젖소에 비유한 성차별적 묘사와 불법촬영 연상 장면이 비판받았다. BBC 등 외신에도 보도됐다.', '성별_고정관념_및_성차별', '["https://cm.asiae.co.kr/article/2021120908135578568", "https://news.mt.co.kr/mtview.php?no=2021120816444370055", "https://www.seoul.co.kr/news/newsView.php?id=20211215500207"]', '2021년 11월 29일, 서울우유는 유기농 우유를 홍보하는 광고를 유튜브에 공개했다. 이 광고에서 한 남성이 여성들을 몰래 촬영하다가 나뭇가지를 밟고, 여성들이 젖소로 변하는 장면이 포함되어 있어 성차별적이라는 비판을 받았다. 비판이 커지자 서울우유는 12월 8일 공식 홈페이지에 사과문을 게재하고 광고를 비공식으로 전환했다. 이후 이 광고는 BBC 등 외신에서도 보도되며 논란이 확산되었다.', '[0.052856445,0.020843506,-0.05618286,0.070495605,-0.051452637,-0.017944336,-0.029785156,-0.0107040405,0.0078125,-0.026672363,0.03552246,-0.0061912537,-0.026687622,-0.016159058,0.010368347,-0.0068092346,-0.026016235,-0.0012569427,-0.022613525,0.0034885406,-0.013473511,0.0024166107,-0.008964539,0.0053710938,-0.0070877075,-0.007835388,0.010856628,-0.00484848,-0.020889282,0.030044556,-0.004310608,-0.022247314,0.022735596,-0.027450562,-0.037200928,-0.025314331,0.015098572,-0.008964539,0.05706787,-0.03451538,0.021881104,0.0012016296,0.0020656586,-0.06298828,0.02192688,0.107299805,-0.02355957,0.01663208,0.013496399,-0.0064849854,-0.015823364,0.06274414,0.0030460358,-0.021224976,0.009819031,-0.0056762695,-0.044006348,-0.012397766,0.02355957,-0.020950317,0.046569824,-0.020263672,0.017974854,0.054107666,-0.0055122375,-0.04949951,0.022262573,0.010787964,-0.039245605,0.009590149,0.09643555,-0.03149414,0.013290405,0.014007568,0.0022659302,0.025253296,-0.014846802,0.005508423,-0.0030212402,-0.062805176,0.002855301,0.05078125,-0.038513184,0.03286743,-0.030975342,0.016067505,-0.060028076,0.02720642,-0.018707275,0.05886841,-0.056549072,0.054779053,-0.021102905,-0.0014390945,-0.008201599,0.01934