INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-006', 'KR', 'GENDER', 'GS25 편의점 ''캠핑가자'' 포스터 집게손가락 남혐 논란', '2021-05-01', '2021년 5월 GS25 편의점이 캠핑 프로모션 포스터에서 소시지를 집는 손 모양 이미지가 메갈리아의 남성 신체 비하 제스처와 유사하다는 논란이 폭발했다. 조윤성 GS리테일 사장이 직접 사과하고, 청와대 국민청원까지 등장했으며, BBQ·무신사·교촌·카카오뱅크 등 업계 전반으로 ''손가락 주의보''가 확산됐다.', '온라인_젠더갈등_및_손모양_기호_논쟁', '["https://news.nate.com/view/20210526n28197"]', '2021년 5월, GS25 편의점의 캠핑 프로모션 포스터에서 소시지를 집는 손 모양이 메갈리아의 남성 신체 비하 제스처와 유사하다는 논란이 일어났다. 조윤성 GS리테일 사장은 사과했으며, 청와대 국민청원도 등장했다. 이후 랭킹닭컴, BBQ, 농심 등 다른 업체들도 손 모양 이미지로 남혐 논란에 휘말렸고, 이들 업체는 해당 이미지를 수정하거나 삭제했다. 업계 전반에 ''손가락 주의보''가 내려졌으며, 일부 소비자들은 손가락 사용에 대한 우려를 표명했다.', '[0.047302246,0.029785156,-0.02734375,0.014434814,-0.002571106,-0.040222168,-0.042297363,-0.0018634796,0.019943237,-0.07757568,0.0074691772,-0.04748535,-0.0069618225,-0.034729004,-0.012382507,-0.037872314,-0.023010254,-0.06567383,-0.03314209,0.00566864,0.029159546,0.05230713,0.019561768,0.0053977966,0.0056762695,0.085510254,0.0074691772,0.01260376,0.028762817,0.011505127,0.0030174255,-0.00831604,0.024978638,-0.05908203,-0.020401001,0.0045166016,-0.00028395653,0.0020313263,0.05569458,-0.014968872,0.0071907043,0.040405273,-0.007888794,-0.020507812,0.051879883,0.038269043,0.00028800964,-0.007347107,0.02458191,0.024459839,-0.01108551,0.059631348,0.058624268,-0.011367798,-0.047454834,-0.04626465,-0.03390503,-0.033172607,0.0085372925,0.011276245,0.06506348,-0.047454834,-0.064453125,0.04626465,-0.004299164,-0.036376953,0.043182373,0.04031372,-0.049804688,-0.0262146,0.03894043,0.017196655,0.0033283234,0.021347046,-0.0026340485,-0.020721436,-0.021331787,0.010139465,0.05206299,-0.03173828,-0.039001465,0.022079468,-0.012359619,0.01222229,-0.0064086914,-0.0018844604,-0.074523926,-0.0014715195,-0.02003479,0.000323534,-0.022247314,0.031555176,0.017990112,-0.01966858,-0.00064373016,-0.030014038,0.028762817,0.013366699,0.023117065,0.018356323,0.026748657,-0.0293