INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-008', 'KR', 'GENDER', '넥슨 메이플스토리 ''엔젤릭버스터'' 홍보영상 집게손가락 남혐 논란', '2023-11-26', '2023년 11월 넥슨 메이플스토리의 엔젤릭버스터 리마스터 홍보 애니메이션에서 0.1초 동안 캐릭터가 메갈리아 상징 손가락 제스처를 취한다는 의혹이 제기됐다. 외주 제작사 ''스튜디오 뿌리'' 소속 작가의 페미니즘 SNS 글이 발견되며 논란이 증폭됐다. 넥슨은 새벽 직원 호출로 프레임 단위 검수를 진행하고 전 영상을 비공개 처리했다.', '온라인_젠더갈등_및_손모양_기호_논쟁', '["https://m.khan.co.kr/national/national-general/article/202311301534001"]', '2023년 11월, 넥슨 메이플스토리의 ''엔젤릭버스터'' 리마스터 홍보 애니메이션에서 캐릭터가 0.1초 동안 메갈리아 상징 손가락 제스처를 취한 의혹이 제기됐다. 이와 함께 외주 제작사 ''스튜디오 뿌리'' 소속 작가의 페미니즘 관련 SNS 글이 발견되며 논란이 확산되었다. 넥슨은 새벽에 직원들을 호출해 프레임 단위로 검수를 진행하고, 해당 영상을 비공개 처리했다.', '[0.03543091,0.03036499,-0.032806396,0.011993408,-0.0012102127,-0.03967285,0.041412354,0.048919678,0.0050468445,-0.033569336,-0.018341064,-0.004508972,-0.033843994,-0.021331787,-0.027633667,-0.015213013,0.0036907196,-0.064575195,-0.040924072,0.021865845,-0.012702942,0.046936035,0.0073051453,-0.0473938,0.01966858,0.0075187683,0.026641846,-0.015007019,0.0030517578,0.010772705,-0.0078125,-0.010925293,0.044525146,-0.023620605,-0.006587982,-0.00945282,-0.019332886,-0.017822266,-0.0035991669,0.021011353,-0.0052948,0.021347046,-0.011375427,-0.0021800995,0.0050468445,0.03918457,-0.0118637085,0.0063056946,0.07116699,0.05441284,-0.007926941,0.07305908,0.032684326,0.017456055,-0.013465881,0.012626648,-0.016311646,-0.06713867,-0.01739502,0.008308411,0.060638428,-0.074645996,-0.026275635,0.0016746521,-0.005706787,-0.06161499,-0.021942139,0.026626587,-0.04586792,0.010444641,0.053344727,-0.02619934,0.01083374,0.0073928833,-0.042785645,-0.011978149,-0.0440979,0.013244629,0.027557373,-0.019195557,0.016189575,0.025878906,-0.007282257,0.014572144,-0.028930664,0.040802002,-0.06100464,-0.061950684,-0.037963867,0.031082153,-0.04272461,0.052978516,0.03656006,0.023468018,0.045837402,-0.05529785,0.012870789,-0.026107788,0.03717041,0.045837402,-0.0020866394,-0.00459671,-0.