INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-009', 'KR', 'GENDER', '무신사 메갈리아 손모양 홍보물(초코송이 콜라보) 논란', '2019-07-01', '무신사가 오리온 초코송이와 콜라보 시 화이트 초코송이가 원래의 양 손 V자 포즈 대신 메갈리아의 상징적 손 모양으로 바뀐 정황이 포착됐다. 무신사가 매크로 답변으로 일관하면서 논란이 지속됐고, 탁치니억 광고 논란과 함께 불거지며 창업자 조만호 대표가 대표이사직에서 물러나는 계기가 됐다.', '온라인_젠더갈등_및_손모양_기호_논쟁', '["https://namu.wiki/w/%EB%AC%B4%EC%8B%A0%EC%82%AC/%EB%85%BC%EB%9E%80%20%EB%B0%8F%20%EC%82%AC%EA%B1%B4%20%EC%82%AC%EA%B3%A0", "https://www.news1.kr/industry/distribution/4286294#_enliple"]', '무신사는 오리온 초코송이와의 콜라보 제품인 화이트 초코송이에서 손 모양이 메갈리아의 상징적 손 모양으로 변경된 사실이 확인됐다. 이로 인해 논란이 발생하였고, 무신사는 매크로 답변으로 일관하면서 문제를 해결하지 못했다. 이와 함께 탁치니억 광고 논란이 불거지면서 창업자 조만호 대표가 대표이사직에서 물러나는 계기가 되었다.', '[0.07299805,0.026397705,-0.04083252,0.031433105,-0.00068950653,-0.008995056,0.014831543,-0.008628845,-0.020141602,-0.06604004,-0.0137786865,-0.021347046,-0.021453857,0.010391235,-0.018218994,-0.007785797,-0.036468506,-0.0703125,0.008811951,0.012184143,-0.04336548,-0.0030536652,0.026306152,-0.026977539,-0.0055122375,0.062805176,0.007358551,-0.019500732,0.03390503,0.043762207,-0.03173828,-0.008506775,0.046020508,-0.04156494,-0.032165527,-0.0027122498,-0.018661499,-5.9247017e-05,0.031982422,-0.010299683,-0.039123535,0.0021305084,-0.002872467,0.000869751,0.06237793,0.015640259,0.0041885376,-0.0013227463,0.0496521,0.015945435,0.0051612854,0.06640625,0.015686035,0.01953125,-0.021331787,0.03778076,-0.0068740845,-0.064331055,-0.02204895,-0.00522995,0.006465912,-0.03829956,-0.011695862,-0.0019950867,-0.0059890747,-0.0075416565,-0.0154800415,-0.011619568,-0.013053894,0.013420105,0.02482605,-0.04067993,0.0368042,0.04345703,-0.004169464,-0.058288574,0.023239136,0.017944336,0.029510498,0.051086426,-0.021743774,0.045410156,0.032196045,0.032958984,-0.002155304,0.055267334,-0.06573486,-0.034576416,-0.053955078,0.02078247,-0.018569946,0.02986145,0.0013113022,0.0049095154,0.011398315,-0.070129395,0.008872986,0.01