INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-010', 'KR', 'HISTORY', 'SBS 런닝맨·비디오머그 ''탁 치니 억'' 밈 무분별 사용 논란', '2019-01-01', 'SBS 예능 런닝맨 및 비디오머그 채널이 ''책상을 탁 치니 억 하고''라는 표현을 오락성 밈처럼 광고·콘텐츠에 사용했다. 이는 1987년 박종철 열사 고문치사 사건 당시 경찰의 은폐 발언을 패러디한 것으로, 심각한 역사적 사건을 가볍게 소비했다는 비판이 2026년 스타벅스 탱크데이 논란이 불거지면서 재소환됐다.', '고문_조작_의혹_국가_권력_남용', '["https://namu.wiki/w/%ED%95%9C%EA%B5%AD%20%EC%8A%A4%ED%83%80%EB%B2%85%EC%8A%A4%20%ED%83%B1%ED%81%AC%EB%8D%B0%EC%9D%B4%20%EC%9D%B4%EB%B2%A4%ED%8A%B8%20%EB%85%BC%EB%9E%80/%ED%9B%84%EC%86%8D%20%EB%85%BC%EB%9E%80", "https://www.yna.co.kr/view/AKR20190603168600005"]', 'SBS 예능 ''런닝맨''과 비디오머그 채널이 ''탁 치니 억''이라는 표현을 광고 및 콘텐츠에 사용해 논란이 일었다. 이 표현은 1987년 박종철 열사 고문치사 사건 당시 경찰의 은폐 발언을 패러디한 것으로, 역사적 사건을 가볍게 소비했다는 비판이 제기되었다. ''런닝맨'' 제작진은 해당 자막 사용에 대해 의도는 없었다고 해명하며, 불편함을 느낀 시청자들에게 주의하겠다고 밝혔다. 이 논란은 2026년 스타벅스 탱크데이 사건과 함께 재조명되었다.', '[0.062927246,0.02017212,-0.040740967,-0.019363403,0.014167786,0.00019466877,-0.010131836,0.010040283,-0.04196167,-0.026931763,0.0073776245,-0.012519836,-0.0057868958,-0.0008597374,0.0021533966,-0.024047852,0.0026302338,-0.024337769,-0.011726379,0.0019264221,0.011222839,0.029678345,-0.026260376,0.006591797,0.018173218,-0.020523071,0.03289795,0.03869629,0.034179688,0.061645508,-0.03414917,-0.008491516,0.012062073,-0.08477783,-0.0057907104,0.0038280487,-0.014823914,-5.120039e-05,0.0062065125,-0.0095825195,-0.01499176,-0.0047912598,-0.045318604,0.029800415,0.0625,0.017974854,-0.0055122375,0.037994385,0.02708435,0.054779053,-0.014762878,0.07092285,-0.018798828,-0.041229248,0.059448242,0.040649414,-0.058746338,-0.042297363,-0.04196167,-0.04940796,0.047546387,-0.054107666,-0.030273438,0.058258057,-0.02268982,-0.03253174,-0.012893677,0.038360596,-0.020614624,0.0395813,-0.0057754517,-0.011001587,0.008682251,0.045715332,0.015930176,0.03427124,-0.029632568,0.066101074,0.022140503,-0.03591919,0.03149414,0.013145447,-0.037750244,0.06707764,-0.01