INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-011', 'KR', 'HISTORY', 'KIA 타이거즈 한준수 ''탱크 나가신다'' SNS 게시글 논란', '2021-05-18', '2021년 5월 18일 5·18 민주화운동 기념일, 광주 KIA 타이거즈 소속 포수 한준수가 개인 SNS에 자신의 대형 자동차를 자랑하며 ''탱크 나가신다''는 표현을 사용해 논란이 됐다. 기념일 당일 탱크 표현 사용에 대한 경각심을 일깨운 사례다.', '계엄군_민간인_학살', '["https://namu.wiki/w/%ED%95%9C%EA%B5%AD%20%EC%8A%A4%ED%83%80%EB%B2%85%EC%8A%A4%20%ED%83%B1%ED%81%AC%EB%8D%B0%EC%9D%B4%20%EC%9D%B4%EB%B2%A4%ED%8A%B8%20%EB%85%BC%EB%9E%80", "https://www.joongang.co.kr/article/24061308"]', 'KIA 타이거즈 소속 포수 한준수가 2021년 5월 18일 5·18 민주화운동 기념일에 자신의 SUV 사진과 함께 "탱크 나가신다"는 게시물을 올려 논란이 일었다. 이 게시물은 광주에서 민주화를 위해 싸운 역사적 사건과 관련해 부적절하다는 비판을 받았다. 팬들은 그의 행동에 대해 강한 반발을 보였고, 한준수는 이후 사과문을 게시하며 "5·18을 잠시나마 생각하지 못한 점을 반성하고 있다"고 밝혔다. KIA 타이거즈는 같은 날 신인 투수 이의리의 응원 이벤트를 연기하기로 결정했다.', '[0.016235352,-0.030426025,-0.053100586,0.020599365,0.05895996,-0.062408447,-0.038269043,0.046691895,-0.0077171326,-0.050872803,0.016921997,-0.018417358,-0.02305603,-0.027694702,0.03186035,-0.03540039,-0.052612305,-0.031143188,7.593632e-05,0.007408142,-0.002565384,0.05203247,0.008338928,0.020477295,0.0036201477,-0.0048179626,0.00040340424,-0.008140564,-0.00075769424,-0.0034980774,-0.068725586,-0.0030918121,0.010803223,-0.037506104,-0.004245758,0.0055732727,0.037139893,-0.025177002,0.026885986,-0.03024292,0.00063562393,-0.021896362,0.025741577,0.025436401,0.0181427,-0.0007338524,0.016021729,-0.034423828,0.0069007874,0.014038086,0.022628784,0.00944519,-0.017074585,-0.00037121773,-0.021636963,0.008018494,-0.017288208,0.009819031,0.003660202,-0.015403748,-0.022277832,-0.026412964,-0.06439209,0.0022296906,0.033233643,-0.046325684,0.041534424,0.0033187866,-0.059783936,0.027557373,0.009590149,0.041778564,-0.016357422,-0.014144897,0.018707275,0.0023078918,-0.011543274,0.045837402,0.020431519,0.015548706,0.05215454,0.034301758,-0.03994751,0.015945435,-0.054534912,-0.016647339,-0.07183838,-0.04272461,-0.0228576