INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-012', 'KR', 'DISASTER', '대한항공 ''비행기 사고로 사망한 가수 음악'' 광고 BGM 논란', '1985-01-01', '1985년 대한항공이 ''Welcome to My World''를 BGM으로 사용했는데, 원곡자 짐 리브스(Jim Reeves)가 1964년 비행기 사고로 사망한 인물이었다. 항공사 광고에 비행기 사고 사망자의 ''제 세계로 어서오세요'' 노래를 쓴 것이 불길하다는 논란이 일었다. 공교롭게도 해당 광고에 등장한 비행기가 12년 뒤 대형 참사의 당사자가 됐다.', '항공사고_인명_피해', '["https://namu.wiki/w/%EC%9E%98%EB%AA%BB%20%EC%84%A0%EC%A0%95%ED%95%9C%20%EA%B4%91%EA%B3%A0%20BGM"]', '대한항공은 1985년 광고에서 짐 리브스의 ''Welcome to My World''를 BGM으로 사용했다. 그러나 짐 리브스는 1964년 비행기 사고로 사망한 인물로, 이로 인해 광고에 사용된 음악의 선정이 부적절하다는 논란이 일었다. 해당 광고에 등장한 비행기는 12년 후 대형 참사의 당사자가 되기도 했다. 이러한 사례는 광고 음악 선정에서 가사나 원작자의 배경을 고려하지 않아 발생하는 문제로 지적되고 있다.', '[-0.015281677,0.016036987,-0.00023627281,-0.021621704,-0.01927185,-0.011650085,-0.024108887,0.02355957,-0.0067749023,-0.012428284,-0.0051727295,0.0003709793,-0.0068359375,-0.011062622,-0.008529663,0.015090942,-0.052825928,0.0071640015,0.018310547,-0.032562256,0.025787354,-0.015510559,-0.043395996,-0.008087158,-0.0040016174,0.0020256042,0.03074646,0.028945923,0.05493164,-0.04449463,-0.006046295,-0.02420044,0.008049011,-0.0071792603,-0.042388916,-0.02029419,0.021697998,-0.029647827,-0.016235352,-0.043640137,0.034210205,0.0036201477,0.019119263,0.0058174133,-0.027770996,0.023117065,-0.05307007,-0.011604309,0.083618164,0.011306763,-0.015151978,0.029571533,-0.029190063,0.0016536713,0.036193848,-0.005531311,-0.0034275055,0.03741455,0.021896362,-0.020904541,0.00831604,-0.04449463,-0.058441162,-0.021087646,-0.034576416,-0.048736572,0.017059326,0.049804688,-0.06088257,0.0131073,0.033081055,0.034362793,0.010749817,-0.0035972595,-0.042663574,0.027893066,0.022613525,0.008033752,-0.025466919,-0.07421875,0.014007568,-0.00894928,-0.040649414,0.037506104,-0.03652954,0.02128601,-0.080444336,-0.028564453,0.0340271,0.05493164,-0.05557251,0.013961792,0.010498047,-0.002439499,0.007850647,0.017028809,0.018692017,