INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-013', 'KR', 'GENDER', '서울우유 2003년 인사동 누드 퍼포먼스 홍보 사건', '2003-01-01', '2003년 1월 서울우유가 인사동 화랑에서 신제품 홍보 행사를 진행하면서 전라의 여성 누드모델 3명을 출연시켜 분무기로 우유 등을 뿌리는 퍼포먼스로 사회적 물의를 일으켰다. 광고 담당 직원이 공연음란 혐의로 벌금형을 선고받았으며, 2021년 젖소=여성 광고 논란 때 함께 재소환됐다.', '성별_고정관념_및_성차별', '["https://www.salgoonews.com/news/articleView.html?idxno=13057"]', '2003년 1월 서울우유는 인사동에서 신제품 홍보 행사 중 전라의 여성 누드모델 3명을 출연시켜 우유를 뿌리는 퍼포먼스를 진행해 사회적 물의를 일으켰다. 이 사건으로 광고 담당 직원은 공연음란 혐의로 벌금형을 선고받았다. 2021년 서울우유의 광고가 여성을 젖소에 비유한 내용으로 논란이 일자, 과거 누드 퍼포먼스 사건이 재조명되었다. 서울우유는 해당 광고가 여성혐오 의도가 없다고 해명했으나, 비판이 이어지며 광고 영상은 비공개 처리되었다.', '[0.0007915497,0.018737793,-0.004196167,0.031280518,-0.015975952,-0.07525635,-0.036102295,0.051239014,0.004711151,-0.028686523,0.010528564,0.004676819,-0.046325684,-0.018295288,-0.0043258667,-0.0023422241,-0.010559082,-0.041503906,-0.0053138733,0.016098022,0.012924194,0.015083313,-0.015899658,-0.027236938,-0.0019006729,-0.006416321,-0.004234314,0.022750854,0.045928955,-0.0015258789,0.006500244,-0.015617371,0.008285522,0.011146545,-0.037902832,-0.012466431,-0.017150879,-0.03982544,0.040863037,-0.012504578,-0.0033073425,-0.0054397583,0.0029964447,-0.04043579,0.021942139,0.08068848,0.0022735596,0.0287323,0.023742676,0.049926758,0.021957397,0.06878662,0.043121338,-0.012001038,-0.03387451,0.01687622,-0.01108551,-0.010002136,-0.034301758,-0.012763977,0.05038452,-0.010498047,0.016601562,0.02166748,-0.017852783,-0.04840088,-0.0029239655,-0.011543274,-0.033691406,-0.015823364,0.10253906,0.014137268,0.027252197,0.0012235641,-0.01612854,0.020935059,0.0076293945,-0.013175964,-0.044189453,-0.025924683,0.013290405,0.034454346,-0.041900635,0.008934021,-0.045928955,0.0072402954,-0.03086853,-0.0012130737,-0.071899414,0.044036865,-0.05606079,0.050598145,0.02243042,0.04019165,-0.0038280487,-0.008270264,-0.014144897,-0.025939941,0.060638428,0.03866577,0.0054397583,0.011047363,0.00