INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-015', 'KR', 'GENDER', 'YES24 ''어쩌면 그렇게 한(국)남(자)스럽니?'' 도서 마케팅 논란', '2018-12-01', '2018년 12월 온라인 서점 YES24가 ''(광고) 어쩌면 그렇게 한(국)남(자)스럽니?''라는 제목의 이메일로 도서 ''한국 남자''를 홍보해 논란이 발생했다. ''한남''이라는 남성 비하 표현을 광고 제목에 노골적으로 사용한 것이 문제가 됐다. YES24는 사과문을 게재했으나 숨긴 위치에 공지해 ''4과문''이라는 비아냥을 들었고, 불매운동과 탈퇴자 급증이 이어졌다.', '온라인_젠더갈등_및_손모양_기호_논쟁', '["https://namu.wiki/w/YES24%20%ED%95%9C%EA%B5%AD%20%EB%82%A8%EC%84%B1%20%EB%B9%84%ED%95%98%20%EB%A7%88%EC%BC%80%ED%8C%85%20%EC%82%AC%EA%B1%B4", "https://www.joongang.co.kr/article/23175062"]', '2018년 12월, 온라인 서점 YES24가 ''(광고) 어쩌면 그렇게 한(국)남(자)스럽니?''라는 제목의 이메일로 도서 ''한국 남자''를 홍보하면서 논란이 일어났다. ''한남''이라는 남성 비하 표현이 사용된 것이 문제로 지적되었고, 이에 대한 비판이 이어졌다. YES24는 12월 3일 사과문을 게시했으나, 사과문이 숨겨진 위치에 있어 비아냥을 받았고, 회원 탈퇴자가 급증했다. 이후 YES24는 비판 댓글을 검열하는 정황이 드러나며 논란이 더욱 확산되었다.', '[0.035339355,0.057891846,-0.008766174,0.038085938,-0.006038666,-0.07714844,-0.018310547,-0.007171631,0.011459351,-0.02659607,0.02015686,0.012321472,-0.008285522,0.04901123,0.01322937,-0.023269653,-0.014785767,-0.005924225,-0.031021118,0.002357483,0.059143066,0.0071372986,-0.008323669,-0.025115967,-0.04449463,0.044006348,0.00062179565,-0.015411377,0.032989502,0.018127441,-0.013961792,-0.035125732,0.04144287,-0.08996582,0.01423645,0.003063202,-0.0023765564,-0.03060913,-0.008918762,-0.073913574,-0.009338379,-0.016036987,0.0014362335,-0.05899048,0.048187256,0.048858643,-0.001613617,-0.008956909,0.045318604,0.042877197,-0.025665283,0.04058838,0.0038814545,0.043151855,0.025115967,-0.03756714,-0.011756897,-0.004333496,-0.012458801,-0.0068969727,0.05606079,-0.03781128,-0.0418396,0.083984375,0.020507812,-0.030853271,0.010246277,-0.004196167,-0.044647217,-0.004196167,0.058654785,-0.0012407303,0.048187256,0.027420044,-0.010734558,-0.00078487396,-0.030960083,0.022644043,-0.013893127,0.021514893,0.025161743,0.026855469,-0.02822876,0.031829834,0.02267456,-0.0054512024