INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-014', 'KR', 'GENDER', '동아제약 인사팀 채용 공고 ''여혐'' 논란', '2021-05-01', '2021년 동아제약 인사팀장이 채용 과정에서 여성 지원자에게 부적절한 외모 관련 언급을 했다는 논란이 불거졌다. 동아제약은 해당 인사팀장을 보직해임하고 대표이사까지 직접 사과에 나섰지만, 불매운동 움직임으로 이어지는 등 논란이 지속됐다.', '성별_고정관념_및_성차별', '["https://www.straightnews.co.kr/news/articleView.html?idxno=105360"]', '2021년 동아제약 인사팀장이 여성 지원자에게 부적절한 외모 관련 질문을 한 사건이 논란이 되었다. 해당 인사팀장은 보직해임되었고, 동아제약 대표이사가 직접 사과했다. 그러나 이 사건은 불매운동으로 이어지며 논란이 지속되고 있다. 유통업계는 젠더 갈등으로 인한 이미지 손상을 우려하며, 관련 논란을 방지하기 위해 더욱 주의하고 있는 상황이다.', '[-0.0029697418,0.03982544,0.023544312,0.06188965,0.033355713,-0.018371582,-0.032806396,0.01474762,0.032684326,-0.017120361,0.039642334,0.0012550354,-0.06536865,0.025253296,-0.0143966675,0.02168274,-0.0029792786,-0.038848877,-0.036071777,0.016677856,0.0068206787,0.042877197,-0.028396606,0.029083252,0.0062675476,-0.018081665,0.013343811,-0.02192688,0.03286743,-0.027618408,0.047576904,-0.011245728,0.03427124,-0.017623901,0.008460999,0.03213501,0.0071258545,0.0054359436,0.0016355515,-0.03503418,0.0013523102,-0.018157959,0.04034424,-0.007171631,-0.02784729,0.056915283,0.030731201,0.032684326,0.03253174,0.015808105,-0.010665894,0.06817627,0.014320374,0.047729492,0.007171631,0.0041923523,0.009933472,0.009262085,-0.013923645,0.022506714,0.016983032,0.0054092407,-0.019119263,0.018981934,-0.0446167,-0.026428223,-0.0066070557,0.033355713,-0.008705139,0.03643799,0.054351807,0.0063819885,0.01777649,0.010017395,0.0022182465,-0.015220642,0.006374359,0.04043579,-0.03250122,-0.012863159,-0.007499695,0.05831909,-0.048583984,0.039794922,0.0010948181,-0.008636475,-0.06390381,-0.022445679,-0.0040397644,-0.029037476,-0.0579834,0.079956055,-0.00083875656,0.005142212,-0.0046920776,-0.02684021,-0.0049743652,0.0037899017,0.034484863,0.029327393,0.005130768,-0.025543213,-0.0014781952,0.009384155,0.01663208,-0.027175903,-0.053375244,-0.009391785,0.007183075,-0.005256