INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-016', 'KR', 'GENDER', '넥슨 클로저스 성우 김자연 메갈리아 지지 티셔츠 논란', '2016-07-18', '2016년 7월 넥슨 게임 클로저스의 신규 캐릭터 성우 김자연이 메갈리아4 후원 티셔츠를 입은 사진을 SNS에 게시해 남성 게임 유저들의 반발이 폭발했다. 넥슨은 업데이트를 며칠 앞두고 성우를 교체했다. 게임업계 최초의 대규모 페미니즘 관련 광고·마케팅 논란으로 이후 수많은 게임사 유사 사건의 원형이 됐다.', '온라인_젠더갈등_및_손모양_기호_논쟁', '["https://www.ngetnews.com/news/articleView.html?idxno=427512"]', '2016년 7월, 넥슨의 게임 클로저스 성우 김자연이 메갈리아4 후원 티셔츠를 입은 사진을 SNS에 게시해 남성 게임 유저들의 반발을 샀다. 넥슨은 성우 교체를 결정하며 "논란이 되고 있는 사안에 대해 유저들의 우려를 확인했다"고 밝혔다. 2023년 11월, 넥슨은 메이플스토리의 홍보물에서 남성혐오 제스처가 포함된 것에 대해 사과하며 해당 영상을 비공개 처리했다. 게임업계 전반에서 남성혐오 논란이 재조명되며, 여러 게임사들이 자진 검토에 나섰다.', '[-0.009521484,0.028823853,-0.033599854,0.032836914,-0.018157959,-0.026168823,0.041931152,0.050476074,-0.005821228,-0.00983429,0.019500732,-6.914139e-06,-0.049102783,-0.02784729,-0.01953125,0.01713562,-0.03640747,-0.037597656,-0.03439331,0.0113220215,0.021484375,0.034729004,-0.008804321,-0.015930176,0.027694702,0.043548584,0.0018053055,-0.034973145,-0.038208008,0.022018433,-0.044128418,-0.026062012,0.014266968,-0.0234375,0.025283813,-0.013267517,-0.049987793,-0.0031642914,0.0082473755,0.008605957,-0.029678345,-0.03652954,-0.0259552,0.03704834,-0.026809692,0.013710022,-0.04208374,-0.010635376,0.012481689,0.019180298,0.032196045,0.061676025,0.009849548,0.019256592,0.029251099,-0.011528015,0.0146102905,-0.033294678,0.02909851,0.02027893,0.042938232,-0.0011854172,-0.02243042,0.01940918,-0.039642334,-0.059661865,0.012168884,-0.030319214,-0.027053833,0.029525757,0.052215576,0.0067214966,0.013038635,0.01008606,-0.003068924,-0.009796143,-0.014266968,-0.030838013,0.039215088,-0.002418518,-0.008613586,0.015670776,0.010856628,0.02281189,-0.03173828,-0.016906738,-0.06744385,-0.0047569275,-0.011894226,0.04437256,-0.042816162,0.02432251,-0.026565552,0.022949219,0.0002002716,-0.021484375,0.006160736,-0.0050697327,0.04510498,0.03479004,0.001335144,-0.0