INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-018', 'KR', 'GENDER', 'MLB 코리아 모자 광고 여성 외모(쌩얼) 성차별 논란', '2022-04-01', '스트리트 캐주얼 브랜드 MLB 코리아가 여성 모델의 민낯(쌩얼) 이미지를 활용한 모자 광고를 선보여 여성의 외모를 상품화했다는 성차별 논란이 일었다. 결국 광고 게시를 자진 중단했다.', '성별_고정관념_및_성차별', '["https://www.iconsumer.or.kr/news/articleView.html?idxno=25294"]', '스트리트 캐주얼 브랜드 MLB 코리아가 여성 모델의 민낯 이미지를 활용한 모자 광고를 선보였고, 이로 인해 여성의 외모를 상품화했다는 성차별 논란이 일어났다. 소비자들의 반발이 커지자 MLB 코리아는 광고 게시를 자진 중단했다. 이 사건은 광고의 윤리적 쟁점과 함께 소비자 의식의 변화를 보여주는 사례로 언급되었다.', '[-0.004173279,0.03137207,-0.008384705,0.044006348,-0.029312134,0.005382538,0.003929138,-0.0435791,-0.020568848,-0.060516357,-0.008102417,-0.026321411,-0.022598267,0.01322937,0.014564514,-0.026107788,-0.0048828125,-0.0045166016,-0.013870239,0.037231445,0.012641907,0.041534424,-0.038391113,-0.014717102,0.022750854,0.06530762,-0.011993408,-0.03881836,0.0067481995,0.033599854,-0.024551392,-0.023834229,0.01586914,-0.07543945,-0.012496948,0.025634766,0.03060913,-0.0084991455,0.05078125,-0.013938904,-0.018447876,-0.015060425,0.05126953,0.01007843,-0.0068855286,0.06201172,0.008544922,0.0064048767,0.027069092,0.0015277863,-0.03050232,0.01322937,0.033355713,0.013450623,-0.027008057,-0.026992798,0.013969421,0.0018520355,0.04751587,-0.00018405914,-0.029953003,-0.059906006,-0.0052337646,0.0053215027,-0.030471802,-0.04046631,-0.029708862,0.004131317,-0.058563232,0.011604309,0.016159058,-0.055877686,0.034973145,0.022109985,0.00868988,-0.0038032532,-0.00059890747,0.035888672,0.036071777,0.013137817,-0.033294678,0.06011963,0.013557434,0.06149292,-0.032714844,0.010635376,-0.05368042,-0.019744873,-0.027511597,0.030548096,-0.06890869,0.024734497,0.0024909973,0.025421143,0.015434265,0.017456055,-0.04119873,-0.0015468597,0.06274414,0.054870605,-0.02128601,-0.041168213,0.006389618,0.041412354,-0.0005288124,-0.038635254,-0.009422302,0.03161621,0.027297974,-0.025909424,0.015838623,0.027008057,-0.037750244,