INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-019', 'KR', 'GENDER', '삼성전자 싱가포르 성소수자 광고 논란 (이슬람권 맥락)', '2022-01-01', '삼성전자가 싱가포르에서 성소수자에 대한 편견을 깨자는 메시지를 담은 광고를 제작해 방영했으나, 이슬람교도 비율이 높은 싱가포르 정서와 충돌했다. 결국 광고를 내렸는데, 이번에는 성소수자 인권단체들이 보수주의자들 반발에 굴복했다고 역풍을 쏟았다. 지역사회 문화 맥락을 고려하지 않은 광고 기획 실패 사례로 꼽힌다.', '이슬람_라마단_금식월', '["https://www.greened.kr/news/articleView.html?idxno=295564"]', '삼성전자는 2022년 1월 싱가포르에서 성소수자에 대한 편견을 깨자는 메시지를 담은 광고를 방영했으나, 이슬람교도 비율이 높은 지역 정서와 충돌하여 강한 반발을 받았다. 광고는 즉시 삭제되었고, 삼성은 지역사회에 무신경한 점을 인정하며 사과했다. 이후 성소수자 인권단체로부터 보수주의자들의 반발에 굴복했다는 비판을 받았다. 이 사건은 지역문화와 사회적 배경을 고려하지 않은 광고 기획의 실패 사례로 지적되었다.', '[0.016952515,0.03439331,-0.029769897,0.050811768,-0.0017261505,-0.044006348,-0.03741455,-0.005203247,0.024505615,-0.046875,0.04916382,-0.041381836,-0.034118652,0.016204834,0.010498047,0.022201538,-0.027420044,-0.03250122,-0.020141602,0.003156662,0.00756073,0.020217896,-0.006378174,0.019302368,-0.020645142,0.018920898,0.01890564,-0.009757996,-0.020904541,0.018005371,0.024871826,-0.0022010803,-0.004711151,-0.07232666,-0.008056641,0.008033752,0.008178711,-0.024353027,-0.010139465,0.0043296814,-0.022247314,-0.022445679,0.029190063,-0.027160645,0.0034828186,0.074035645,-0.016113281,0.029769897,0.016647339,0.0005979538,0.0008072853,0.04309082,0.05834961,0.0013437271,0.013595581,-0.00016975403,-0.04196167,0.009841919,0.03100586,0.02684021,0.031204224,-0.049560547,0.017974854,0.012290955,-0.048431396,-0.06628418,0.035369873,0.019470215,-0.03274536,-0.0011615753,0.0569458,-0.033050537,0.034729004,-0.002538681,-0.006652832,0.014457703,0.068603516,0.022201538,-0.011787415,-0.028167725,-0.025787354,0.054382324,0.018692017,0.028793335,-0.059265137,0.03527832,-0.08135986,-0.02192688,-0.053771973,0.031204224,-0.056365967,0.021072388,-0.0066871643,0.014381409,-0.018508911,-0.01586914,-0.031921387,0.022598267,0.064575195,0.056640625,-0.0021419525,-0.05255127,0.038635254,0.004951477