INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-022', 'KR', 'HISTORY', '정종연 PD ''대탈출'' 5·18 기념일 탱크 연출 논란', '2021-05-18', 'tvN 예능 ''대탈출''이 5·18 민주화운동 기념일과 관련 있는 날짜에 탱크 관련 연출을 했다는 사실이 2026년 스타벅스 탱크데이 논란 이후 재소환됐다. 방심위 심의 안건에도 오르지 않은 채 어떠한 징계나 공식 사과 없이 조용히 넘어갔다는 비판이 제기됐다.', '계엄군_민간인_학살', '["https://namu.wiki/w/%ED%95%9C%EA%B5%AD%20%EC%8A%A4%ED%83%80%EB%B2%85%EC%8A%A4%20%ED%83%B1%ED%81%AC%EB%8D%B0%EC%9D%B4%20%EC%9D%B4%EB%B2%A4%ED%8A%B8%20%EB%85%BC%EB%9E%80/%ED%9B%84%EC%86%8D%20%EB%85%BC%EB%9E%80", "https://www.newsprime.co.kr/news/article/?no=734130"]', 'tvN 예능 ''대탈출''이 5·18 민주화운동 기념일에 탱크 관련 연출을 진행한 사실이 논란이 되고 있다. 이 사건은 2026년 스타벅스의 ''탱크데이'' 논란과 연결되어 재조명되었으며, 방송통신심의위원회 심의 안건에 오르지 않고 공식 사과나 징계 없이 넘어간 점에 대한 비판이 제기되었다. 무신사와 같은 다른 기업들은 논란 발생 후 신속하게 사과 및 조치를 취한 반면, ''대탈출''은 미온적인 대처로 비판받고 있다.', '[0.035461426,-0.010597229,-0.012756348,0.007419586,-0.0032100677,0.015823364,0.009048462,0.005558014,-0.03656006,-0.06793213,0.012107849,-0.018585205,-0.0027046204,0.016098022,0.024169922,-0.01234436,-0.01612854,-0.044281006,-0.028564453,0.00086927414,0.026046753,-0.005104065,0.00094652176,-0.017440796,0.006389618,-0.028640747,-0.0049362183,0.039093018,0.043182373,0.039398193,-0.052337646,-0.005973816,-0.015777588,-0.031677246,0.041015625,-0.0025787354,0.018676758,-0.039489746,-0.0041999817,-0.032226562,0.042419434,-0.018554688,-0.06463623,0.041412354,0.03704834,0.038482666,-0.014015198,0.007041931,0.042266846,0.061523438,0.059631348,0.022125244,-0.014755249,-0.03414917,-0.013038635,-0.0046920776,-0.009849548,-0.013908386,-0.02130127,0.002199173,0.032226562,0.015098572,-0.011581421,0.008003235,-0.002281189,-0.01928711,-0.02381897,0.07110596,-0.019607544,0.021331787,0.002090454,0.018981934,0.059906006,-0.016571045,-0.01625061,0.028518677,-0.023727417,0.022903442,-0.001830101,0.029067993,0.012084961,-0.0038146973,0.006542206,0.048919678,0.03161621,-0.03488159,-0.079589844,-0.024551392,