INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-023', 'KR', 'HISTORY', '자라(ZARA) 아동복 나치 수용소 죄수복 유사 디자인 논란', '2014-08-01', '스페인 의류브랜드 자라(ZARA)가 2014년 노란색 별 마크가 달린 줄무늬 아동복을 출시해 나치 시대 유대인 강제수용소 죄수복과 닮았다는 비판을 받았다. 홀로코스트를 상업적으로 연상시켰다는 거센 비난에 즉시 제품을 회수했다.', '인종_청소_및_집단_학살', '["https://www.khan.co.kr/article/201801171740001"]', '스페인 의류 브랜드 자라(ZARA)는 2014년 노란색 별 마크가 달린 줄무늬 아동복을 출시하여 나치 시대 유대인 강제수용소 죄수복과 유사하다는 비판을 받았다. 이로 인해 홀로코스트를 상업적으로 연상시킨다는 비난이 일었고, 자라는 즉시 해당 제품을 회수했다. 이 사건은 인종차별 광고 논란의 일환으로, 자라 외에도 여러 브랜드가 유사한 문제로 비판받아왔다.', '[0.04324341,0.06298828,-0.07537842,0.03213501,0.012832642,-0.043060303,-0.04058838,-0.011009216,0.051635742,-0.046722412,-0.019638062,0.00340271,-0.041259766,-0.02330017,-0.0067710876,0.039245605,0.009811401,-0.038238525,-0.06976318,0.0037574768,0.033813477,0.053100586,0.013374329,-0.01663208,0.060760498,0.02192688,0.04397583,0.003900528,-0.0075683594,0.011245728,-0.033172607,-0.0048675537,0.0019111633,-0.039642334,0.0043678284,-0.054107666,0.03842163,-0.017181396,0.027145386,0.011657715,-0.04156494,-0.015945435,0.020385742,-0.035491943,0.009994507,0.06866455,0.0058670044,0.012496948,0.004585266,0.008857727,-0.003458023,0.064453125,-0.01826477,0.003189087,-0.059143066,0.0005874634,-0.03062439,0.021591187,-0.047576904,-0.0074424744,0.026046753,-0.028884888,-0.00831604,0.01121521,-0.011680603,-0.022216797,-0.009544373,-0.0012378693,-0.025619507,0.07122803,0.035949707,0.0068588257,-0.011756897,-0.03591919,-0.013130188,-0.04144287,0.032470703,-0.019088745,0.017593384,0.03591919,-0.02041626,0.015472412,-0.0045280457,0.030258179,0.014884949,-0.0066490173,-0.037841797,0.016983032,-0.0046310425,-0.010505676,-0.023452759,0.05545044,-0.010902405,0.0119018555,0.019760132,0.011680603,-0.04449463,0.04083252,0.059173584,0.045532227,-0.02268982,-0.06549072,0.04058838,0.017333984,-0.021133423,0.030166626,-0.0050964355,-0.02748108,-0.037597656,0.0138168335,-0.041