INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-024', 'KR', 'GENDER', '카카오뱅크 ''집게손가락'' 남혐 논란', '2021-06-01', '2021년 5월 GS25발 손가락 논란이 확산되면서 카카오뱅크 광고 이미지에서도 유사한 손가락 모양이 발견됐다는 의혹이 제기됐다. 식품·편의점 업계에서 시작된 ''집게손가락 남혐 논란''이 금융업계까지 번진 사례로, 한국 사회 젠더 갈등의 광범위한 파급력을 보여준다.', '온라인_젠더갈등_및_손모양_기호_논쟁', '["https://www.kdfnews.com/news/articleView.html?idxno=75352"]', '2021년 5월, GS25가 홍보 포스터에서 남성 혐오 표현을 사용했다는 비난을 받으면서 ''집게손가락 남혐 논란''이 시작되었다. 이로 인해 GS25는 불매 운동을 막기 위해 다양한 프로모션을 진행하고 있으며, 가맹점주들은 본사를 상대로 집단 소송을 제기했다. 소비자들은 여전히 GS25에 대한 불만을 표출하고 있으며, GS리테일 측은 프로모션이 여름 성수기에 맞춘 것이라고 해명했다. 이 논란은 카카오뱅크 광고 이미지에서도 유사한 손가락 모양이 발견되면서 금융업계로 확산되었다.', '[0.021408081,-0.03390503,-0.009483337,0.048065186,0.015655518,-0.023742676,-0.016326904,-0.031188965,-0.019882202,-0.046325684,0.070007324,-0.0065574646,-0.033447266,-0.029296875,0.0068473816,0.00090408325,-0.01979065,-0.03579712,-0.010467529,0.015548706,0.023010254,0.015258789,0.0011358261,0.023803711,0.008972168,0.05227661,0.01802063,0.004589081,0.013313293,-0.018463135,0.02229309,-0.002948761,-0.0028324127,-0.061706543,0.025726318,-0.040618896,0.008415222,-0.008460999,0.06567383,0.0021038055,-0.0041160583,0.017288208,-0.020950317,-0.019927979,0.0031738281,0.07104492,0.02633667,-0.022888184,0.03967285,0.049682617,-0.028259277,0.020217896,0.0031280518,-0.040100098,-0.01411438,0.016403198,-0.012451172,0.0005016327,0.014328003,-0.0077400208,0.07672119,-0.048614502,-0.041290283,0.020462036,-0.013389587,-0.026519775,-0.016281128,0.02798462,-0.03253174,0.021408081,0.05392456,-0.010139465,-0.009117126,0.01651001,-0.03314209,-0.05831909,-0.037200928,0.0031375885,0.039520264,-0.016662598,-0.009033203,0.04800415,-0.0019044876,0.04937744,0.033294678,-0.024139404,-0.09161377,-0.011703491,-0.03994751,0.023117065,-0.048065186,0.02609253,0.045043945,-0.017211914,0.008361816,-0.015823364,0.02406311,-0.0018882751,0.036895752,0.035888672,0.024841309,-0.04095459,0.01