INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-025', 'KR', 'GENDER', '국내 다이어트 보조제 광고 ''비만체형 비하'' 논란', '2022-01-01', '국내 제약사 및 건강식품 회사들의 다이어트 보조제 광고에서 비만인 몸을 부정적으로 묘사하거나 특정 체형을 ''성공 전/후''로 표현하는 광고들이 신체 비하(바디 쉐이밍) 논란을 지속적으로 일으키고 있다. 특히 여성 모델을 활용한 사례들이 반복적 비판을 받는다.', '성별_고정관념_및_성차별', '["https://www.bbc.com/news/articles/cly5v89xny3o"]', '국내 다이어트 보조제 광고에서 비만 체형을 부정적으로 묘사하거나 특정 체형을 ''성공 전/후''로 표현하는 사례가 지속적으로 논란이 되고 있다. 특히 여성 모델을 활용한 광고들이 신체 비하를 조장한다는 비판을 받고 있다. 이러한 광고들은 비만에 대한 사회적 낙인을 강화하고, 건강보다 외모에 초점을 맞춘다는 지적을 받고 있다. 제약사와 건강식품 회사들은 광고 규제를 강화하고 있으며, 소비자들의 불만이 증가하고 있다.', '[0.08520508,0.01637268,0.0042533875,0.04711914,-0.015083313,-0.010536194,-0.021697998,0.008384705,0.02810669,-0.021865845,0.032989502,-0.056030273,-0.03439331,-0.049316406,0.01108551,0.026260376,-0.00052785873,-0.023284912,-0.0049858093,0.01991272,0.049224854,0.047790527,0.024475098,-0.020706177,0.033721924,0.019378662,0.02470398,-0.030899048,0.034942627,0.0015354156,-0.022323608,-0.011520386,0.030899048,-0.099609375,0.0064926147,0.014678955,0.009178162,0.02998352,0.046325684,-0.0044555664,-0.00944519,-0.024612427,0.020492554,-0.033843994,-0.012580872,0.045410156,0.013397217,-0.006336212,0.01399231,0.03942871,-0.017868042,0.07836914,0.016906738,0.006793976,0.008674622,0.013809204,-0.03225708,-0.023651123,0.011238098,0.017410278,0.033325195,-0.020202637,-0.044403076,0.041381836,-0.033599854,0.01134491,-0.02229309,0.026306152,-0.060821533,-0.0030918121,0.06021118,-0.023895264,-0.0067977905,0.026367188,0.008255005,-0.021057129,0.05303955,0.02911377,0.007091522,-0.03503418,-0.02583313,0.020706177,-0.01725769,0.032836914,-0.025878906,-0.01171875,-0.039001465,0.0143585205,-0.036346436,-0.0009379387,0.004798889,-0.0024433136,-0.02130127,-0.018508911,-0.016159058,-0.040283203,-0.015853882,0.018737793,0.022949219,0.02583313,0.026062012,0.018753052,0.061828613,0.059448242,0.01889038,-0.064331055,0.015182495,0