INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-027', 'KR', 'GENDER', '국방부 포스터 ''집게손가락 경례동작'' 남혐 논란', '2021-05-01', '2021년 GS25 손가락 논란이 확산되면서 국방부가 제작한 홍보 포스터의 군인 경례 동작에서도 ''메갈리아 집게손가락''이 포함됐다는 의혹이 제기됐다. 경찰 홍보물에서도 유사한 논란이 이어지면서 공공기관 홍보물 전반에 대한 손가락 이미지 전수조사 움직임이 일었다.', '온라인_젠더갈등_및_손모양_기호_논쟁', '["https://www.joongang.co.kr/article/24068378"]', '2021년 5월 25일, 국방부의 홍보 포스터에서 군인 경례 동작이 ''집게 손'' 모양으로 표현되어 남성 혐오 논란이 일었다. 부승찬 국방부 대변인은 이와 관련해 "주의하겠다"는 입장을 밝혔으며, 향후 홍보 콘텐츠 제작 시 유의하겠다고 전했다. 포스터는 2월 22일과 26일에 페이스북에 게시된 ''군대생활백과'' 카드뉴스로, 일반적인 경례 동작과 달리 부자연스러운 손 모양이 문제로 지적되었다. 이 논란은 GS25의 손가락 이미지와 관련된 이른바 ''메갈 손 의혹''에서 비롯되어 공공기관 전반으로 확산되고 있다.', '[0.04144287,0.034362793,-0.011001587,0.028152466,-0.015113831,-0.01701355,0.002910614,-0.002418518,0.012939453,-0.047576904,-0.0024337769,-0.017959595,0.0033740997,-0.053527832,0.0044441223,-0.025177002,-0.020996094,-0.041625977,-0.020996094,-0.0031833649,0.017227173,0.02368164,-0.036254883,0.029769897,0.0021800995,0.045806885,0.010139465,-0.00040006638,0.03475952,0.025177002,-0.016204834,-0.021072388,0.0095825195,-0.09436035,0.010475159,-0.0023918152,0.0074424744,-0.009109497,0.034454346,0.01576233,0.02192688,0.014465332,-0.04244995,-0.017547607,-0.0031147003,0.015350342,0.016311646,0.013595581,0.05279541,0.0289917,-0.030700684,0.052581787,0.019927979,-0.0032234192,-0.02281189,0.028152466,-0.06854248,-0.042297363,-0.027175903,0.0020503998,0.05078125,-0.0519104,-0.033477783,0.017181396,-0.011642456,-0.025222778,0.0066566467,0.021484375,-0.041046143,0.021087646,0.08355713,0.023880005,0.028167725,0.019500732,-0.003271103,-0.0010700226,0.007926941,0.0055122375,0.048095703,-0.05218506,0.013420105,-0.0021266937,0.019424438,0.025527954,-0.018600464,0.0309906,-0.07489014,-0.030151367,-0.015686035,0.0025806427,-0.061157227,0.0491333,0.033935547,0.002325058,0.022659302,-0.04498291,0.008796692,-0.00390625,0.05340576,0.017837524,-0.0109939575,-0.001