INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-029', 'KR', 'DISASTER', '세월호 참사 10주기 각종 기업 부적절 마케팅 논란', '2024-04-16', '세월호 참사 기념일인 4월 16일 전후로 부적절한 광고나 이벤트를 진행해 논란이 된 사례들이 반복적으로 발생한다. 특히 2024년에는 스타벅스의 사이렌 머그 출시 외에도 여러 브랜드의 기념일 마케팅이 유족과 시민들의 비판을 받았다.', '선박_침몰_및_구조_실패', '["https://www.asiatoday.co.kr/kn/view.php?key=20260522010006654"]', '2024년 4월 16일 세월호 참사 기념일에 스타벅스가 ''사이렌 클래식 민트 머그''를 출시하면서 논란이 일었다. 제품명 ''사이렌''과 용량 237ml가 세월호 실종자 수와 일치해 의도성이 의심받았다. 스타벅스는 과거에도 ''탱크데이'' 프로모션으로 비판을 받았으며, 이에 따라 공식 사과와 함께 대표가 해임됐다. 정부 차원에서도 스타벅스 불매 선언이 이어지는 등 브랜드에 대한 불신이 커지고 있다.', '[0.017333984,0.06402588,0.023406982,0.016983032,0.015586853,-0.0005040169,-0.010726929,0.010658264,-0.024353027,-0.043945312,0.06567383,-0.029464722,-0.048919678,-0.02583313,0.011528015,0.02772522,-0.059020996,0.004890442,-0.036987305,-0.0023765564,0.025054932,0.026412964,-0.026977539,0.041809082,-0.02708435,0.01701355,0.001493454,0.033721924,0.047821045,0.01977539,0.03982544,-0.031311035,-0.0012388229,-0.0211792,-0.00548172,0.04498291,-0.01838684,-0.026290894,-0.0025691986,0.01965332,-0.026657104,0.0038375854,-0.0013027191,0.0096206665,0.03253174,0.007080078,-0.015205383,-0.0008788109,0.05444336,0.088134766,0.022628784,0.03479004,0.046875,-0.027420044,0.037322998,-0.010772705,-0.007926941,-0.017913818,-0.017150879,0.0030918121,0.060028076,-0.030151367,-0.0028266907,-0.0395813,-0.03427124,-0.035705566,0.017578125,0.0068206787,-0.007385254,0.035827637,-0.0007972717,0.030899048,0.040039062,0.009056091,-0.0019454956,0.0063972473,0.03189087,0.0029716492,0.029083252,0.00061941147,-0.0041618347,0.0039024353,-0.04284668,0.041534424,-0.054901123,-0.018127441,-0.087646484,-0.013626099,-0.04837036,0.024230957,-0.04660034,0.044158936,-0.009590149,0.04348755,0.008369446,-0.039642334,0.016677856,-0.0008368492,0.023757935,0.036346436,0.0069503784,-0.009010315,-0.01625061,-0.0005040169,0.0024642944,-0.026062012,0.00494384