INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-030', 'KR', 'HISTORY', '아디다스 독일 축구 유니폼 번호 ''44'' 나치 SS 친위대 연상 논란', '2024-03-01', '2024년 아디다스가 새로 제작한 독일 축구 국가대표팀 유니폼의 등번호 숫자 ''44''가 나치 군사조직인 SS 친위대의 상징(⚡⚡)을 연상시킨다는 지적이 제기됐다. 아디다스는 즉시 디자인을 수정했다.', '인종_청소_및_집단_학살', '["https://www.asiae.co.kr/article/2024072009461046148"]', '2024년 아디다스가 제작한 독일 축구 국가대표팀 유니폼의 등번호 ''44''가 나치 SS 친위대의 상징을 연상시킨다는 지적이 제기되었다. 이에 아디다스는 디자인을 수정하기로 결정했다. 아디다스는 과거에도 반유대주의 논란에 휘말린 바 있으며, 최근에는 팔레스타인계 모델을 기용한 광고가 이스라엘의 비판을 받자 광고를 교체하기로 했다. 아디다스는 이러한 사건들이 의도치 않은 연결임을 인식하고 있다고 밝혔다.', '[-0.014984131,0.024627686,-0.004814148,0.017211914,-0.040924072,0.03201294,-0.0069732666,-0.011146545,-0.02507019,-0.0345459,0.029434204,-0.02720642,-0.032989502,-0.0012598038,0.039154053,0.010345459,-0.009635925,0.006072998,-0.06829834,-0.0335083,0.026809692,0.0057258606,0.011169434,-0.013961792,0.039031982,0.009513855,-0.023269653,-0.050567627,0.008239746,0.0058555603,-0.03375244,-0.012229919,0.057556152,-0.010017395,0.03010559,-0.057495117,0.021911621,0.032287598,0.002067566,0.009880066,-0.014228821,-0.005619049,-0.0146865845,0.027938843,0.010192871,0.021057129,0.044067383,-0.015296936,-0.024154663,0.030334473,0.04257202,0.095825195,-0.024841309,0.049682617,0.036865234,0.012771606,-0.0014667511,-0.0107803345,0.012771606,-0.037719727,-0.022003174,-0.076660156,-0.0052719116,0.022399902,-0.017059326,-0.044281006,-0.001742363,0.048706055,-0.0049438477,0.05355835,-0.016647339,0.012359619,0.031799316,-0.0131073,-0.05130005,-0.012832642,-0.031188965,0.031585693,0.045166016,0.026641846,0.0027008057,0.06463623,-0.050476074,0.019042969,0.011627197,-0.071777344,-0.031036377,0.005870819,0.0119018555,0.010955811,0.006996155,0.03930664,-0.04675293,-0.0039367676,-0.034454346,0.029418945,0.0064430237,0.043273926,0.015167236,0.03286743,0.006351471,-0.028030396,0.03173828,0.03753662,0.010055542,-0.017181396,0.0011768341,0.015342712,-0.