INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-001', 'INTL', 'DISCRIMINATION', '펩시 켄달 제너 ''Live for Now'' BLM 시위 광고 논란', '2017-04-04', '2017년 4월 펩시가 BLM 시위에서 모티브를 얻어 백인 모델 켄달 제너가 시위 현장에서 경찰에게 펩시를 건네는 장면으로 끝나는 광고를 공개했다. 심각한 인종차별 반대 운동을 경쾌하게 상업화했다는 비판이 폭발했다. 마틴 루터 킹 목사의 딸이 SNS를 통해 공개 비판하는 등 하루 만에 광고가 철회됐다.', '인종차별_경찰_폭력_및_흑인_살해', '["https://www.ytn.co.kr/_ln/0104_201704071330097248", "https://biz.heraldcorp.com/article/1290087", "https://www.hankookilbo.com/News/Read/201704061066214793"]', '2017년 4월, 펩시는 켄달 제너가 출연한 광고를 공개했으나 하루 만에 철회했다. 이 광고는 ''흑인 생명도 소중하다'' 운동을 소재로 하여, 제너가 시위 현장에서 경찰에게 펩시를 건네는 장면으로 구성되었다. 그러나 광고는 시위의 심각성을 경시하고 상업화했다는 비판을 받았으며, 마틴 루터 킹 목사의 딸이 공개적으로 비판하는 등 여론이 악화되자 펩시는 사과문을 발표하고 광고를 중단했다.', '[0.035461426,0.0015010834,0.02166748,0.03967285,-0.0028247833,-0.03149414,-0.02470398,-0.020629883,-0.0034065247,-0.050445557,0.009498596,-7.802248e-05,-0.03475952,0.037902832,0.05822754,0.01260376,-0.030151367,-0.03451538,-0.039276123,0.034973145,0.025741577,0.0011606216,-0.055480957,0.031585693,-0.021499634,0.04623413,-0.00074100494,-0.011421204,0.022018433,0.07098389,-0.00932312,-0.018875122,0.0024375916,-0.091918945,-0.016021729,-0.0049819946,-0.009277344,-0.024169922,0.040802002,-0.04458618,-0.037322998,0.006828308,0.0030136108,0.05822754,0.006298065,0.04849243,-0.011688232,-0.012763977,0.053894043,0.06829834,-0.021652222,0.032073975,-0.0030498505,0.005794525,0.0027389526,-0.020126343,-0.0036716461,-0.046569824,-0.009773254,-0.015060425,0.021728516,-0.029418945,-0.03640747,0.040405273,-0.016174316,-0.0670166,0.031463623,0.027633667,-0.054260254,-0.007686615,0.049926758,-0.013977051,0.025299072,0.04147339,-0.051361084,-0.003042221,0.046905518,0.03982544,-0.01537323,-0.029571533,0.024230957,0.036834717,-0.030593872,0.066467285,-0.043304443,0.026550293,-0.09472656,0.026901245,-0.020568848,0.015686035,-0.034454346,0.0022716522,-0.004459381,0.01537323,0.00967