INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-002', 'INTL', 'DISCRIMINATION', '도브(Dove) 흑인→백인 변신 인종차별 광고 논란 (2017)', '2017-10-08', '2017년 10월 도브가 페이스북에 흑인 여성이 도브 제품을 쓰고 백인 여성으로 변하는 3초짜리 GIF 광고를 게재해 전 세계적 인종차별 논란이 폭발했다. 도브는 2011년에도 흑인 여성을 ''사용 전'', 백인 여성을 ''사용 후'' 위치에 세운 광고로 유사 논란을 일으킨 전력이 있었다.', '피부색_차별_및_백인우월주의', '["https://www.seoul.co.kr/news/newsView.php?id=20171009500056", "https://www.ohmynews.com/NWS_Web/View/at_pg.aspx?CNTN_CD=A0002366259"]', '2017년 10월, 도브는 흑인 여성이 도브 제품을 사용한 후 백인 여성으로 변하는 광고를 페이스북에 게시하여 인종차별 논란에 휘말렸다. 이 광고는 빠르게 퍼지며 비난을 받았고, 도브는 즉시 광고를 삭제하고 공식 사과했다. 도브는 광고가 진정한 아름다움의 다양성을 대변하지 못했다고 인정하며, 내부 광고 검토 체계를 개선하겠다고 밝혔다. 도브는 2011년에도 유사한 인종차별 논란을 일으킨 바 있다.', '[0.062164307,0.010345459,-0.0101623535,0.050323486,0.007583618,-0.012954712,-0.0033035278,0.020996094,0.024978638,-0.04284668,0.07366943,-0.018814087,-0.023864746,-0.005558014,0.0066947937,0.021118164,0.013114929,-0.010177612,-0.044281006,0.039642334,-0.02722168,0.015945435,-0.035827637,0.043426514,0.016708374,0.023788452,0.017700195,-0.025177002,-0.013633728,0.01121521,-0.0046844482,-0.02053833,-0.0073013306,-0.049926758,0.02583313,-0.003545761,-0.0029964447,0.022323608,0.059020996,-0.0030517578,-0.010597229,-0.003850937,0.0066490173,0.0058174133,-0.025802612,0.08306885,0.012825012,-0.019088745,0.02456665,0.025177002,-0.027389526,0.022720337,-0.015602112,-0.012741089,-0.03656006,0.052093506,-0.0026950836,-0.01914978,0.025680542,0.0046691895,-0.01576233,-0.03262329,0.018478394,0.015991211,-0.016708374,-0.050079346,-0.019073486,0.041107178,0.0065689087,-0.008338928,0.07141113,0.0006313324,0.012573242,0.04321289,-0.018203735,0.023727417,-0.0070495605,0.039764404,-0.0028858185,-0.037994385,0.023864746,0.027618408,-0.013427734,0.06524658,-0.005428314,0.011375427,-0.042236328,0.00035905838,-0.003396988,-0.009994507,-0.034973145,0.028717041,-0.0340271,-0.008033752,0.0017032623,0.034362793,-0.000