INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-003', 'INTL', 'DISCRIMINATION', '도브(Dove) 흑인=''사용 전'', 백인=''사용 후'' 세정제 광고 논란 (2011)', '2011-01-01', '도브가 2011년 피부 세정제 광고에서 흑인 여성, 라틴계 여성, 백인 여성을 ''사용 전''부터 ''사용 후'' 순으로 나란히 세워 어두운 피부색을 ''개선이 필요한 상태''로 암묵적으로 규정했다는 비판을 받았다. 2017년의 더 노골적인 인종차별 광고의 전조가 된 사례다.', '피부색_차별_및_백인우월주의', '["https://imnews.imbc.com/replay/2017/nw1800/article/4435484_29865.html"]', '2011년 도브의 피부 세정제 광고에서 흑인 여성, 라틴계 여성, 백인 여성이 ''사용 전''과 ''사용 후''로 나란히 서 있는 모습이 논란이 되었다. 이 광고는 흑인 여성을 ''사용 전''으로, 백인 여성을 ''사용 후''로 묘사하여 어두운 피부색을 개선이 필요한 상태로 암시했다. 2017년에는 흑인 여성이 갈색 상의를 벗고 백인 여성으로 변신하는 광고가 게재되어 비난을 받았고, 도브는 이를 삭제하고 사과했다. 이러한 광고는 인종차별적 메시지를 포함하고 있다는 비판을 받으며 일부 소비자들 사이에서는 불매운동이 일어나기도 했다.', '[0.070129395,0.0071868896,0.0011034012,0.02923584,0.008705139,-0.010795593,-0.01411438,0.013519287,0.039794922,-0.021728516,0.055755615,-0.039093018,-0.052337646,-0.031402588,0.033843994,0.011886597,-0.012496948,-0.0047454834,-0.022567749,0.034454346,0.021347046,0.022598267,-0.06329346,0.019973755,0.008918762,0.016281128,0.03564453,-0.0005187988,0.031585693,0.007789612,-0.02633667,-0.029022217,-0.02482605,-0.04486084,0.038482666,-0.008354187,0.0146102905,0.034118652,0.052612305,-0.023376465,-0.009269714,-0.01096344,0.018539429,-0.014099121,-0.018737793,0.06829834,-0.008590698,-0.050964355,0.05606079,0.023376465,-0.025360107,0.038391113,-0.020233154,0.021392822,-0.018966675,0.023391724,-0.0015916824,-0.00027656555,0.026885986,-0.008735657,0.034057617,0.00491333,-0.0033493042,0.021530151,-0.029052734,-0.058380127,0.010528564,0.044891357,-0.024093628,-0.023529053,0.055664062,-0.024108887,-0.023635864,0.02923584,-0.027633667,0.034729004,0.013381958,0.028457642,-0.003112793,-0.015625,-0.00010108948,0.03567505,-0.029464722,0.049346924,0.0061454773,0.00774765,-0.051452637,0.023666382,-0.022460938,0.012321472,-0.040130615,0.010284424,-0.03286743,0.0031528473,0.0051078796,0.038