INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-004', 'INTL', 'DISCRIMINATION', 'H&M ''정글에서 가장 멋진 원숭이'' 흑인 아동 광고 논란', '2018-01-08', '2018년 1월 H&M이 흑인 아동 모델에게 ''Coolest monkey in the jungle(정글에서 가장 멋진 원숭이)''이라고 적힌 후드티를 입혀 광고했다. 같은 제품을 촬영한 백인 아동 모델에게는 ''정글의 생존 전문가''라는 문구를 입혔다는 사실이 드러나 논란이 증폭됐다. The Weeknd 등 협업 아티스트들이 관계를 끊었고, 남아공에서는 시민들이 H&M 매장을 습격했다.', '인종차별_경찰_폭력_및_흑인_살해', '["https://www.khan.co.kr/article/201801171740001", "https://www.khan.co.kr/article/201801091416021/"]', '2018년 1월, H&M은 흑인 아동 모델에게 ''정글에서 가장 멋진 원숭이(Coolest monkey in the jungle)''라는 문구가 적힌 후드티를 입혀 광고를 진행했다. 같은 제품을 착용한 백인 아동 모델에게는 ''정글의 생존 전문가''라는 문구가 적혀 있어 논란이 일었다. 이 광고는 즉각적인 비판을 받았고, H&M은 사과문을 발표하며 해당 이미지를 삭제했다. 남아프리카공화국에서는 H&M 매장이 시위대에 의해 습격당하고, H&M은 모든 여름 광고 일정을 취소했다.', '[0.0413208,0.01763916,-0.038269043,0.0287323,0.002231598,-0.026000977,-0.014228821,0.057281494,-0.019042969,-0.042663574,-0.016784668,-0.017227173,-0.09295654,-0.0025577545,0.010673523,0.04486084,-0.01133728,-0.028335571,-0.046051025,0.06347656,0.00491333,0.0473938,-0.014564514,0.04815674,0.013908386,0.010902405,-0.018203735,0.0017299652,0.036193848,0.03326416,0.010108948,-0.010108948,-0.0061073303,-0.0073547363,-0.010406494,0.0017080307,-0.04421997,-0.0072250366,0.0058135986,-0.0019283295,-0.007446289,0.031173706,0.04156494,-0.02659607,0.012367249,0.035186768,0.010734558,-0.004310608,0.033447266,0.022705078,0.0022411346,0.03970337,-0.009140015,-0.032226562,-0.030151367,-0.010307312,0.01612854,-0.0256958,-0.002878189,-0.057800293,0.022918701,0.020370483,-0.07696533,0.018203735,0.0025959015,-0.044158936,-0.0050735474,-0.015510559,-0.016113281,0.0011548996,0.07910156,-0.024124146,0.000518322,0.00041556358,-0.012214661,-0.038482666,-0.04196167,-0.022705078,-0.016525269,-0.021377563,-0.01360321,0.019744873,0.008636475,0.024124146,-0.028717041,-0.019607544,-0.05670166,-0.022720337,-0.04095459,-0.02104187,-0.025466919,0.0344238