INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-005', 'INTL', 'CHILD_PROTECTION', '발렌시아가 아동 BDSM 곰인형 광고 논란', '2022-11-22', '2022년 11월 발렌시아가가 2023 홀리데이 컬렉션 광고에서 BDSM 가죽 하네스와 자물쇠로 결박된 곰인형 가방을 어린 아동 모델이 안고 있는 이미지를 공개해 아동 성적 대상화 논란이 폭발했다. 광고 배경 서류 중 아동 성착취물 관련 미국 대법원 판결문이 포함됐다는 사실도 밝혀졌다.', '아동_학대_및_방임', '["https://www.newspim.com/news/view/20221124000137", "https://www.seoul.co.kr/news/newsView.php?id=20221126500038"]', '2022년 11월 발렌시아가는 2023 홀리데이 컬렉션 광고에서 아동 모델이 BDSM 하네스에 결박된 곰인형 가방을 안고 있는 이미지를 공개해 아동 성적 대상화 논란에 휘말렸다. 광고 배경에는 아동 성착취물 관련 미국 대법원 판결문이 포함되어 있었고, 이에 대한 비판이 거세지자 발렌시아가는 23일 공식 사과를 발표하며 광고를 철회했다. 발렌시아가는 "아동과 함께 있는 곰인형 가방 광고는 부적절했다"며 사과했지만, 여론은 여전히 냉담한 반응을 보였다.', '[0.031158447,0.04034424,-0.022384644,0.029388428,-0.022766113,-0.003786087,-0.016662598,0.0024852753,0.040771484,-0.050811768,0.018859863,-0.04940796,-0.0625,0.0034503937,0.032592773,0.00762558,0.01838684,-0.0077934265,-0.029052734,0.01977539,0.03488159,0.018310547,-0.044433594,0.0035305023,0.01008606,-0.0047340393,0.041381836,-0.053771973,0.011253357,0.06518555,-0.027236938,-0.025970459,-0.042755127,-0.03466797,0.01739502,-0.026763916,-0.028213501,-0.019439697,0.033691406,-0.011199951,-0.02758789,-0.055908203,0.011360168,0.013801575,-0.024261475,0.06945801,0.008255005,0.0039863586,0.04269409,0.009681702,0.011314392,0.064331055,0.01096344,0.01713562,-0.013793945,0.031707764,-0.009414673,-0.038848877,-0.0008778572,0.020568848,0.017868042,-0.021514893,-0.035888672,0.016937256,-0.022506714,-0.05996704,-0.029937744,0.049713135,-0.02734375,0.03353882,0.05984497,0.02784729,0.019943237,-0.0017681122,-0.03955078,-0.0010528564,0.030731201,0.0056533813,0.008529663,-0.010063171,-0.05343628,0.047912598,0.035369873,0.066833496,-0.045898438,0.03793335,-0.042938232,0.025970459,0.015113831,0.012207031,-0.024108887,0.011756897,-0.023910522,0.010597229,0.012878418,0.012451172,-0.027496338,-0.008903503,0.053100586,