INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-006', 'INTL', 'DISCRIMINATION', '니베아 ''White is Purity(순백은 순수)'' 광고 논란', '2017-04-01', '2017년 4월 니베아가 중동 지역 페이스북에 ''흰색은 순수하다(White is Purity)''는 문구와 함께 흰 가운을 입은 여성의 뒷모습 광고를 게재했다. 백인우월주의 극우 세력이 이 광고를 열렬히 환영하고 공유하면서 인종차별 논란이 폭발했다. 광고를 삭제하고 사과했다.', '피부색_차별_및_백인우월주의', '["https://www.hankookilbo.com/News/Read/201704061066214793"]', '2017년 4월, 니베아는 중동 지역 페이스북에 ''흰색은 순수하다(White is Purity)''라는 문구와 함께 흰 가운을 입은 여성의 뒷모습을 담은 광고를 게재했다. 이 광고는 백인우월주의 논란에 휘말리며 비판을 받았고, 니베아는 광고를 삭제하고 사과했다. 니베아는 "다양성과 평등한 기회는 우리의 핵심 가치"라고 강조했으며, 광고의 의도는 불쾌감을 주려는 것이 아니었다고 해명했다. 이 사건은 니베아의 과거 인종차별적 광고와 연관되어 논란을 더욱 키웠다.', '[0.01309967,-0.000223279,-0.0022659302,0.03717041,-0.025924683,-0.051086426,-0.0008277893,0.0032367706,0.025619507,-0.041748047,0.043792725,0.02796936,-0.0657959,-0.009147644,0.013267517,0.017593384,-0.0072402954,-0.016296387,-0.038208008,0.022369385,-0.0002784729,0.045440674,-0.031982422,0.040130615,0.018493652,-0.0024280548,0.03463745,-0.034088135,0.064208984,-0.0009613037,0.004257202,-0.011634827,0.020736694,-0.07720947,0.0154953,-0.046325684,-0.015563965,-0.045410156,0.066833496,-0.016220093,-0.030761719,0.026824951,0.010620117,-0.04058838,-0.011367798,0.083984375,0.00983429,0.019958496,0.039093018,0.0008249283,-0.015327454,0.026733398,0.010734558,-0.00920105,-0.0027008057,0.03137207,-0.011383057,-0.016860962,0.022705078,0.0042648315,0.00409317,-0.026473999,-0.038238525,0.026733398,-0.021499634,-0.068115234,-0.01977539,0.0068092346,-0.013572693,-0.010734558,0.085510254,-0.024261475,-0.0126953125,-0.0019721985,-0.030426025,-0.004573822,0.021697998,0.032318115,-0.020324707,-0.052856445,-0.026397705,0.046203613,-0.047454834,0.033569336,-0.02557373,-0.0053901672,-0.06640625,0.015670776,-0.04763794,0.024551392,-0.037963867,0.03439331,-0.050445557,0.02368164,-0.017959595,0.005970001,-8.85725e-05,0.009597778,0.026657104,0.028961182,-0.