INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-007', 'INTL', 'DISCRIMINATION', '니베아 ''Re-civilize Yourself'' 아프로헤어 흑인 비하 광고 논란', '2011-01-01', '2011년 니베아가 ''Re-civilize Yourself(다시 문명인이 되어라)''라는 광고 문구와 함께 흑인 남성이 아프로 헤어를 한 마네킹 머리를 집어 던지는 장면을 사용했다. 흑인의 자연스러운 헤어스타일을 ''야만''으로 규정하는 것이 인종차별적이라는 비판이 쏟아졌다.', '피부색_차별_및_백인우월주의', '["https://www.khan.co.kr/article/201801171740001"]', '2011년, 독일계 스킨케어 브랜드 니베아는 ''Re-civilize Yourself(다시 문명인이 되어라)''라는 광고 문구와 함께 흑인 남성이 아프로 헤어를 한 마네킹 머리를 던지는 장면을 사용했다. 이 광고는 흑인의 자연스러운 헤어스타일을 ''야만''으로 묘사한 것으로 인식되어 인종차별적이라는 비판을 받았다. 니베아는 이 광고로 인해 구설에 올랐으며, 이후에도 여러 차례 인종차별 논란에 휘말린 바 있다.', '[0.023620605,-0.007965088,-0.009056091,0.046722412,-0.041259766,-0.05041504,-0.02456665,0.06347656,0.018005371,-0.051696777,0.006565094,-0.001376152,-0.054718018,0.0049095154,0.04168701,-0.029388428,-0.043701172,-0.034210205,0.00349617,0.036376953,-0.021194458,0.04800415,-0.04046631,0.033966064,0.023986816,0.0072135925,0.022506714,0.0054969788,0.035369873,0.033966064,-0.042785645,-0.0146102905,-0.003419876,-0.038085938,-8.046627e-05,-0.038116455,-0.010215759,-0.053985596,0.03643799,-0.018707275,0.0012540817,0.011802673,0.03543091,0.00013422966,-0.03451538,0.06921387,0.0018444061,-0.0042304993,0.06567383,0.05722046,-0.024490356,0.056915283,-0.018447876,-0.017578125,-0.00026774406,-0.0015630722,-0.01777649,-0.026626587,0.007408142,-0.017044067,0.038726807,-0.009132385,-0.016357422,0.02696228,-0.06903076,-0.040527344,-0.010269165,0.00881958,-0.02368164,-0.038360596,0.06506348,-0.01210022,-0.011856079,0.0027179718,-0.033203125,-0.018798828,0.0036182404,0.039367676,-0.042297363,-0.016708374,0.0007009506,0.022628784,-0.029785156,0.028015137,-0.0044784546,-0.013259888,-0.061462402,-0.028076172,-0.043273926,0.012527466,-0.038269043,0.06008911,-0.052368164,0.009414673,-0.01550293,-0.011009216,-0.009643555,-0.01424408,0.054534912,0.05380249,-0.030441284,-0.038757324,0.025