INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-008', 'INTL', 'ETC', '버드라이트(Bud Light) 트랜스젠더 인플루언서 딜런 멀바니 협찬 논란', '2023-04-01', '2023년 4월 미국 맥주 브랜드 버드라이트가 트랜스젠더 인플루언서 딜런 멀바니와 협찬 광고를 진행했다가 보수 성향 소비자들의 대규모 불매운동을 맞았다. 20년 이상 미국 맥주 판매 1위를 지켜온 버드라이트가 시장 1위 자리를 모델로에 내줬고, AB인베브는 임원 2명을 휴직 처분하고 대규모 구조조정을 단행했다.', '성소수자_권리_및_젠더_정체성_사회_갈등', '["https://www.segye.com/newsView/20230425518348", "https://www.brandbrief.co.kr/news/articleView.html?idxno=5977", "https://mobile.newsis.com/view.html?ar_id=NISX20230614_0002338908"]', '2023년 4월, 미국 맥주 브랜드 버드라이트는 트랜스젠더 인플루언서 딜런 멀바니와 협찬 광고를 진행했다. 이로 인해 보수 성향 소비자들의 대규모 불매운동이 발생했으며, 버드라이트의 판매량은 급감했다. 4월 셋째 주 매출은 전년 대비 17% 감소했고, 6월 초에는 20% 이상 줄어들었다. 불매운동의 여파로 버드라이트는 시장 점유율 1위를 모델로에 내주었고, 앤하이저부시는 관련 임원 2명을 휴직 조치했다. 이 사건은 폭탄 테러 위협으로까지 이어졌고, 백악관은 이를 강하게 비판했다.', '[-0.014160156,-0.0026359558,-0.040985107,0.011108398,0.0015087128,0.019195557,0.0032444,0.08514404,-0.01763916,-0.03475952,0.002937317,-0.0051841736,-0.03744507,-0.00022804737,0.05114746,0.031982422,0.007686615,-0.029769897,-0.08898926,0.032989502,-0.003211975,-0.017501831,0.019012451,-0.018600464,0.059661865,0.033233643,-0.01838684,-0.054779053,-0.019210815,-0.0010938644,-0.03543091,-0.028427124,0.05596924,-0.037872314,-0.010627747,-0.0039253235,0.002368927,-0.009811401,0.025909424,0.007873535,-0.021240234,-0.0031013489,0.044921875,0.024734497,0.064331055,0.026260376,-0.014152527,0.0345459,0.054779053,0.03375244,-0.00617218,0.062683105,0.022354126,-0.02508545,-0.007183075,0.015357971,0.012123108,-0.039916992,0.06951904,0.026885986,0.08514404,-0.0574646,-0.0011110306,0.0035953522,-0.064331055,-0.08959961,-0.055877686,0.06378174,0.0070343018,0.05090332,0.054260254,-0.003107071,-0.00039696693,-0.02067566,-0.0069732666,0.020843506,0.018722534,0.004558563,0.010673523,-0.0093307495,-0.017608643,-0.013656616,-0.0044670105,0.038391113,-0.049224854,-0.019882202,-0.016448975,-0.018569946,0.0