INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-009', 'INTL', 'ETC', '아디다스 칸예(예) 반유대주의 발언 후 이지(Yeezy) 협업 강제 종료', '2022-10-25', '2022년 10월 힙합 아티스트 칸예 웨스트(예)가 SNS에 반유대주의적 발언을 쏟아내자 아디다스가 10년간의 이지(Yeezy) 브랜드 협업을 즉시 중단했다. 이지 라인 매출 손실로 2022년 아디다스 순이익이 수억 달러 감소했으며, 이지 재고 처리가 수년간 이어졌다.', '인종_청소_및_집단_학살', '["https://www.seoul.co.kr/news/international/2022/10/26/20221026500057", "https://www.christiantoday.co.kr/news/350703"]', '2022년 10월, 아디다스는 칸예 웨스트(예)의 반유대주의적 발언을 이유로 10년간의 이지(Yeezy) 브랜드 협업을 즉시 중단한다고 발표했다. 아디다스는 예의 발언이 회사의 가치에 위배되며, 이러한 혐오 발언을 용납할 수 없다고 밝혔다. 이로 인해 아디다스는 2022년 순이익이 최대 2500만 유로 감소할 것으로 예상되며, 이지 라인 매출 손실로 연간 약 20억 달러의 수익이 사라질 것으로 보인다. 웨스트와의 관계를 끊은 것은 아디다스뿐만 아니라 여러 기업과 기관들도 포함된다.', '[-0.040374756,-0.02619934,-0.016662598,0.019760132,-0.019515991,-0.002626419,0.030700684,0.015701294,0.0074806213,-0.02470398,0.016311646,-0.06402588,-0.0881958,-0.015571594,0.031433105,-0.012901306,-0.05581665,0.009475708,-0.031921387,0.003578186,-0.0138549805,-0.029800415,-0.0010099411,0.0637207,0.06011963,-0.04751587,-0.018112183,0.02709961,0.06286621,-0.012214661,0.020965576,-0.014015198,0.0597229,-0.019805908,-0.028167725,-0.01927185,0.031097412,-0.04421997,0.025177002,-0.019332886,0.010124207,0.0053901672,-0.0075531006,0.02720642,0.026412964,0.03427124,-0.011108398,0.006427765,0.07861328,0.03918457,0.015106201,0.09222412,-0.026031494,0.019744873,-0.015914917,-0.019485474,-0.008857727,-0.015434265,-0.023666382,-0.027664185,0.034118652,-0.01876831,0.005279541,-0.012298584,0.0033168793,-0.054656982,0.024795532,0.024734497,-0.02760315,-0.015991211,-0.001906395,0.014389038,-0.0018634796,-0.007801056,0.005783081,0.005847931,0.015792847,0.03479004,0.026046753,-0.0074882507,0.046447754,0.08148193,-0.061676025,0.050201416,0.012107849,-0.01663208,-0.056152344,-0.0074768066,0.011878967,0.034332275,-0.072631836,0.046447754,-0.008232117,-0.004295349,-0.011695862,0.036132812,0.0197143