INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-010', 'INTL', 'HISTORY', '아디다스 이스라엘 유니폼 광고에 팔레스타인계 모델 벨라 하디드 기용 논란', '2024-07-15', '2024년 7월 아디다스가 1972 뮌헨 올림픽 당시 이스라엘 국가대표팀 유니폼을 오마주한 SL72 스니커즈 광고에 팔레스타인계 아버지를 둔 모델 벨라 하디드를 기용했다. 이스라엘 주재 독일 대사관이 공개 비판하고, 유대인 단체들의 거센 항의를 받아 하디드를 광고에서 교체했다.', '이스라엘_팔레스타인_분쟁', '["https://www.asiae.co.kr/article/2024072009461046148"]', '2024년 7월, 아디다스는 1972년 뮌헨 올림픽을 기념한 SL72 스니커즈 광고에 팔레스타인계 모델 벨라 하디드를 기용했다. 이 광고는 이스라엘 주재 독일 대사관과 유대인 단체들로부터 강한 비판을 받았고, 하디드는 과거 팔레스타인 지지 활동으로 논란이 일었던 인물이다. 아디다스는 19일 광고 모델을 교체하기로 결정하며, 역사적 사건과의 연관성을 인식했다고 밝혔다. 이전에도 아디다스는 반유대주의 논란에 휘말린 바 있다.', '[0.011917114,0.033172607,-0.03277588,0.017990112,-0.033111572,0.040405273,-0.02861023,0.021591187,-0.009719849,-0.030838013,-0.02998352,-0.054138184,-0.041992188,-0.029327393,0.042510986,0.0035896301,-0.0008354187,-0.031982422,-0.051330566,-0.009429932,0.049041748,0.039916992,-0.009757996,0.0022888184,0.033416748,0.012313843,0.014709473,-0.014282227,0.03817749,0.022735596,0.0259552,-0.0135650635,0.074035645,-0.00040316582,-0.010444641,0.003288269,0.0011663437,0.01789856,-0.023208618,0.048187256,0.0033054352,0.038757324,0.008407593,0.024963379,0.030258179,0.052703857,0.004383087,0.016082764,0.022140503,0.022460938,0.048706055,0.081726074,0.014030457,0.03640747,-0.018829346,0.022537231,0.015975952,-0.024658203,0.0003273487,0.025604248,-0.025039673,-0.046081543,0.032440186,-0.0042800903,-0.060699463,-0.03817749,-0.033447266,0.056121826,-0.058166504,0.01033783,0.024780273,0.024810791,0.020187378,-0.023132324,-0.031555176,-0.046783447,0.0056762695,0.055267334,0.027435303,-0.012550354,-0.016540527,0.0146102905,-0.0036373138,0.03781128,-0.032958984,-0.013557434,-0.015296936,0.021133423,0.0019626617,0.032348633,-0.029006958,-0.015914917,-0.046783447,0.020736694,0.008522034,0.027114868,-0.026412964,-0.0005607605,0.0423584,0.048339844,0.038146973,-0.03955078,0.0040245056,0.0