INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-011', 'INTL', 'DISCRIMINATION', '중국 Qiaobi 세탁세제 ''흑인→아시아인'' 인종차별 광고', '2016-05-01', '중국 세탁세제 브랜드 Qiaobi가 2016년 흑인 남성을 세탁기에 집어넣자 밝은 피부색의 아시아인 남성으로 변해 나오는 광고를 제작해 전 세계적 비난을 받았다. 흑인의 피부색이 세탁으로 제거해야 할 ''더러움''임을 암시하는 역사상 가장 노골적인 인종차별 광고 중 하나로 기록됐다.', '피부색_차별_및_백인우월주의', '["https://imnews.imbc.com/replay/2017/nw1800/article/4435484_29865.html"]', '중국 세탁세제 브랜드 Qiaobi는 2016년 흑인 남성을 세탁기에 넣고 밝은 피부색의 아시아인 남성으로 변하는 장면을 담은 광고를 제작했다. 이 광고는 흑인의 피부색이 세탁으로 제거해야 할 ''더러움''이라는 메시지를 암시하며 전 세계적으로 비난을 받았다. 이 광고는 역사상 가장 노골적인 인종차별 광고 중 하나로 기록되었고, 이후 소비자들 사이에서 불매운동이 일어나는 등 큰 논란을 일으켰다.', '[0.024505615,0.03201294,-0.0056419373,0.06793213,-0.023468018,-0.059448242,-0.01386261,0.019515991,-0.019515991,-0.055725098,0.01524353,0.01739502,-0.071899414,0.00013566017,0.033172607,0.0021381378,-0.01977539,-0.0262146,-0.048919678,0.053375244,0.018295288,0.032684326,-0.01676941,0.026443481,0.008018494,-0.021148682,0.0055732727,0.006843567,0.009727478,0.006462097,0.010147095,-0.015991211,-0.013008118,-0.05871582,0.039611816,-0.0017242432,-0.0154953,0.0010948181,0.026916504,-0.016204834,0.017120361,-0.01701355,0.011764526,0.001964569,-0.015304565,0.047912598,0.018325806,-0.035736084,0.03555298,0.029586792,0.0010938644,0.036010742,0.004322052,-0.036346436,-0.009147644,0.026565552,-0.0075531006,0.00025248528,0.00466156,-0.0065727234,0.018234253,-0.05307007,-0.01159668,0.042053223,-0.04824829,-0.05899048,0.0020999908,0.05895996,-0.026885986,-0.046295166,0.054016113,-0.005958557,-0.009483337,0.019042969,0.005542755,-0.006111145,-0.035064697,0.047180176,-0.024353027,-0.05340576,0.0053901672,0.021942139,-0.0020275116,0.032440186,-0.018218994,0.013626099,-0.040863037,0.0069351196,-0.037353516,0.019073486,-0.043029785,0.028045654,-0.018875122,-0.025939941,0.028961182,0.02305603,0.024536133,0.043273926,0.054473877,0.047546387,-0.02734375,-0.045562744,0.04824829,0.