INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-017', 'INTL', 'DISCRIMINATION', '나이키 Colin Kaepernick ''Just Do It'' 광고 논란', '2018-09-03', '2018년 9월 나이키가 흑인 차별에 항의해 NFL 경기 중 국가 연주 시 무릎을 꿇어 논란이 됐던 전 선수 콜린 캐퍼닉을 ''Just Do It'' 30주년 캠페인의 주인공으로 기용했다. 보수층 소비자들이 나이키 신발을 태우거나 잘라버리는 불매운동을 벌였으나, 광고 이후 나이키 주가와 매출은 오히려 상승했다.', '인종차별_경찰_폭력_및_흑인_살해', '["https://www.hani.co.kr/arti/international/international_general/861773.html"]', '2018년 9월, 나이키는 ''Just Do It'' 30주년 캠페인 광고의 주인공으로 콜린 캐퍼닉을 기용했다. 캐퍼닉은 NFL 경기 중 국가 제창 시 무릎을 꿇어 인종차별에 항의한 전 선수로, 광고 공개 후 나이키에 대한 지지와 반발이 동시에 일어났다. 일부 소비자들은 나이키 제품을 불태우며 불매운동을 벌였으나, 광고 이후 나이키의 온라인 매출은 예년보다 31% 증가하고 주가는 회복됐다. NFL 시즌 개막 후, 캐퍼닉을 지지하는 선수들이 다시 무릎을 꿇기 시작했다.', '[0.013381958,0.049682617,0.026901245,0.025741577,0.041931152,-0.03253174,-0.036468506,0.002040863,-0.00026082993,-0.038513184,0.0012187958,-0.02293396,-0.066833496,0.020507812,0.051605225,-0.00365448,-0.05532837,-0.04534912,-0.02619934,0.016296387,0.0030155182,0.020584106,-0.043182373,0.031311035,0.0048599243,0.015541077,-0.0058021545,-0.0053863525,0.008491516,0.040374756,-0.034484863,-0.01197052,-0.019882202,-0.0390625,0.028564453,-0.029266357,0.008575439,-0.0107421875,-0.0017671585,-0.01637268,0.011238098,-0.014289856,0.053833008,-0.008956909,-0.027954102,0.029785156,0.018997192,-0.031677246,0.05130005,0.07647705,-0.026153564,0.033203125,-0.009887695,0.040161133,-0.005996704,0.022323608,-0.0024471283,-0.06707764,-0.007881165,0.010147095,-0.0068511963,-0.062561035,-0.005126953,-0.004798889,-0.051971436,-0.051879883,0.0018520355,0.08898926,0.0053215027,0.0036811829,0.020935059,-0.0010185242,0.0075263977,0.023895264,0.017852783,0.0463562,-0.017745972,0.016036987,0.0026798248,-0.04647827,0.017501831,0.02281189,-0.030685425,0.02470398,-0.042022705,-0.010536194,-0.060150146,-0.025650024,-0.006664276,-0.012763977,-0.015380859,0.026672363,-0.0061569214,-0.012565613,0.022415161,0.023635864,0