INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-018', 'INTL', 'GENDER', '길레트 ''최고의 남자'' 독성 남성성 광고 논란', '2019-01-14', '2019년 1월 면도기 브랜드 길레트(P&G)가 ''최고의 남자(The Best Men Can Be)''라는 광고를 통해 남성의 괴롭힘, 성차별적 행동 등 ''독성 남성성''을 비판하는 내용의 광고를 선보였다. 기존 슬로건 ''The Best a Man Can Be''를 변형한 이 광고는 MeToo 운동에 편승했다는 지지와 남성을 일방적으로 비판했다는 반발이 동시에 폭발했다.', '성별_고정관념_및_성차별', '["https://view.asiae.co.kr/article/2019011515381620152"]', '2019년 1월, 면도기 브랜드 길레트는 ''최고의 남자''라는 광고를 통해 남성의 독성 남성성을 비판하고 미투 운동을 지지하는 내용을 담았다. 이 광고는 기존 슬로건을 변형하여 남성의 괴롭힘과 성차별적 행동을 지적하며, "소년은 소년이 될 것"이라는 관념에 의문을 제기했다. 광고 발표 이후 일부 남성들 사이에서 불매운동이 일어났고, 월스트리트저널은 이 광고가 소비 브랜드의 사회운동 접근법에 대한 시험대가 될 것이라고 평가했다. 길레트 측은 이러한 대화가 중요하며 변화를 촉구하는 것이 목표라고 밝혔다.', '[0.024978638,0.043426514,-0.057861328,0.018798828,-0.028411865,-0.04058838,-0.05126953,0.032592773,0.004486084,-0.04232788,0.022399902,-0.0056152344,-0.04788208,-0.040802002,0.050872803,0.011054993,-0.014007568,-0.022460938,-0.03201294,0.051330566,0.008026123,-0.0022239685,0.00096559525,0.0022087097,-0.02003479,0.02784729,-0.00844574,0.032287598,0.018127441,0.05621338,-0.0084991455,-0.008781433,0.016845703,-0.03475952,0.009384155,-0.016174316,-0.0033874512,-0.026672363,0.051574707,-0.007545471,0.015640259,0.024475098,0.040039062,-0.054870605,0.02848816,0.014518738,0.014785767,-0.01927185,0.061157227,0.018417358,-0.012336731,0.025604248,0.042022705,0.02532959,0.021865845,-0.02482605,0.0023593903,-0.04525757,0.045776367,-0.014595032,0.007118225,0.011428833,-0.020462036,-0.011505127,-0.01309967,-0.030258179,-0.026382446,0.0524292,-0.01071167,-0.008125305,0.103149414,-0.042785645,0.0317688,0.0065956116,0.0035572052,-0.040374756,0.0012073517,0.027893066,0.011688232,-0.051818848,-0.024261475,0.021911621,-0.0075416565,0.059631348,-0.07409668,0.0030784607,-0.064086914,-0.0027103424,-0.033721924,0.008102417,-0.021621704,-0.013618469,0.001285553,-0.008049011,-0.016937256,0.02357483,0.038