INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-020', 'INTL', 'DISCRIMINATION', 'H&M 신장 위구르 강제노동 공급망 비판 후 중국 불매운동 역풍', '2021-03-01', '2021년 3월 H&M이 중국 신장 위구르 자치구의 강제노동 의혹 면화 사용을 중단하겠다는 이전 성명이 재조명되면서 중국 내 대규모 불매운동이 일었다. 중국 정부와 관영매체가 적극 지원한 이 불매운동으로 H&M 중국 내 온라인 플랫폼에서 퇴출됐고, 나이키·버버리 등 동일 입장을 밝힌 다른 브랜드들도 동시에 피해를 봤다.', '신장_위구르_강제노동_인권_탄압', '["https://namu.wiki/w/H&M", "https://www.bbc.com/news/business-57691415"]', '2021년 3월 H&M은 신장 위구르 자치구의 강제노동 의혹에 대한 우려를 표명하며 해당 지역의 면화 사용을 중단하겠다고 발표했다. 이로 인해 중국 내에서 대규모 불매운동이 발생하였고, H&M은 중국의 온라인 플랫폼에서 퇴출되었다. 2021년 2분기 H&M의 중국 매출은 전년 대비 23% 감소하며, 중국 시장에서의 판매가 급감한 것으로 나타났다. H&M은 중국 시장에 대한 의지를 재확인했으나, 불매운동의 여파로 어려움을 겪고 있다.', '[0.009162903,0.05783081,0.0023231506,0.024871826,0.0026855469,0.004436493,-0.012535095,0.04763794,-0.013511658,-0.021255493,0.026611328,0.015960693,-0.097839355,0.020965576,-0.0037384033,0.06921387,-0.022521973,-0.043426514,-0.042053223,0.021896362,0.011833191,0.0597229,-0.028030396,0.029083252,0.006160736,-0.0012264252,0.010253906,-0.0065078735,0.021713257,-0.003917694,-0.0066337585,-0.02142334,0.0031337738,-0.01109314,0.035095215,0.003168106,-0.032470703,0.016082764,0.022705078,0.0011281967,-0.043151855,-0.042816162,-0.0007457733,-0.011276245,-0.0029010773,0.04421997,0.01600647,0.012619019,0.028717041,0.025558472,0.011161804,0.03591919,0.0005760193,-0.045410156,0.011009216,0.0007138252,0.019439697,0.01727295,0.013999939,0.0070114136,0.0015954971,-0.039367676,-0.04220581,0.031555176,-0.027114868,-0.03793335,0.005466461,0.010559082,0.017684937,0.012496948,0.008895874,-0.027618408,0.020431519,0.0074310303,-0.0004930496,-0.02268982,0.027633667,0.035247803,0.0055503845,-0.008529663,-4.8816204e-05,0.04260254,-0.032928467,0.047821045,-0.02268982,-0.008163452,-0.06750488,0.0013751984,-0.033721924,-0.009933472,-0.010559082,0.014732361,-0.018203735,0.048614502,-0.013191223,-0.01838684,0.0060310364,-0.0017747879,0.046691