INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-021', 'INTL', 'CHILD_PROTECTION', '아메리칸 어패럴 아동 성상품화 광고 논란 (반복)', '2014-01-01', '아메리칸 어패럴(American Apparel)이 10대 모델들을 성인 패션 컨셉으로 활용한 선정적 광고를 반복적으로 집행해 아동 성상품화 논란이 끊이지 않았다. 영국 ASA(광고표준청)에서 수차례 광고를 금지했으며, 이는 글로벌 패션업계 아동 모델 가이드라인 강화 논의의 촉매가 됐다.', '아동_학대_및_방임', '["https://www.bbc.com/news/newsbeat-29046818"]', '아메리칸 어패럴은 2014년 9월 3일 영국 광고표준청(ASA)으로부터 ''학교 소녀''를 성상품화한 광고 두 개가 금지됐다. 해당 광고는 모델이 짧은 치마를 입고 엉덩이와 사타구니가 강조된 포즈를 취하고 있어 비판을 받았다. ASA는 이 광고가 여성의 성적 대상화를 조장하고, 성적 predatory 행동을 정상화할 수 있다고 판단했다. 아메리칸 어패럴은 광고가 명시적이지 않다고 주장했으나, ASA는 이를 "무책임하고 심각한 불쾌감을 초래할 가능성이 있다"고 결론지었다. 이후 해당 광고는 아메리칸 어패럴 웹사이트와 인스타그램에서 삭제됐다.', '[0.05142212,0.044128418,-0.003622055,0.042785645,0.0015411377,-0.0003619194,-0.044891357,-0.0135269165,0.029464722,-0.02671814,0.019851685,-0.08880615,-0.060272217,-0.007572174,-0.0038852692,0.016921997,-0.023529053,-0.02571106,-0.035980225,0.0054473877,-0.0019483566,0.017608643,-0.022018433,0.0035743713,-0.0069999695,-0.0158844,0.058441162,-0.033843994,0.022491455,0.040985107,0.025772095,-0.026184082,-0.002243042,-0.024307251,-0.00044608116,-0.005710602,0.010757446,0.00774765,0.0010824203,0.0021781921,0.020523071,-0.05496216,0.05102539,-0.023498535,0.0087509155,0.07989502,0.01927185,-0.008911133,0.046661377,0.0395813,0.0054512024,0.056518555,0.02760315,-0.014518738,-0.03491211,0.021255493,-0.015655518,-0.035980225,0.019683838,0.055267334,0.014060974,-0.029510498,-0.0018539429,0.019882202,-0.038391113,-0.0030918121,-0.017547607,0.029373169,-0.02468872,0.019363403,0.028167725,-0.03414917,-0.00025892258,-0.0234375,-0.027023315,-0.019851685,0.013648987,0.010238647,-0.0013542175,-0.011787415,-0.025527954,0.06414795,-0.025726318,0.01737976,0.028381348,0.004245758,-0.049957275,-0.0135650635,-0.047302246,-0.0005364418,-0.032043457,0.024673462,-0.049713135,0.053619385,-0.036621094,0.029922485,-0.018325806,0.0010843277