INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-023', 'INTL', 'DISCRIMINATION', '타코벨 히스패닉 문화 왜곡 치와와 광고 논란', '1997-01-01', '1997년 타코벨이 스페인어로 ''타코벨 원해요''라고 말하는 치와와 캐릭터를 중심으로 광고 캠페인을 전개했다. 히스패닉 커뮤니티와 시민단체들이 라틴계 문화를 귀여운 강아지로 단순화하고 고정관념을 강화한다고 비판했다. 타코벨은 결국 캠페인을 종료했다.', '소수민족_문화_전용_및_고정관념', '["https://www.youtube.com/watch?v=H-kvtKo7Ud8"]', '1997년 타코벨은 스페인어로 ''타코벨 원해요''라고 말하는 치와와 캐릭터를 중심으로 광고 캠페인을 시작했다. 그러나 히스패닉 커뮤니티와 시민단체들은 이 광고가 라틴계 문화를 단순화하고 고정관념을 강화한다고 비판했다. 이러한 논란으로 인해 타코벨은 결국 해당 캠페인을 종료했다.', '[0.05001831,-0.039733887,-0.024963379,0.049438477,0.004425049,-0.031677246,-0.03857422,0.03665161,0.004512787,-0.06542969,0.0031909943,-0.0011329651,-0.041931152,-0.009468079,0.038848877,-0.013473511,-0.0052261353,-0.017654419,0.0014038086,0.012962341,-0.0124435425,0.013389587,-0.04663086,0.05328369,0.00333786,0.017059326,0.00093126297,0.066223145,0.053222656,0.009422302,-0.047027588,-0.0077400208,-0.025146484,-0.061920166,-0.0184021,0.0009675026,-0.005115509,0.02017212,0.004753113,-0.0073509216,-0.04550171,0.03503418,0.035217285,0.01838684,0.017608643,0.009719849,0.017623901,0.039031982,0.016708374,0.021759033,-0.008552551,0.06695557,-0.026260376,-0.01890564,-0.016204834,0.00048565865,-0.02154541,-0.01398468,-0.0211792,-0.0042648315,0.01789856,0.010696411,0.005580902,-0.049621582,-0.024887085,0.023910522,0.012481689,0.020645142,-0.033294678,0.030532837,0.028533936,0.026397705,0.012161255,0.036987305,-0.020370483,-0.019683838,-0.027435303,0.012428284,0.016571045,-0.041748047,-0.003835678,0.015541077,-0.020492554,0.030899048,-0.006587982,-0.011680603,-0.07281494,-0.025436401,-0.011108398,0.017684937,-0.033203125,0.081970215,-0.019699097,0.036376953,0.0050735474,-0.05517578,0.009033203,-0.01751709,0.042236328,0.0017671585,-0.010604858,-0.040405273,-0.034423828,0.006011963,0.01386261,-0.009536743,0.007904053,0.01272583,0.013954163,-0.031280518,-0.039916992,0.046691895,-0.048