INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-031', 'KR', 'ETC', '네파 ''지리산은 망했지만 네파는 네팝니다'' PPL 마케팅 논란', '2021-11-23', '2021년 11월 아웃도어 브랜드 네파가 PPL로 참여한 tvN 드라마 ''지리산''이 흥행 실패하자, 삼성카드 임직원 복지몰에 ''지리산은 망했지만, 네파는 네팝니다''라는 광고 문구가 게재됐다. 드라마에 출연 중인 모델 전지현과 작품을 향해 ''망했다''고 표현하는 것이 배우와 작품 양측에 무례하다는 비판이 쏟아졌다. 해당 광고는 네파 공식몰이 아닌 제3자 임직원몰에서 제작됐으나, 관련사가 사과하고 광고를 내렸다.', '세계_환경의_날_World_Environment_Day', '["https://www.fnnews.com/news/202111231351067379", "https://m.news.nate.com/view/20211123n15992", "https://www.news1.kr/society/general-society/4501331"]', '2021년 11월, 아웃도어 브랜드 네파가 드라마 ''지리산''의 PPL로 참여한 가운데, 삼성카드의 임직원 복지몰에서 ''지리산은 망했지만, 네파는 네팝니다''라는 광고 문구가 사용되며 논란이 일었다. 이 광고는 네파의 제품을 홍보하기 위한 것이었으나, 드라마에 출연 중인 모델 전지현과 작품에 대한 무례한 표현으로 비판을 받았다. 네파 측은 해당 광고가 자사몰이 아닌 제3자 쇼핑몰에서 진행된 것이라며 사과하고 광고를 삭제했다고 밝혔다. ''지리산''은 제작비 300억원을 투자한 대작 드라마로, 기대에 미치지 못하는 성과를 보이고 있다.', '[-0.027069092,0.03878784,-0.052215576,0.010635376,0.030059814,-0.06762695,0.006298065,0.011444092,0.038238525,-0.016433716,0.014038086,-0.004055023,-0.05126953,0.042999268,-0.0259552,-0.013114929,-0.05532837,-0.0597229,-0.011291504,0.00040555,-0.03475952,0.021499634,-0.03164673,0.0016698837,-0.00051784515,0.0024433136,-0.008636475,-0.007347107,0.020492554,0.009223938,0.000749588,-0.002073288,-0.004337311,0.0014381409,-0.0129470825,0.002155304,0.00061416626,-0.020248413,-0.013328552,-0.049102783,-0.02986145,0.03918457,-0.016189575,0.0065460205,0.028945923,0.05822754,-0.0058059692,-0.0021953583,0.03652954,0.009185791,-0.0055122375,0.059631348,-0.01638794,0.01727295,-0.030181885,0.0072402954,-0.0070495605,-0.03086853,-0.03491211,-0.046844482,0.0055389404,-0.07519531,0.024017334,0.04031372,-0.010108948,-0.06762695,-0.029647827,0.03237915,-0.020904541,0.011940002,0.020477295,-0.001906395,-0.0047035217,0.035095215,-0.07348633,-0.016662598,0.049987793,0.0005455017,0.0032310486,-0.015823364,0.054656982,0.033843994,-0.002855301,0