INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-033', 'KR', 'GENDER', '마몽드 ''명품백 얻는 법은 남자친구 사귀기'' 광고 논란', '2012-04-26', '2012년 4월 아모레퍼시픽의 화장품 브랜드 마몽드가 소녀시대 유리를 모델로 한 광고에서 ''명품백 갖는 가장 쉬운 방법 = 남자친구 사귀기'', ''남자를 꼬시려면 치마를 10cm 자르라''는 내용을 담아 여성을 물질적이고 외모 지향적으로 묘사했다는 거센 비판을 받았다. 여성 소비자를 ''된장녀''로 프레이밍한다는 지적이 이어지며 광고 영상을 전면 삭제하고 공식 사과했다.', '연애_이성관계_성별_고정관념', '["https://www.seoul.co.kr/news/newsView.php?id=20120426800073", "https://m.cnbnews.com/m/m_article.html?no=167418"]', '2012년 4월, 아모레퍼시픽의 화장품 브랜드 마몽드는 소녀시대 유리를 모델로 한 광고에서 "명품백을 얻는 가장 쉬운 방법은 남자친구를 사귀는 것"이라는 내용을 담아 논란에 휘말렸다. 광고는 유리가 명품백을 얻기 위해 여러 방법을 고민하다가 결국 남자친구를 사귀는 방안을 제시하는 내용을 포함하고 있었다. 이로 인해 여성을 물질적이고 외모 지향적으로 묘사했다는 비판이 일었고, 마몽드는 해당 광고를 삭제하고 공식 사과문을 게재했다. 아모레퍼시픽은 광고 제작 의도가 경쾌하고 재미있게 제품을 소개하기 위한 것이었으나, 일부 내용이 부적절하다는 점을 인정했다.', '[0.047943115,0.072753906,-0.035003662,0.031707764,-0.041748047,0.01399231,-0.0209198,-0.0005221367,0.02281189,-0.016113281,0.004272461,-0.053588867,-0.05596924,0.013137817,0.046081543,-0.0014123917,-0.005924225,-0.020858765,0.020004272,0.028533936,0.03845215,0.07299805,-0.0031871796,-0.007774353,0.016159058,0.010559082,0.04864502,0.011940002,0.014579773,0.027175903,0.0025558472,-0.013702393,0.01739502,-0.08068848,0.020370483,-0.020721436,-0.005214691,-0.047027588,0.03390503,-0.045166016,-0.029556274,-0.0070648193,0.021057129,-0.029022217,0.016098022,0.08685303,0.0064926147,0.023788452,-0.013244629,0.021133423,-0.011566162,0.05279541,-0.023712158,0.014129639,-0.00022399426,0.007774353,0.008613586,-0.007850647,0.02017212,0.012207031,0.0004682541,-0.03491211,-0.037078857,0.0013189316,-0.0151901245,-0.020370483,0.036499023,0.04547119,-0.054595947,0.0038700104,0.10168457,-0.023330688,0.034942627,-0.0029201508,-0.028289795,-0.05014038,0.0395813,0.04119873,0.004760742,-0.015975952,0.02029419,0.007194519,0.014884949,0.050445557,-0.034240723,0.0011177063,-0.064208984,0.061950684,-0.035736084,0.01229