INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-048', 'KR', 'GENDER', '공차 BC카드 광고 ''어차피 계산은 내가 하는데'' 문구 논란', '2016-05-09', 'BC페이가 공차와 연계한 할인 이벤트 웹툰 광고에서 여성 캐릭터가 ''어머! 공차 가기 전에 BC Pay 등록해야겠다!''라고 하자 뒤의 남성이 ''어차피 계산은 내가 하는데''라고 말하는 장면이 포함됐다. 데이트 비용을 남성이 부담해야 한다는 성 역할 고정관념을 강화한다는 비판이 이어졌다. 공차의 세 번째 여혐 논란으로 불매운동이 재점화됐다.', '연애_이성관계_성별_고정관념', '["https://www.consumuch.com/news/articleView.html?idxno=22968"]', '공차는 BC페이와 연계한 할인 이벤트 웹툰 광고에서 여성 캐릭터가 BC Pay 등록을 언급하자 남성이 "어차피 계산은 내가 하는데"라고 말하는 장면이 포함되어 논란에 휘말렸다. 이 문구는 남성이 데이트 비용을 부담해야 한다는 성 역할 고정관념을 강화한다는 비판을 받았다. 공차는 이번이 세 번째 여성혐오 마케팅 논란으로, 소비자들의 분노가 커지자 즉시 광고를 중단했다. 공차 측은 해당 광고가 사전 논의 없이 BC페이에서 단독으로 진행된 것이라고 해명했다.', '[0.031951904,-0.009521484,0.025558472,0.008583069,0.025146484,-0.034454346,0.004142761,0.030029297,0.023361206,0.0052261353,0.044769287,-0.005706787,-0.016159058,0.0112838745,0.0124053955,0.038757324,-0.038116455,-0.020462036,-0.014541626,0.0140686035,0.0141067505,0.04916382,0.015098572,-0.007461548,-0.021408081,0.0029335022,0.027496338,-0.034454346,0.0052604675,-0.05508423,0.008712769,-0.022964478,0.01033783,-0.07989502,-0.017120361,0.014427185,-0.04989624,0.04272461,0.071777344,-0.045776367,-0.0038795471,0.0141067505,0.007965088,-0.042938232,-0.010269165,0.04650879,-0.0090408325,-0.019622803,0.012924194,0.047546387,-0.038391113,0.04147339,0.009170532,0.015083313,-0.0016422272,0.022201538,-0.035186768,-0.017242432,0.03555298,0.023605347,0.04837036,-0.05355835,-0.08123779,0.0569458,-0.032806396,0.020019531,0.024047852,0.025985718,-0.08203125,-0.001244545,0.020828247,-0.010910034,0.0524292,-0.0011863708,0.023864746,-0.019134521,0.0006599426,-0.01676941,0.015487671,-0.030212402,0.03616333,0.010375977,-0.0231781,0.0105896,-0.004261017,-0.035003662,-0.066223145,-0.00017273426,-0.04763794,-0.017089844,-0.08251953,0.012413025,-0.040405273,-2.2530556e-05,0.025375366,0.025238037,-0.04864502,-0.024780273,0.021408081,0.