INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-034', 'KR', 'CHILD_PROTECTION', '배스킨라빈스 핑크스타 ''아동 성상품화'' 광고 논란', '2019-06-28', '2019년 6월 배스킨라빈스가 당시 12세 아동 모델 엘라 그로스에게 짙은 립스틱을 바르게 하고 아이스크림을 먹는 입술을 클로즈업하는 ''핑크스타'' 광고를 공개해 아동 성적 대상화 논란이 폭발했다. ''이런 여름은 처음이야'', 모델이 쓰러지는 장면 등 성인 여성 광고 기법을 아동에게 그대로 적용했다는 비판이 제기됐다. 하루 만에 광고를 삭제하고 사과했으며, 방통심의위원회가 심의에 착수해 방송사 7곳에 ''경고'' 법정제재를 의결했다.', '아동_학대_및_방임', '["https://www.khan.co.kr/article/201907032132005", "http://www.sisanews.kr/news/articleView.html?idxno=41632", "https://www.asiae.co.kr/article/2019070116391163107", "https://www.pdjournal.com/news/articleView.html?idxno=70265"]', '2019년 6월, 배스킨라빈스는 12세 아동 모델 엘라 그로스가 등장하는 ''핑크스타'' 광고를 공개했으나, 아동 성상품화 논란에 휘말렸다. 광고에서 엘라 그로스는 짙은 립스틱을 바르고 아이스크림을 먹는 장면이 클로즈업되며, 성인 여성 광고 기법이 적용되었다는 비판이 제기되었다. 광고는 하루 만에 삭제되었고, 배스킨라빈스는 사과하며 모델 부모와 사전 논의를 거쳤다고 해명했다. 방송통신심의위원회는 해당 광고에 대해 심의를 진행하고, 법정 제재를 의결할 가능성이 높다고 밝혔다.', '[0.052215576,0.035217285,-0.03353882,0.031921387,0.0029697418,-0.016433716,-0.02911377,0.03857422,-0.002866745,-0.053985596,0.0047836304,-0.06414795,-0.04937744,-0.026290894,0.031204224,0.008766174,0.006462097,-0.036193848,-0.07757568,0.0022277832,0.020065308,0.037322998,0.012214661,-0.023712158,0.024490356,-0.015853882,0.08685303,-0.048919678,0.025238037,0.05203247,0.009315491,-0.020111084,-0.009254456,-0.039642334,0.0018920898,-0.0357666,-0.021728516,0.01512146,0.036376953,0.022064209,-0.013954163,-0.012611389,0.0061454773,-0.0022964478,-0.007408142,0.06958008,0.0022239685,0.02999878,0.026107788,0.04095459,-0.013404846,0.077819824,0.0048294067,-0.013145447,-0.019378662,0.011940002,-0.017868042,-0.03111267,-0.00831604,0.038391113,0.014839172,-0.00756073,-0.040618896,-0.00333786,-0.023147583,-0.043762207,-0.006843567,0.021026611,-0.029037476,0.033966064,0.061462402,-0.012710571,0.022201538,-0.0047035217,-0.033966064,-0.024459839,0.054534912,0.026901245,0.032440186,-0.012077332,-0.02702