INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-035', 'KR', 'GENDER', '삼성전자 파워건 청소기 ''남성을 청소기에 비유'' 광고 논란', '2017-11-12', '2017년 11월 삼성전자가 파워건 청소기 광고에서 예비 장모가 남자친구를 청소기와 비교하며 ''어째 튼튼하니?'', ''편하게 잘 써?''라고 묻고 딸이 ''친구 중에 최강이야'', ''제일 편해''라고 답하는 장면을 삽입해 남성을 가전제품에 비유했다는 남성 성상품화 논란이 일었다. 삼성전자는 과거 여혐 광고(김치냉장고, 세탁기) 논란에 이어 반복적으로 젠더 관련 광고 논란을 일으킨 브랜드로 지적됐다.', '성별_고정관념_및_성차별', '["https://www.newsfc.co.kr/news/articleView.html?idxno=30185"]', '삼성전자가 2017년 11월 파워건 청소기 광고에서 남성을 청소기와 비교하는 장면을 담아 성상품화 논란에 휘말렸다. 광고에서는 예비 장모가 남자친구에게 "어째 튼튼하니?"라고 묻고, 딸이 "친구 중에 최강이야"라고 답하는 내용이 포함되어 있다. 이로 인해 남성 소비자들은 불쾌감을 표하며 성차별적이라는 비판이 이어졌다. 삼성전자는 과거에도 성차별 논란이 있는 광고를 게재한 바 있으며, 커뮤니케이션팀은 광고에 대한 의견을 내기 어렵다고 밝혔다.', '[0.02720642,0.017684937,-0.079956055,0.023651123,0.0135269165,-0.021408081,-0.021209717,-0.0063552856,0.024139404,-0.025863647,0.04248047,-0.016143799,-0.002981186,-0.01637268,0.019454956,0.031143188,-0.06573486,-0.043701172,-0.004196167,0.016708374,0.029541016,0.04473877,0.025787354,-0.03479004,-0.024993896,0.032714844,0.00541687,0.013893127,0.008087158,0.011100769,0.020050049,-0.013259888,0.024871826,-0.07922363,0.015274048,0.033996582,0.028747559,-0.04434204,0.01576233,0.013786316,-0.006072998,-0.002166748,0.014472961,-0.03744507,0.03012085,0.031921387,-0.030395508,0.008552551,0.05038452,-0.00023055077,-0.010314941,0.036468506,0.028915405,-0.012252808,0.0231781,-0.019973755,-0.013343811,-0.021026611,0.018432617,0.046844482,0.050720215,-0.034576416,-0.014160156,0.04626465,-0.018676758,-0.023010254,0.04159546,0.07147217,-0.04510498,-0.04598999,0.07849121,-0.02609253,0.02243042,0.0032157898,0.019897461,0.012840271,0.055480957,0.010719299,0.0032806396,-0.034240723,0.017333984,0.01838684,0.010665894,0.038726807,-0.074035645,0.015258789,-0.084228516,-0.012626648,-0.02961731,0.0011358261,-0.040039062,0.03479004,-0.012756348,-0.019363403,0.021606445,-0.001335144,0.03466797,0.004447937,0.05551