INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-036', 'KR', 'GENDER', '삼성 갤럭시 ''새벽 2시 여성 혼자 조깅'' Night Owls 광고 논란 (영국)', '2022-04-28', '2022년 4월 삼성전자가 공개한 갤럭시 광고 ''Night Owls''에서 여성이 새벽 2시에 도심에서 혼자 조깅하는 장면이 등장했다. 영국 등 해외에서 여성 야간 안전 문제를 외면한 비현실적 광고라는 비판이 폭발했다. 해당 광고를 제작한 영국법인이 영국광고표준청(ASA)으로부터 제재를 받았으며, 광고는 삭제됐다. 한국 네티즌들은 ''광고 고칠 게 아니라 치안을 고쳐야 한다''는 반응을 보이기도 했다.', '여성혐오_살인_범죄', '["https://biz.sbs.co.kr/article/20000060509", "https://www.hankookilbo.com/news/article/A2022042915360002885"]', '2022년 4월, 삼성전자가 공개한 갤럭시 광고 ''Night Owls''에서 새벽 2시에 혼자 조깅하는 여성이 등장해 비판을 받았다. 광고는 여성 안전 문제에 둔감하다는 지적을 받으며, 영국에서 여성 살해 사건이 잇따라 발생한 상황과 맞물려 논란이 커졌다. BBC와 가디언 등 주요 언론이 이 문제를 보도하였고, 광고는 결국 영국광고표준청(ASA)으로부터 제재를 받아 삭제됐다. 삼성은 광고의 의도가 여성 안전 문제를 외면하려는 것이 아니었다고 사과했다.', '[0.04260254,0.016677856,-0.01411438,0.0024700165,-0.022323608,-0.010505676,-0.00088357925,0.0057144165,0.03768921,0.0058670044,0.039276123,-0.018478394,-0.0121536255,0.00055646896,0.028259277,0.005493164,-0.05078125,-0.016052246,-0.02418518,0.04598999,-0.02293396,0.013633728,-0.0181427,-0.014289856,-0.042510986,0.027633667,0.048553467,-0.024673462,-0.0026016235,0.022644043,0.0031757355,-0.021621704,0.030212402,-0.066833496,0.005592346,0.017456055,0.020309448,-0.009597778,0.014770508,-0.0423584,-0.018920898,-0.035888672,0.055908203,-0.06048584,0.032104492,0.036956787,0.013259888,0.02420044,0.018081665,0.013580322,-0.027542114,-0.006099701,0.0053367615,-0.00680542,-0.014671326,0.014709473,-0.059936523,0.044647217,0.062561035,0.051574707,0.01966858,0.011695862,0.0061149597,0.036071777,0.044128418,-0.035308838,-0.0008649826,0.039398193,-0.03479004,0.008224487,0.032104492,-0.017425537,0.010734558,-0.006855011,-0.019317627,0.04208374,0.0138168335,0.02758789,0.017181396,-0.04321289,-0.016952515,0.007045746,-0.036010742,0.039733887,-0.052368164,0.0068092346,-0.09637451,0.0010814667,-0.049102783,0.03930664,-0.011726379,0.03149414,-0