INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-037', 'KR', 'GENDER', '오리온 초코파이 ''군대 가야지 뭐 충성'' 군 비하 광고 논란', '2014-08-01', '2014년 여름 오리온이 배우 김유정을 내세운 초코파이 광고에서 ''초코파이 더 맛있게 먹는 법이 없냐고? 그럼 군대 가야지 뭐~ 충성!''이라는 멘트가 남성의 병역 의무를 조롱하는 것처럼 비쳐 논란이 됐다. 군 복무를 하지 않는 여성 연예인이 군인들의 힘든 경험을 가볍게 광고 소재로 사용했다는 비판이 제기됐다.', '군복무_병역_의무_사회적_긴장', '["https://www.segye.com/newsView/20171114003687"]', '오리온의 초코파이 광고가 논란에 휘말렸다. 2014년 여름, 배우 김유정이 출연한 광고에서 "더 맛있게 먹는 법 없냐고? 그럼 군대 가야지 뭐~ 충성!"이라는 멘트가 군 복무를 조롱하는 것으로 해석되면서 비판을 받았다. 네티즌들은 군인을 비하하는 내용이라며 광고 기획자에 대한 비난을 쏟아냈다. 과거에도 유사한 군 비하 광고가 논란이 되었으며, 군인에 대한 존중이 필요하다는 목소리가 제기되었다.', '[0.017333984,0.024139404,-0.003894806,0.033233643,0.026824951,-0.0104599,0.001461029,0.022644043,0.013580322,-0.022247314,0.004207611,-0.03994751,-0.017105103,-0.00762558,0.028442383,0.020080566,-0.028335571,-0.0362854,-0.013305664,-0.011680603,0.011558533,0.035858154,-0.01576233,-0.014251709,0.010696411,0.014221191,0.042663574,0.009132385,0.018295288,-0.0015106201,-0.027816772,-0.021850586,0.01701355,-0.08166504,-0.018203735,-0.04257202,-0.0007996559,0.007209778,0.04348755,-0.011657715,0.009887695,-0.014312744,0.03262329,0.011299133,0.04425049,0.0317688,0.008872986,-0.00756073,0.040008545,0.034729004,-0.037322998,0.06359863,0.015167236,0.047546387,-0.013877869,0.017593384,-0.013618469,-0.018936157,0.01108551,0.02128601,0.02949524,-0.0102005005,-0.025863647,0.04562378,-0.00141716,-0.018295288,0.010696411,0.022155762,-0.034729004,0.01739502,0.064941406,-0.017608643,0.024551392,0.0059928894,0.018417358,-0.020599365,0.038391113,-0.008026123,6.80089e-05,-0.05041504,-0.010353088,0.036071777,-0.013183594,0.055389404,-0.022583008,-0.0055236816,-0.0847168,0.04623413,-0.019241333,0.06378174,-0.06628418,0.060577393,-0.03387451,-0.011810303,-0.047332764,0.04949951,0.010864258,0.03805542,0.054260254,0.0158844,0.004043579,-0.023849487,0.007896423,0.052825928,0.030029297,-0.027023315,-0.