INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-038', 'KR', 'GENDER', '해피포인트 SPC ''국방의 의무 축하해'' 입영 광고 논란', '2009-06-08', '2009년 6월 SPC그룹의 해피포인트카드 광고 ''입영통지서'' 편에서 배우 이민정이 입영통지서를 흔들며 ''국방의 의무 축하해 / 드디어 멋진 남자 되는 거야 / 정신 좀 차리겠구나 / 면회는 자주 가줄게''라고 노래했다. 병역 의무를 조롱하고 군 복무를 하지 않는 여성이 입영 통보를 기뻐하는 것처럼 표현했다는 거센 비판이 일었다. 결국 해피포인트는 사과문을 발표하고 해당 편을 삭제했다.', '군복무_병역_의무_사회적_긴장', '["https://www.etoday.co.kr/news/view/1154240"]', '2009년 SPC그룹의 해피포인트 광고 ''입영통지서'' 편에서 배우 이민정이 군입대를 소재로 한 CM송을 부르며 논란이 일었다. 광고 내용은 입대 기념 축하파티를 여는 설정과 함께 "국방의 의무 축하해"라는 가사가 포함되어 있어, 병역 의무를 조롱하는 것으로 해석되었다. 이로 인해 네티즌들은 불편한 시선을 보였고, 결국 해피포인트는 사과문을 발표하고 해당 광고를 삭제했다. 최근 이 광고가 다시 재조명되며 논란이 일어났다.', '[0.032409668,-0.02078247,0.011207581,0.06726074,-0.009490967,-0.035095215,-0.031280518,0.027511597,0.030914307,-0.04751587,0.02911377,0.0021648407,-0.04714966,0.020080566,0.048736572,-0.0028266907,-0.03665161,-0.022003174,-0.016036987,0.012184143,0.02368164,0.030593872,-0.011077881,0.014060974,-0.0013618469,0.018478394,0.009651184,-0.0044021606,0.04208374,0.002286911,-0.02130127,-0.01309967,0.0063934326,-0.068725586,-0.0020141602,0.0025577545,-0.020202637,0.009185791,0.022735596,-0.04864502,-0.00030469894,0.05230713,0.009284973,-0.02381897,-0.012321472,0.016677856,0.031097412,-0.0066566467,0.05984497,0.015655518,-0.026397705,0.06970215,0.042266846,0.017044067,0.010536194,0.005836487,-0.032928467,-0.020446777,0.007511139,-0.04638672,0.06048584,-0.026123047,-0.05456543,0.022155762,0.015823364,-0.009262085,0.012268066,0.02432251,-0.0021953583,-0.004283905,0.050476074,0.008026123,-0.016143799,0.0063476562,0.015617371,-0.006111145,0.01348114,0.025741577,0.016738892,-0.058258057,0.0057411194,0.025924683,-0.027954102,0.023803711,-0.030548096,-0.012557983,-0.10626221,0.022537231,5.6624413e-06,0.060577393,-0.1171875,0.06439209,-0.002773285,-0.028518677,-0.018295288,-0.037506104,-0.012924194,-0.013801575,0.0070991516,0.02375793