INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-049', 'KR', 'GENDER', 'BHC ''뿌링클 사줄 사람 없는 여자분들 필독'' SNS 광고 논란', '2015-01-01', '치킨 프랜차이즈 BHC가 2015년 공식 SNS에 ''뿌링클 사줄 사람 없는 여자분들 필독하세요. 이 문장(나꿍꼬또, 뿌링클 멍는 꿍꼬또)을 매일 밤 20번씩 연습하세요''라는 홍보 문구를 게재했다. 여성을 남성에게 의존해야 하는 존재로 묘사한다는 비판이 일었고, 이후 BHC는 여혐 기업 불매운동 대상으로 선정됐다.', '연애_이성관계_성별_고정관념', '["https://www.seoul.co.kr/news/society/2018/11/19/20181119500151"]', 'BHC는 2015년 공식 SNS에 "뿌링클 사줄 사람 없는 여자분들 필독하세요"라는 광고를 게재하여 성차별적 요소가 포함되었다는 비판을 받았다. 이로 인해 일부 여성들이 BHC를 ''여성 혐오 기업''으로 지목하고 불매 운동을 벌이기 시작했다. 이들은 매달 두 곳의 여성 혐오 기업을 선정해 집단 항의와 불매 운동을 진행하고 있으며, BHC는 그 대상이 되었다. 이 운동은 기업의 인식 개선을 요구하는 활동으로, 사회적 반향을 일으키고 있다.', '[0.036743164,0.02809143,-0.019638062,0.07598877,-0.015853882,-0.0014772415,-0.0058174133,0.045318604,0.020736694,-0.052490234,0.02949524,-0.0020370483,0.016479492,0.020355225,0.02407837,0.051116943,-0.0024871826,-0.020263672,-0.0074920654,0.03414917,0.040893555,0.04345703,-0.026000977,0.008758545,0.000916481,0.021194458,-0.0035572052,0.001203537,0.06048584,0.016967773,0.009117126,-0.0017051697,-0.004295349,-0.038238525,-0.008010864,0.03918457,-0.0075950623,0.03439331,0.03967285,-0.004142761,-0.0008416176,-0.0063705444,0.03451538,-0.0076828003,0.012191772,0.045715332,0.017929077,0.05105591,0.011558533,0.032196045,-0.035736084,0.072021484,0.0020961761,-0.02720642,-0.0006866455,0.028457642,-0.04940796,0.011955261,-0.030059814,0.018203735,0.03427124,-0.016433716,-0.0713501,0.018127441,-0.02381897,-0.07086182,0.033996582,0.0034008026,-0.038635254,0.06951904,0.05368042,-0.019638062,-0.00919342,0.033477783,-0.027328491,-0.01675415,0.016296387,0.010108948,0.013130188,-0.012802124,-0.0079422,0.027496338,-0.024154663,0.036590576,-0.049560547,0.01008606,-0.1027832,0.026260376,-0.05114746,0.019561768,0.008132935,0.041107178,-0.04296875,-0.00674057,-0.013504028,-0.008102417,0.0015830994,0.010047913,0.020263672,0.058410645,0.032318115,0.0036