INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-025', 'INTL', 'ETC', '맥도날드 네덜란드 AI 생성 크리스마스 광고 혐오감·불쾌감 논란', '2025-12-06', '2025년 12월 네덜란드 맥도날드가 생성형 AI만으로 제작한 45초짜리 크리스마스 광고를 공개했다. 교통체증에 갇힌 산타, 사고 장면 등 크리스마스 혼란을 묘사했으나 AI 특유의 ''불쾌한 골짜기'' 현상(어색한 인물 묘사, 매끈한 피부, 초점 안 맞는 눈동자)으로 ''올해 가장 끔찍한 광고'', ''AI 잡동사니''라는 혹평이 폭발했다. 공개 3일 만에 광고를 철회했으며, AI 광고 시대의 품질·진정성 문제를 환기한 대표 사례로 기록됐다.', 'AI_생성_콘텐츠_윤리_및_딥페이크', '["https://www.brandbrief.co.kr/news/articleView.html?idxno=9326", "https://kormedi.com/2772094/", "https://www.ebn.co.kr/news/articleView.html?idxno=1690581"]', '2025년 12월 6일, 네덜란드 맥도날드는 AI로 제작한 크리스마스 광고를 공개했다. 광고는 크리스마스의 혼란을 묘사했으나, 어색한 인물 묘사와 불쾌한 골짜기 현상으로 인해 혹평을 받았다. 3일 후, 맥도날드는 광고를 철회하며 "연휴 스트레스를 표현하려 했으나 많은 고객이 이 시기를 긍정적으로 받아들인다는 점을 알게 되었다"고 밝혔다. 광고 제작사는 10명이 5주간 작업했음을 강조했으나, 여론은 반전되지 않았다. 이 사건은 AI 광고의 품질과 진정성 문제를 환기시켰다.', '[0.02142334,-0.009277344,-0.035888672,-0.003944397,-0.01071167,-0.03857422,-0.0011234283,0.013168335,0.004749298,0.018676758,-0.0035896301,-0.035858154,-0.0513916,-0.062316895,0.030319214,0.025131226,-0.106933594,-0.027526855,0.013061523,-0.04864502,-0.0041046143,0.015991211,-0.006164551,0.010688782,0.033813477,0.01411438,0.048858643,0.008270264,0.03692627,0.054718018,0.023880005,-0.02822876,0.036834717,-0.054351807,0.005695343,-0.016189575,0.0033130646,-0.025024414,-0.0043640137,0.028518677,-0.012580872,-0.02859497,0.04321289,0.014335632,-0.012466431,0.043273926,0.02432251,0.0010166168,0.01725769,0.042388916,-0.037322998,0.023498535,-0.02999878,0.016189575,-0.0129776,-0.0063667297,0.0021972656,-0.00030231476,0.053955078,-0.0028762817,-0.0011301041,-0.07019043,0.042297363,0.017868042,0.010955811,-0.043762207,-0.026138306,0.037963867,-0.048309326,0.004337311,0.010299683,-0.008430481,0.030075073,-0.061065674,-0.029754639,-0.022903442,0.021377563,0.03543091,-0.0009994507,-0.0038146973,-0.009605408,0.034210205,-0.070373535,-0.04522705,-0.0034294128,-0