INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-027', 'INTL', 'GENDER', '필라델피아 크림치즈 ''남성은 아이를 못 돌본다'' 광고 논란 (2018)', '2018-01-01', '2018년 영국에서 필라델피아 크림치즈가 남성들이 아이를 돌보다 컨베이어 벨트에 태워 보내거나 분실하는 광고를 방영했다. 남성 부모는 아이를 제대로 돌보지 못한다는 고정관념을 강화한다는 이유로 영국 광고표준청(ASA)이 방영을 금지했다. 이는 ASA가 성 고정관념을 조장하는 광고를 규제하는 새로운 가이드라인을 적용한 초기 사례 중 하나다.', '성별_고정관념_및_성차별', '["https://www.bbc.com/korean/international-49340830"]', '2018년, 필라델피아 크림치즈 광고가 남성의 육아 능력을 부정적으로 묘사한다는 이유로 영국 광고표준청(ASA)에 의해 방영이 금지되었다. 이 광고에서는 아버지가 아이를 컨베이어 벨트에 방치하는 장면이 등장해 성 고정관념을 조장한다는 비판을 받았다. ASA는 성역할 정형화를 금지하는 새로운 규정을 도입한 이후 첫 사례로 이 광고를 지목하며, 남성과 여성의 역할을 대비시키는 광고에 대해 세심한 주의가 필요하다고 강조했다.', '[0.023742676,0.05029297,-0.0501709,0.04336548,-0.029510498,-0.023513794,-0.043060303,-0.025238037,0.023712158,-0.048034668,0.015083313,-0.061950684,-0.0206604,-0.0041160583,-0.0021648407,0.0036182404,-0.020095825,-0.0357666,-0.06311035,0.03753662,0.008674622,0.012619019,0.029144287,-0.025482178,-0.013687134,-0.0018901825,0.043182373,-0.00856781,0.003501892,0.064208984,0.018600464,-0.029800415,0.027679443,-0.01663208,-0.032318115,0.0074386597,0.036254883,-0.0066375732,0.037109375,-0.027679443,-0.018417358,-0.019729614,0.040802002,-0.053100586,0.021255493,0.08502197,0.00894165,0.0003054142,0.030288696,0.0149002075,-0.029403687,0.06323242,-0.005207062,-0.008636475,-0.010612488,0.02041626,-0.019348145,-0.010139465,0.04940796,0.020843506,0.00032401085,-0.008148193,0.01084137,-0.01134491,-0.05621338,-0.03842163,-0.014724731,0.04034424,-0.023132324,0.00957489,0.088378906,0.001953125,-0.004917145,-0.015533447,-0.011390686,-0.007926941,-0.0039405823,0.043640137,-0.025650024,-0.030944824,-0.014144897,0.03010559,0.009773254,0.015991211,0.0030345917,0.021194458,-0.055786133,0.03668213,-0.02722168,0.011070251,0.0045433044,-0.009010315,-0.07836914,0.03112793,-0.024978638,0.018218994,0.036376953,0.023361206,0.051940918,0.04763794,0.0031700134,-0.03