INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-028', 'INTL', 'GENDER', '베를린 지하철 남성 역차별 요금 할인 광고 논란 (2018)', '2018-03-08', '2018년 3월 8일 세계 여성의 날, 베를린 교통공사(BVG)가 여성의 날 당일 여성 승객에게 임금 격차를 이유로 21% 할인 요금을 적용하는 이벤트를 실시했다. 성별에 따른 차별적 요금 정책이 역차별이라는 논란과 함께, 남성들의 반발이 폭발했다. ''성별로 요금을 다르게 받는 것이 합법인가''라는 법적 논란도 제기됐다.', '세계_여성의_날_International_Women_s_Day', '["https://www.bbc.com/news/world-europe-47613667"]', '2018년 3월 8일, 베를린 교통공사(BVG)는 세계 여성의 날을 기념하여 여성 승객에게 21% 할인 요금을 제공하는 이벤트를 실시했다. 이 할인은 독일 내 성별 임금 격차를 알리기 위한 것으로, 평균 21%의 차이를 반영한 것이다. 그러나 성별에 따른 차별적 요금 정책이 역차별이라는 논란이 일어나 남성들의 반발이 커졌고, 법적 문제도 제기되었다. BVG는 모든 직종에서 남녀에게 동일한 급여를 지급하고 있으며, 여성 직원 비율을 20%에서 27%로 늘리기 위해 노력하고 있다.', '[-0.005771637,-0.018569946,0.016464233,0.008094788,-0.031143188,-0.017028809,-0.009300232,0.04269409,0.00932312,-0.049560547,-0.027938843,0.008377075,-0.009414673,0.024887085,0.013031006,-0.0060768127,-0.0055732727,0.027648926,-0.036193848,0.03692627,0.015808105,0.0124435425,-0.008125305,0.023513794,-0.016677856,0.004169464,0.008781433,-0.0069084167,-0.028549194,-0.033050537,0.0037384033,-0.016235352,0.021133423,-0.06222534,0.0005979538,0.011375427,-0.046142578,-0.0016717911,0.08312988,-0.031051636,-0.026031494,-0.017593384,0.012992859,-0.007144928,-0.011375427,0.07159424,0.012649536,-0.01625061,-0.015579224,0.044189453,-0.006877899,-0.013160706,-0.0015039444,-0.03125,0.038757324,0.014862061,-0.0046539307,-0.022918701,0.059570312,-0.033966064,0.03050232,-0.04815674,-0.013160706,0.017791748,-0.021453857,-0.011734009,0.007949829,0.021347046,-0.03463745,0.013633728,0.07080078,0.0046806335,0.054901123,-0.0151901245,-0.00995636,0.018630981,0.0044937134,0.002954483,-0.017974854,-0.028121948,0.006729126,-0.005596161,-0.019836426,0.029876709,-0.045318604,-0.030761719,-0.06463623,0.025680542,0.019332886,0.012535095,-0.06982422,0.014411926,-0.057159424,0.007423401,0.023071289,0.0096206665,-0.03366089,-0.021453