INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-039', 'KR', 'GENDER', '현대자동차 쏘나타 ''여자니까 봐준다'' 여성 운전자 비하 광고 논란', '2016-01-01', '2016년 현대차가 쏘나타 뉴 라이즈 광고에서 여성 소비자 타깃 문구로 ''감각적이지만 운전 감각은 서툰 나 같은 사람들을 위해''라는 문구를, 남성 타깃 광고에는 ''사시사철 운전하는 나 같은 사람들에게''라는 문구를 사용해 여성을 운전 못하는 존재로 고정관념화했다는 비판이 이어졌다. 또 다른 현대차 광고에 ''여자니까 봐준다''는 대사도 논란이 돼 비공개 전환됐다.', '성별_고정관념_및_성차별', '["https://www.hankookilbo.com/News/Read/201906281595724638", "https://ewhabrandcommunication.wordpress.com/2017/04/24/%EA%B4%91%EA%B3%A0-%EC%86%8D%EC%97%90-%EB%82%98%ED%83%80%EB%82%9C-%EC%84%B1%EC%B0%A8%EB%B3%84-%EA%B3%A0%EC%A0%95%EA%B4%80%EB%85%90-%EC%9E%90%EB%8F%99%EC%B0%A8-%EA%B4%91%EA%B3%A0%EB%A5%BC-%EC%A4%91/"]', '2016년 현대자동차는 쏘나타 뉴 라이즈 광고에서 여성 소비자를 겨냥한 문구로 ''감각적이지만 운전 감각은 서툰 나 같은 사람들을 위해''라는 표현을 사용하여 여성 운전자를 비하했다는 비판을 받았다. 남성 소비자 대상 광고에는 ''사시사철 운전하는 나 같은 사람들에게''라는 문구가 사용되었다. 이 외에도 ''여자니까 봐준다''는 대사가 포함된 광고가 논란이 되어 비공식적으로 전환되었다. 이러한 광고는 성 고정관념을 강화하고 있으며, 소비자들의 비판으로 인해 현대차는 해당 광고를 철회한 바 있다.', '[-0.0030574799,0.019256592,-0.030136108,-0.00039291382,-0.0051193237,-0.04547119,-0.0234375,0.053222656,0.024291992,-0.05618286,-0.0033283234,-0.004245758,-0.0029392242,-0.001115799,0.010650635,-0.00021576881,-0.053466797,-0.034210205,0.004180908,-0.010307312,0.022750854,0.021850586,-0.0047912598,-0.012825012,0.0042152405,-0.00021791458,0.0024204254,0.008987427,-0.004096985,-0.0016202927,0.0259552,-0.021774292,0.007297516,-0.071899414,0.025558472,-0.010528564,0.016067505,-0.009292603,0.057800293,-0.0491333,0.01108551,0.020309448,0.043701172,-0.011871338,0.011909485,0.004299164,0.00027227402,0.01399231,0.010246277,0.01725769,-0.02722168,0.017868042,-0.005874634,0.011154175,-0.0076446533,0.041381836,-0.025497437,-0.01979065,0.054748535,0.0065956116,-0.01777649,-0.060058594,-0.061401367,0.016189575,0.008522034,-0.0057144165,0.023406982,0.028793335,-0.07543945,-0.0017557144,0.051605225,-0.023284912,0.044433594,0.01739502,-0.01