INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-040', 'KR', 'GENDER', '현대자동차 유튜브 영상 집게손가락 남혐 논란', '2024-10-11', '2024년 10월 현대자동차 공식 유튜브 채널에 올라온 ''충전 중 차량 활용 방법'' 영상에서 여성 캐릭터가 메갈리아의 남성 비하 제스처로 지적받는 집게손가락 모양을 하고 있다는 논란이 제기됐다. 현대차는 즉시 영상을 비공개 처리하고 ''혐오 표현이 사용된 것에 대해 진심으로 사과드린다''는 공식 사과문을 발표했다.', '온라인_젠더갈등_및_손모양_기호_논쟁', '["https://www.tleaves.co.kr/news/articleView.html?idxno=6470"]', '2024년 10월, 현대자동차의 공식 유튜브 채널에 게시된 ''충전 중 차량 활용 방법'' 영상에서 여성 캐릭터가 남성 비하 제스처로 지적받는 집게손가락 모양을 하고 있어 논란이 일어났다. 이에 현대차는 즉시 영상을 비공개 처리하고, "혐오 표현이 사용된 것에 대해 진심으로 사과드린다"는 공식 입장을 발표했다. 또한, 현대차는 해당 콘텐츠와 관련된 모든 시리즈를 노출하지 않도록 조치하고, 콘텐츠 제작 검열을 강화하겠다고 밝혔다.', '[0.044281006,0.052825928,-0.04788208,0.022445679,0.014907837,-0.009155273,0.011009216,0.039978027,0.016067505,-0.0062332153,0.022064209,-0.026275635,0.009757996,-0.021942139,-0.019470215,-0.0031852722,0.024612427,-0.035858154,-0.00674057,0.015533447,0.009719849,0.010070801,0.029800415,-0.010574341,0.016921997,-0.014266968,0.025177002,0.0038375854,-0.042816162,-0.02458191,0.01777649,-0.019134521,0.03942871,-0.057891846,0.000992775,-0.037628174,0.01940918,-0.001791954,0.03817749,-0.0003335476,-0.005493164,0.0065612793,0.015144348,0.003856659,0.01348114,0.041778564,0.028015137,0.009971619,0.03866577,0.012649536,-0.018829346,0.048706055,0.01914978,0.028305054,-0.019973755,0.032226562,-0.026779175,-0.003742218,0.014030457,-0.027313232,-0.0005302429,-0.090148926,-0.039215088,0.0015058517,0.023895264,-0.025619507,-0.02684021,0.027557373,-0.026885986,-0.014907837,0.036193848,-0.023605347,0.033966064,0.024627686,-0.028823853,-0.047027588,-0.000579834,0.037139893,0.012580872,-0.008270264,0.0073165894,0.04916382,-0.074401855,0.014274597,-0.045928955,0.07281494,-0.029632568,-0.01725769,-0.028045654,-0.018096924,-0.07507324,0.044281006,-0.0031604767,-0.03878784,0.015853882,0.008552551,0.014762878,0.011764526,0.039154053,0.015289307,0.004486084,-0.012878418,0