INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-041', 'KR', 'GENDER', 'LG전자 폴란드 V60 씽큐 ''몰카 조장'' 광고 논란', '2020-05-23', '2020년 5월 LG전자 폴란드 법인이 틱톡 공식 계정에 V60 씽큐 스마트폰 홍보 영상을 게재했다. 영상에서 남성 노인이 치마를 입고 계단을 오르는 여성의 뒷모습을 몰래 촬영하다 적발되지만, 듀얼스크린·펜타샷 기능 덕에 셀카를 찍은 것처럼 위장해 위기를 모면한다는 내용이었다. n번방 방지법이 막 시행된 시점에 불법 촬영 범죄를 유머 소재로 삼았다는 국제적 비판이 쏟아지며 200만 조회수를 넘긴 후 삭제·사과했다.', '디지털_성착취_및_불법_촬영물_유포', '["https://www.bloter.net/news/articleView.html?idxno=33402", "https://www.hankookilbo.com/News/Read/202005241153741135", "http://news.tf.co.kr/read/economy/1794720.htm", "https://www.ytn.co.kr/_ln/0102_202005250523458455_"]', '2020년 5월, LG전자 폴란드 법인이 틱톡에 게재한 V60 씽큐 스마트폰 광고가 논란에 휘말렸다. 광고 내용은 남성이 계단을 오르는 여성의 뒷모습을 몰래 촬영하다가 셀카로 위장해 적발을 피하는 상황을 담고 있었다. 이 광고는 성범죄를 유머로 다룬 것으로 비판받아 200만 조회수를 기록한 후 삭제되었으며, LG전자는 해당 콘텐츠가 회사 정책에 부합하지 않음을 인정하고 사과했다.', '[0.042419434,0.025482178,-0.07623291,0.0011129379,-0.060180664,-0.013801575,0.004306793,0.0017442703,0.03463745,-0.0725708,0.001206398,-0.07244873,-0.021728516,-0.025344849,0.024612427,0.005142212,-0.05770874,-0.07055664,-0.040618896,-0.007896423,0.003932953,0.02748108,0.057128906,-0.012306213,-0.01878357,0.016998291,-0.011062622,-0.045806885,0.020965576,-0.014297485,-0.018157959,-0.022720337,0.00083065033,-0.03186035,-0.01259613,0.021621704,0.031402588,-0.03314209,0.007095337,0.03765869,-0.04046631,-0.028045654,0.020080566,-0.013832092,0.029281616,0.03967285,-0.0029830933,0.04449463,0.040802002,-0.011558533,-0.016296387,0.038330078,0.0036067963,0.06304932,-0.009170532,-0.018218994,0.022018433,-0.03845215,0.031402588,0.018707275,0.0027236938,-0.06921387,0.019348145,-0.00011885166,-0.014625549,-0.052001953,0.0067329407,0.05178833,-0.03036499,0.020019531,0.042297363,-0.0048103333,-0.009635925,0.004108429,-0.02418518,0.005973816,0.046173096,-0.022064209,0.045562744,-0.0011415482,0.015213013,-0.0033073425,-0.005756378,0.05001831,-0.03314209,0.014389038,-0.077