INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-042', 'KR', 'GENDER', '직방 ''자취방 성범죄 피해자 탓'' 카드뉴스 광고 논란', '2017-02-26', '2017년 2월 부동산 중개 앱 직방이 페이스북에 여성 자취방에 낯선 남성이 침입해 몰래 살던 실화를 소재로 한 카드뉴스 광고를 게재했다. 마지막 장에 ''그러니까 대충 알아볼 게 아니라 직방으로 방을 구했어야지 X신아!''라는 문구를 넣어, 성범죄 피해의 책임을 피해자에게 돌리는 메시지를 담았다는 비판이 폭발했다. 직방은 즉시 사과하고 게시물을 삭제했다.', '디지털_성착취_및_불법_촬영물_유포', '["https://m.insight.co.kr/newsRead.php?ArtNo=95294"]', '2017년 2월, 부동산 중개 앱 직방이 페이스북에 여성 자취방에서의 성범죄를 소재로 한 카드뉴스 광고를 게재했다. 광고의 마지막 장에는 "그러니까 대충 알아볼 게 아니라 직방으로 방을 구했어야지 X신아!"라는 문구가 포함되어 있어, 성범죄 피해의 책임을 피해자에게 돌리는 메시지로 비판받았다. 이에 직방은 즉시 사과하고 게시물을 삭제했으며, 향후 이러한 문제가 발생하지 않도록 주의하겠다고 밝혔다.', '[0.03503418,0.014732361,0.00025057793,0.045440674,0.004299164,-0.02267456,-0.01322937,0.011642456,0.013900757,-0.048706055,0.07147217,-0.007385254,-0.01171875,0.057678223,0.019348145,0.019699097,-0.008323669,-0.0390625,-0.047729492,0.022094727,-0.050994873,0.029907227,-0.004295349,-0.018173218,0.025009155,0.060638428,0.01084137,-0.0013389587,0.02281189,0.009597778,-0.02532959,-0.014572144,0.020996094,-0.066589355,0.012390137,-0.01953125,-0.011398315,-0.024520874,0.023330688,-0.027572632,-0.012420654,0.016204834,0.00047969818,0.013031006,-0.043548584,0.040985107,-0.01361084,0.01953125,0.009880066,0.047424316,-0.00894928,0.032226562,0.0037612915,0.04324341,-0.012748718,0.0008506775,-0.034606934,-0.020599365,0.010925293,0.0035591125,0.020187378,-0.01737976,-0.04537964,0.016693115,-0.036315918,-0.04876709,-0.033111572,0.048583984,-0.029220581,0.03152466,0.08001709,-0.013702393,0.011169434,0.022583008,0.03277588,-0.03817749,-0.035217285,0.039001465,-0.0075645447,-0.030090332,0.040771484,0.057922363,0.0028038025,0.0619812,-0.040161133,-0.033935547,-0.09661865,-0.039794922,0.017333984,0.0039024353,-0.05279541,0.078063965,0.0234375,-0.0013618469,-0.0010871887,-0.044006348,-0.02281189,-0.022644043,0.062408447,0.03643799,0.022201538,-0.017074585,0.1032714