INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-029', 'INTL', 'GENDER', '호주 Handsome Her 카페 ''남성 추가 요금(Man Tax)'' 역차별 논란', '2017-04-01', '2017년 4월 호주 멜버른의 카페 Handsome Her가 남녀 임금 격차(18%)를 이유로 남성 손님에게 1.8호주달러의 추가 요금을 부과하는 정책을 시행해 국제적 논란이 됐다. 성별에 따른 차별적 요금 정책이 역차별이라는 비판과 함께, 남성 단체들의 차별 신고가 이어졌다. 논란이 확산되며 결국 정책을 철회했다.', '세계_여성의_날_International_Women_s_Day', '["https://www.bbc.com/korean/news-48061921"]', '호주 멜버른의 카페 Handsome Her는 2017년부터 남성 손님에게 1.8호주달러의 추가 요금을 부과하는 정책을 시행했다. 이 정책은 남녀 임금 격차를 반영한 것으로, 여자 손님에게는 좌석 우선권을 제공했다. 그러나 성별에 따른 차별적 요금 정책이 역차별이라는 비판이 커지면서, 카페는 2019년 4월 28일 폐점하기로 결정했다. 카페 측은 남성세로 인해 문을 닫는 것이 아니라 더 이상 카페를 소유하고 싶지 않다고 밝혔다.', '[-0.00036787987,0.0014848709,0.021194458,0.034210205,-0.016662598,-0.008377075,-0.040771484,0.021835327,0.049926758,-0.060577393,-0.0014276505,0.03225708,-0.024597168,0.0059661865,0.0075263977,0.008232117,-0.029174805,-0.025665283,-0.026824951,0.008850098,-0.001865387,0.025024414,0.004032135,-0.003665924,0.0035591125,0.029953003,-0.050354004,-0.025619507,0.029830933,0.0012378693,0.00083065033,-0.02746582,0.050628662,-0.037994385,0.0023918152,-0.015914917,-0.004348755,0.006149292,0.04550171,-0.025756836,-0.004131317,-0.04135132,0.024658203,-0.026977539,-0.034179688,0.03768921,0.02456665,-0.01108551,0.008483887,0.011520386,-0.017654419,-0.018920898,-0.026306152,-0.008094788,0.005596161,-0.0115737915,0.0007972717,0.0041236877,0.0132369995,-0.016204834,0.05618286,-0.04711914,-0.040771484,-0.028579712,-0.0026187897,-0.023086548,-0.011695862,-0.018508911,-0.027786255,-0.0012359619,0.053131104,0.019348145,0.01335907,0.009292603,0.0034828186,0.009147644,-0.011428833,0.013618469,-0.023712158,-0.018325806,0.001326561,0.027923584,-0.008071899,0.026428223,0.04232788,0.0023212433,-0.103393555,0.0045814514,-0.0044403076,0.008110046,-0.0052604675,0.025009155,-0.020339966,0.0021533966,0.013755798,-0.043060303,-0.036254883,0.006591797,0.0157