INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-014', 'INTL', 'ETC', '맥도날드 영국 ''사별한 아버지'' 광고 악용 논란', '2017-05-01', '2017년 영국 맥도날드가 아버지를 잃은 어린이가 아버지를 기억하는 감동적인 광고를 선보였다. 광고가 아이의 슬픔을 상업적으로 착취하고 감정을 광고 도구로 사용했다는 비판이 제기되어 결국 방영을 중단했다.', '유가족_사별_슬픔_상업적_소비', '["https://www.yna.co.kr/view/AKR20170517004300075"]', '2017년 5월, 영국 맥도날드는 아버지를 잃은 소년이 아버지의 기억을 되새기는 감동적인 광고를 방영하기 시작했다. 그러나 광고는 가족과 사별한 사람들의 슬픔을 상업적으로 이용한다는 비판을 받았다. 소셜미디어와 언론에서 수백 건의 항의가 이어지자, 맥도날드는 광고 방영을 철회했다. 맥도날드는 광고의 의도가 슬픔을 자극하려는 것이 아니라고 해명했다.', '[0.06347656,0.032592773,-0.05999756,0.020446777,-0.06414795,-0.0340271,-0.035247803,0.0209198,-0.01008606,-0.016815186,0.04324341,-0.038848877,-0.0077934265,-0.010513306,0.055358887,0.045898438,-0.024475098,-0.010231018,-0.04928589,0.01739502,0.0032482147,0.023834229,-0.018753052,-0.03540039,0.030715942,-0.0014162064,0.011276245,0.00059843063,0.0725708,0.0054016113,0.00036215782,-0.03466797,0.012107849,-0.025161743,-0.0063095093,-0.0003745556,0.016647339,-0.022262573,0.031921387,0.0064811707,-0.010543823,-0.046875,0.056671143,-0.03225708,0.028549194,0.03994751,0.009407043,0.01486969,0.059783936,-0.016616821,0.015357971,0.056671143,0.010978699,0.030059814,0.02041626,6.0260296e-05,-0.0072364807,0.0124053955,0.078552246,0.02268982,-0.017288208,-0.04711914,0.011520386,0.012145996,-0.012039185,-0.043945312,-0.016296387,0.039367676,-0.08294678,-0.010986328,0.054351807,-0.014335632,-0.014472961,-0.012565613,0.008506775,0.02935791,0.00044989586,0.025741577,-0.016723633,-0.06008911,0.015434265,0.007080078,-0.038146973,0.0055503845,-0.031021118,0.024124146,-0.011726379,-0.009361267,-0.014854431,0.03253174,-0.0040740967,0.042236328,-0.046936035,0.0027809143,-0.005748749,0.04714966,-0.020019531,0.021560669,0.04562378,0.062927246,-0.009971619,-0.04019165,-0.008666992,0.018707275,0.009284973,-0.05987549,0.026260376,-0.018234253,0.059020996,0.06298828,-0.033477783,0.012702942,-