INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-012', 'INTL', 'GENDER', '버거킹 영국 ''여성은 부엌에 있어야 한다'' 세계 여성의 날 트윗 논란', '2021-03-08', '2021년 세계 여성의 날(3월 8일), 버거킹 영국 공식 트위터가 ''여성은 부엌에 있어야 한다(Women belong in the kitchen)''는 트윗을 올렸다. 셰프 양성 프로그램을 홍보하기 위한 의도였으나, 성차별적 고정관념을 그대로 활용했다는 거센 비판에 직면해 삭제하고 사과했다.', '세계_여성의_날_International_Women_s_Day', '["https://www.khan.co.kr/article/202103091721001"]', '2021년 3월 8일, 세계 여성의 날을 맞아 버거킹 영국 공식 트위터가 "여성은 부엌에 있어야 한다"라는 트윗을 올렸다. 이는 여성 요리사의 비율을 언급하며 셰프 양성 프로그램을 홍보하려는 의도였으나, 성차별적 고정관념을 활용한 것으로 비판을 받았다. 논란이 커지자 버거킹은 해당 트윗을 삭제하고 사과하며, 여성 노동자들을 더 많이 채용하기 위한 장학 프로그램을 만들겠다고 밝혔다. 마케팅 전문가들은 이 광고가 기업의 사회적 명분을 호소하는 데 실패했다고 평가했다.', '[0.019134521,0.042175293,0.022872925,0.022338867,-0.0009794235,-0.0309906,0.020233154,0.00073957443,-0.0070114136,-0.03616333,0.008407593,0.012161255,0.0054626465,0.014785767,-0.009590149,0.046081543,0.0060577393,0.00592041,-0.017700195,0.032562256,-0.012367249,0.0032138824,-0.03591919,0.023086548,0.0023384094,0.041259766,-0.00086545944,-0.024383545,-0.053344727,0.012588501,-0.012878418,-0.02809143,-0.0023765564,-0.04736328,0.00447464,-0.03756714,0.013954163,0.016098022,0.056915283,-0.024902344,-0.04034424,-0.0015411377,0.021347046,0.0030326843,-0.010528564,0.064575195,-0.068725586,-0.004802704,0.017440796,-0.023727417,-0.006832123,-0.011222839,-0.0026054382,-0.014633179,0.023895264,-0.010887146,-0.025238037,0.025024414,-0.004272461,0.016601562,0.03930664,-0.010848999,-0.068847656,0.019042969,0.017913818,-0.0335083,0.044128418,0.057739258,-0.025253296,0.008712769,0.03375244,-0.00096702576,-0.00052547455,0.017211914,0.05444336,-0.0018196106,-0.037384033,0.012573242,-0.02017212,-0.039642334,-0.0010814667,-0.008621216,-0.053497314,0.037963867,-0.041809082,-0.009681702,-0.05508423,-0.022445679,-0.017822266,0.03564453,-0.038208008,0.01512146,0.0021038055,-0.0118637085,-0.0008773804,-0.012382507,0.028182983,-0.004627228,-0