INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-013', 'INTL', 'GENDER', '아디다스 독일 스포츠브라 여성 25명 맨가슴 광고 논란', '2022-03-01', '2022년 아디다스가 스포츠브라 광고에서 다양한 체형의 여성 25명의 맨가슴 사진을 나란히 배치했다. 다양한 신체를 인정하는 긍정적 의도였으나 과도한 신체 노출이라는 논란이 일었고, 광고 표준 당국의 제재를 받은 나라도 있었다.', '성별_고정관념_및_성차별', '["https://namu.wiki/w/%EC%95%84%EB%94%94%EB%8B%A4%EC%8A%A4", "https://www.donga.com/news/Inter/article/all/20220212/111737249/1"]', '2022년 아디다스는 새로운 스포츠 브라 제품 출시를 알리며 여성 25명의 맨가슴 사진을 공개했다. 이 광고는 다양한 체형의 여성들을 인정하는 긍정적 의도를 담고 있었으나, 과도한 신체 노출로 인해 논란이 일어났다. 소비자 반응은 엇갈렸으며, 일부는 대담한 시도라며 긍정적으로 평가한 반면, 다른 이들은 부적절하다고 비판했다. 아디다스는 이 광고가 가슴의 다양성을 보여주고 맞춤화된 브라의 중요성을 강조하기 위한 것이라고 설명했다.', '[0.021560669,0.05392456,0.001206398,0.006980896,-0.01977539,0.0137786865,-0.02822876,-0.026687622,0.041992188,-0.046051025,-0.014083862,-0.041381836,-0.051452637,-0.053100586,0.04763794,0.017654419,-0.029281616,0.0016784668,-0.03475952,-0.0006017685,0.0552063,0.022094727,-0.03591919,-0.025787354,0.027572632,0.01953125,0.011352539,-0.011413574,0.016860962,0.04046631,0.001001358,-0.003967285,0.04058838,-0.04660034,0.008811951,0.014862061,0.0035533905,0.0132369995,0.047821045,-0.034301758,0.042022705,-0.013252258,0.004169464,0.0017261505,0.007701874,0.05783081,-0.00409317,0.010505676,-0.008857727,0.018112183,0.0012798309,0.06604004,0.002368927,0.031707764,0.019088745,0.008903503,-0.014419556,-0.0050811768,0.012062073,0.022338867,0.0017337799,-0.033996582,0.0026397705,0.0031642914,-0.05987549,-0.041534424,0.032318115,0.03062439,-0.01991272,0.0021800995,0.038360596,0.02458191,0.033477783,0.0040664673,-0.0440979,-0.04083252,-0.0019416809,0.020828247,0.03289795,-0.032806396,0.006038666,0.06506348,-0.011795044,0.06994629,-0.022888184,-0.01965332,-0.048980713,0.014022827,0.007247925,0.038269043,-0.048095703,0.0040283203,-0.016357422,0.0440979,-0.0014953613,-0.02468872,0.0181427,0.007575989,0.021865845,0.028121948,0.016662598,-0.0225524