INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-015', 'INTL', 'DISCRIMINATION', '유니레버 페어앤러블리(Fair & Lovely) 미백크림 이름 논란', '2020-06-01', '유니레버의 대표적 미백크림 브랜드 ''Fair & Lovely(페어앤러블리)''가 어두운 피부색을 열등하게 규정하는 이름 자체가 인종차별적이라는 비판을 장기간 받아왔다. BLM 운동이 전 세계적으로 확산된 2020년 6월 결국 브랜드명을 ''Glow & Lovely''로 교체했다.', '피부색_차별_및_백인우월주의', '["https://www.womentimes.co.kr/news/articleView.html?idxno=50886"]', '유니레버의 미백크림 브랜드 ''페어 앤 러블리''는 인종차별적이라는 비판을 받아왔다. 2020년 6월, BLM 운동의 영향으로 유니레버는 브랜드명을 ''글로우 앤 러블리''로 변경했다. 이 브랜드는 인도에서 1975년부터 판매되었으며, 인도 시장에서 연간 5억 6,000만 달러의 매출을 기록하는 인기 제품이었다. 그러나 미백크림은 인종차별을 조장한다는 주장으로 인해 화장품 업계 전반에서 판매 중단이나 명칭 변경이 이루어지고 있다.', '[0.02319336,-0.015586853,-0.006351471,0.018539429,0.016799927,0.0061912537,0.0013723373,-0.03466797,0.012565613,0.002090454,0.012145996,-0.0032215118,-0.020202637,-0.05267334,0.0033836365,0.0069465637,-0.026260376,0.020553589,0.0024986267,-0.018875122,0.03918457,-0.012306213,-0.00076150894,0.023025513,0.016983032,-0.023391724,0.015075684,-0.059143066,-0.010917664,0.013870239,-0.0025672913,-0.023162842,0.043670654,0.002817154,-0.0016613007,-0.023376465,0.031433105,-0.027740479,0.044006348,0.008308411,-0.02255249,-0.03668213,-0.011894226,0.01058197,-0.023925781,0.05899048,0.021255493,-0.03289795,0.061401367,0.03967285,0.0060691833,0.023590088,-0.03161621,-0.027694702,-0.013000488,-0.00806427,-0.00012719631,0.008262634,-0.024765015,-0.02015686,0.015960693,-0.0051002502,-0.015327454,0.008453369,-0.020904541,-0.018051147,-0.03579712,-0.014259338,-0.0079574585,-0.0037021637,0.015975952,-0.018249512,0.033355713,0.024887085,-0.02027893,0.02859497,0.04550171,-0.018951416,0.027740479,-0.041748047,-0.016082764,0.01991272,-0.019088745,0.035369873,0.021499634,-0.015090942,-0.037719727,-0.019821167,-0.018096924,0.010345459,-0.031402588,0.0016241074,-0.04537964,0.048736572,0.015319824,0.030395508,-0.022842407,-0.005908966,-0.005130768,0.042938232,-0.013374