INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-016', 'INTL', 'CHILD_PROTECTION', 'H&M 아동 성상품화 ''Back to School'' 광고 논란', '2024-01-01', '2024년 1월 H&M이 원피스를 입은 두 소녀와 함께 ''Make those heads turn in H&M''s Back to School fashion(H&M의 교복 패션으로 시선을 사로잡으세요)''라는 광고 문구를 사용해 여성 아동 성상품화 논란이 일었다. H&M은 즉시 삭제하고 트위터에 사과문을 올렸다.', '아동_학대_및_방임', '["https://namu.wiki/w/H&M", "https://www.joongang.co.kr/article/25223803"]', '2024년 1월, H&M은 ''Back to School'' 광고에서 원피스를 입은 두 소녀의 사진과 함께 "H&M의 교복 패션으로 시선을 사로잡으세요"라는 문구를 사용해 아동 성상품화 논란에 휘말렸다. 이 광고는 호주 시장을 겨냥한 것으로, 네티즌들은 아이들을 성적 대상으로 삼았다고 비판했다. 논란이 커지자 H&M은 해당 광고를 즉시 삭제하고 공식 사과문을 발표했다. H&M은 앞으로 광고 방향성을 재검토하겠다고 밝혔다.', '[0.07385254,0.025848389,-0.03173828,0.018432617,-0.026870728,-0.011749268,-0.040802002,0.02017212,0.020767212,-0.04650879,0.0039253235,-0.056671143,-0.052337646,0.0031871796,0.005672455,0.041259766,-0.038208008,-0.044128418,-0.02458191,0.03540039,-0.005088806,0.05267334,-0.022521973,-0.0006489754,0.023635864,0.025634766,0.056640625,-0.035003662,0.033569336,0.038909912,0.033935547,-0.012931824,-0.0032863617,-0.02218628,0.019378662,0.0066070557,-0.037963867,0.03515625,0.03237915,0.018356323,-0.022399902,-0.011077881,0.04727173,-0.033172607,0.012825012,0.06335449,0.011932373,0.023513794,0.05819702,0.008178711,0.0024604797,0.03967285,0.030776978,0.002412796,-0.04916382,-0.0042915344,0.0054626465,-0.005329132,-0.0067749023,0.018188477,0.031982422,0.012046814,-0.06732178,-0.00018310547,0.017150879,-0.012458801,0.0009784698,0.0075798035,-0.029449463,0.042144775,0.07287598,-0.048339844,0.02279663,-0.034362793,-0.032958984,-0.02079773,-0.020767212,-0.016235352,0.016433716,0.00655365,0.00995636,0.049346924,-0.023773193,0.04449463,-0.024032593,-0.0042915344,-0.05545044,-0.014030457,-0.03375244,-0.013374329,-0.020874023,0.06695557,-0.037200928,0.019165039,-0.015426636,-0.008628845,-0.021408081,-0.027801514,0.022506714,0.040893555,0.0231