INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-001', 'KR', 'HISTORY', '스타벅스 코리아 탱크데이 이벤트 논란', '2026-05-18', '2026년 5월 18일 5·18 광주민주화운동 기념일 당일, 스타벅스 코리아가 텀블러 신제품 ''탱크데이'' 프로모션을 진행하며 ''책상에 탁!'' 문구까지 사용해 전국적 공분을 일으켰다. 이재명 대통령이 ''저질 장사치의 비인간적 막장 행태''라고 공개 질타하고, 정용진 신세계 회장이 직접 대국민 사과에 나섰으며 스타벅스 코리아 대표가 경질됐다.', '계엄군_민간인_학살', '["https://www.sedaily.com/article/20047768"]', '스타벅스 코리아는 2026년 5월 18일 5·18 광주민주화운동 기념일에 ''탱크데이'' 프로모션을 진행하며 논란에 휘말렸다. 정용진 신세계 회장은 5·18 단체의 요구에 따라 26일 대국민 사과와 함께 진상조사 결과를 발표할 예정이다. 스타벅스는 ''책상에 탁!''이라는 문구 사용으로 비판을 받았고, 이재명 대통령은 이를 강하게 질타했다. 논란 이후 스타벅스 불매 운동이 확산되고 있으며, 정 회장은 손정현 스타벅스코리아 대표를 경질했다.', '[0.0234375,0.029205322,0.030181885,0.021499634,0.022949219,-0.0015115738,0.016494751,0.036956787,-0.049316406,-0.055358887,0.018005371,-0.016525269,-0.005870819,-0.008598328,0.041229248,0.002149582,-0.044403076,0.01838684,-0.06567383,0.03286743,-0.009742737,-0.015914917,0.012382507,0.02330017,0.02331543,-0.014976501,-0.0058403015,-0.0053100586,0.048706055,0.031036377,-0.001461029,-0.02331543,-0.01461792,-0.042388916,0.016113281,-0.009689331,-0.004070282,-0.009208679,0.024963379,0.023223877,-0.03225708,-0.03540039,-0.031280518,0.05215454,0.0058937073,0.020309448,0.010856628,-1.4364719e-05,-0.017654419,0.036224365,0.050109863,0.008270264,-0.007144928,-0.024490356,-0.01689148,-0.014961243,-0.023086548,-0.0075912476,-0.05633545,-0.0061683655,0.04272461,0.0059127808,0.016082764,-0.008651733,-0.039367676,-0.01739502,0.071899414,0.05340576,-0.02243042,0.032165527,-0.0074539185,0.05307007,0.034454346,0.0042877197,-0.020095825,0.008049011,0.000102579594,0.049316406,0.031951904,0.06463623,0.0032444,-0.014305115,0.02772522,0.078186035,0.014518738,-0.08129883,-0.006565094,-0.018997192,0.034820557,0.041778564,-0.014450073,0.006980896,-0.02305603,0.04196167,0.04083252,-0.035736084,-0.03314209,-0.038238525,-0.0005249977,0.013717651,0.051483154,-0.059936523,0.008796692