INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-028', 'KR', 'GENDER', '교촌치킨 ''집게손가락'' 남혐 의혹 논란', '2021-05-01', '2021년 5월 GS25·BBQ에 이어 국내 치킨 업계 1위 교촌치킨 홍보물에서도 메갈리아 집게손가락 이미지가 무더기로 발견됐다는 주장이 제기됐다. 유통·식품업계 전반으로 번진 ''손가락 주의보''의 대표 사례 중 하나다.', '온라인_젠더갈등_및_손모양_기호_논쟁', '["https://www.kdfnews.com/news/articleView.html?idxno=74457"]', '2021년 5월, 교촌치킨의 홍보물에서 남성 혐오 커뮤니티 ''메갈리아''의 집게손가락 이미지가 발견됐다는 주장이 제기됐다. 이와 관련해 BBQ도 남성 혐오 표현을 사용했다는 의혹에 휘말렸으며, 소세지를 손가락으로 집고 있는 이미지가 논란이 되었다. 네티즌들은 해당 이미지에 대해 의문을 제기했고, BBQ는 논란이 일자 이미지를 수정했다. BBQ 관계자는 디자인이 외주업체에 맡겨졌으며, 오해를 피하기 위해 삭제했다고 밝혔다.', '[0.06274414,0.0011091232,0.004749298,0.020950317,0.03164673,-0.032928467,-0.021209717,0.027801514,-0.020629883,-0.084350586,0.032165527,-0.009757996,-0.043701172,0.005432129,-0.022705078,-0.009994507,-0.025100708,-0.015289307,0.0022563934,0.025299072,0.020080566,-0.0028419495,-0.0181427,0.010795593,0.017150879,0.041015625,-0.018966675,0.038879395,-0.0138168335,0.00819397,-0.027908325,-0.025009155,0.04208374,-0.06878662,0.007858276,0.007106781,-0.046936035,-0.0017728806,0.058013916,0.014640808,-0.017929077,0.048858643,-0.017089844,0.02017212,0.011062622,0.018173218,0.0143585205,-0.045288086,0.02418518,0.013038635,-0.01386261,0.049072266,0.008613586,-0.03036499,-0.0031795502,-0.013694763,-0.07562256,-0.022659302,-0.009536743,-0.020965576,0.006843567,-0.042816162,-0.002374649,-0.012458801,0.0061073303,-0.014755249,0.026870728,0.048461914,-0.0112838745,0.02470398,0.0546875,-0.012710571,0.018295288,0.0019330978,-0.023895264,-0.04144287,-0.02784729,-0.039642334,0.022262573,-0.015525818,-0.0317688,0.051513672,0.010002136,0.043548584,0.019500732,0.0048561096,-0.06604004,-0.022644043,-0.0138549805,-0.00069999695,-0.07513428,0.01902771,0.032348633,-0.011672974,0.022354126,-0.02267456,0.019317627,0.012588501,0.004032135,0.025619507,-0.0151901245,0.00055885315,0.016860962,0.019485474,0.017059326,-0.00058460236,0.01