INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('KR-043', 'KR', 'GENDER', '디즈니코리아 아동복 ''남자는 용감한, 여자는 예쁜 여자친구'' 광고 논란', '2019-05-01', '2019년 디즈니코리아가 공개한 아동복 광고에서 남자아이에게 ''용감한''이라는 표현을 쓴 반면 여자아이에게는 ''만화 주인공처럼 예쁜 여자친구''로만 묘사해 성 역할 고정관념을 조장한다는 비판이 이어졌다. 비판이 확산되자 디즈니코리아는 해당 광고를 삭제하고 새로운 광고를 제작했다.', '성별_고정관념_및_성차별', '["https://www.hankookilbo.com/News/Read/201906281595724638"]', '2019년 디즈니코리아의 아동복 광고에서 남자아이에게는 ''용감한''이라는 표현을 사용하고, 여자아이에게는 ''만화 주인공처럼 예쁜 여자친구''로 묘사해 성 역할 고정관념을 조장한다는 비판이 제기됐다. 이에 따라 디즈니코리아는 해당 광고를 삭제하고 새로운 광고를 제작했다. 이와 같은 성차별적 광고는 국내에서 여전히 빈번하게 발생하고 있으며, 광고 업계의 성평등 감수성이 부족하다는 지적이 있다. 소비자들의 비판이 광고 내용 변경에 영향을 미친 사례도 존재한다.', '[0.035186768,0.030059814,-0.07873535,0.06451416,0.027908325,-0.0010137558,0.0058135986,0.00957489,0.01486969,-0.033203125,-0.02116394,-0.020462036,-0.032958984,-0.037719727,0.06008911,0.014976501,-0.020401001,0.011787415,0.009590149,0.026855469,0.02633667,0.058532715,-0.008773804,-0.036987305,0.029312134,0.028274536,0.025039673,-0.0068969727,0.053833008,0.023269653,-0.017227173,-0.00066804886,0.035827637,-0.059906006,0.019958496,-0.011238098,0.025039673,-0.03149414,0.022537231,-0.019302368,0.0050468445,-0.024139404,0.017349243,-0.053497314,0.009048462,0.0736084,-0.0076408386,0.012367249,0.0690918,-0.008842468,-0.07128906,0.085998535,0.019546509,-0.0032234192,-0.023727417,0.0107040405,0.02003479,-0.04309082,-0.010795593,0.023651123,0.008155823,-0.01940918,-0.019165039,0.024215698,-0.036102295,-0.027664185,-0.060302734,0.028289795,-0.037475586,-0.032684326,0.09765625,0.0039978027,0.011642456,-0.02696228,-0.013648987,-0.005958557,0.045166016,-0.0038146973,-0.04611206,-0.05078125,-0.031799316,0.057281494,-0.007843018,0.02748108,-0.032043457,-0.0009455681,-0.033111572,-0.003528595,0.013694763,-0.009277344,0.0011262894,0.017318726,-0.035888672,-0.008544922,0.014404297,-0.014656067,0.006843567,0.033416748,0.038391113,0.056884766,-0.009819031,-0.02