INSERT INTO public.sensitive_issues (issue_id, region, category, title, issue_date, description, event_id, urls, new_description, embedding) VALUES ('INTL-030', 'INTL', 'DISCRIMINATION', 'H&M ''Coolest monkey in the jungle'' 흑인 아동 후드 문구 논란', '2018-01-08', 'H&M이 흑인 아동 모델에게 ''Coolest monkey in the jungle''이 적힌 후드를 입혀 광고한 사건. ''원숭이''는 역사적으로 흑인 비하 용어로 사용돼왔으며, 동일 제품 백인 아동 모델에게는 ''맹그로브 정글의 생존 전문가''라는 긍정적 문구를 사용해 더욱 논란이 증폭됐다. 문구 하나가 글로벌 불매운동과 남아공 매장 습격 사태로 이어졌다.', '흑인_및_소수인종_동물_비유_차별', '["https://www.khan.co.kr/article/201801091416021/"]', 'H&M은 흑인 아동 모델에게 "Coolest monkey in the jungle"라는 인종차별적 문구가 적힌 후드를 입혀 광고한 사건으로 비판을 받았다. 이 광고는 영국 온라인 상점에 게재되었고, 같은 제품을 착용한 백인 아동 모델에게는 긍정적인 문구가 사용되어 논란이 더욱 커졌다. 사회관계망서비스(SNS)에서는 H&M의 결정이 문화적으로 무지하다는 비판이 이어졌고, 래퍼 위크엔드는 협업 중단을 선언했다. H&M은 해당 이미지를 삭제하고 사과했다.', '[0.050598145,0.03086853,-0.02142334,0.012664795,0.0028495789,-0.015289307,-0.011604309,0.06713867,-0.015205383,-0.0463562,0.006629944,-0.016311646,-0.10205078,0.027557373,0.0031013489,0.012687683,-0.025131226,-0.014579773,-0.049041748,0.06573486,0.010360718,0.07159424,-0.015823364,0.038635254,0.021148682,0.035888672,-0.0014591217,-0.0016765594,0.047576904,0.016784668,0.0036449432,-0.006450653,-0.019363403,-0.007511139,0.012031555,-0.0058937073,-0.0446167,0.021057129,0.0076522827,-0.013450623,-0.022628784,-0.00793457,0.028198242,-0.0090408325,0.023406982,0.026138306,0.027755737,0.01108551,0.0118255615,0.026260376,-0.008811951,0.039276123,-0.010169983,-0.041748047,-0.0368042,-0.018432617,0.0074806213,-0.028900146,-0.021133423,-0.03479004,0.013282776,-0.008094788,-0.073791504,0.018508911,-0.007396698,-0.019226074,-0.02368164,-0.0055618286,-0.017929077,0.00806427,0.045135498,-0.011940002,-0.003250122,0.02267456,-0.0491333,-0.017288208,-0.05731201,-0.02746582,-0.016616821,0.0032844543,-0.03237915,0.015426636,0.016021729,0.029556274,0.027297974,-0.00033664703,-0.06112671,-0.0034103394,-0.039245605,-0.025039673,-0.027069092,0.03878784,-0.03265381,0.011672974,-0.022613525,0.014671326,-0.05371